pragma solidity ^0.5.16;
pragma experimental ABIEncoderV2;
import "./BaseSynthetix.sol";
import "./interfaces/IRewardEscrow.sol";
import "./interfaces/IRewardEscrowV2.sol";
import "./interfaces/ISupplySchedule.sol";
contract Synthetix is BaseSynthetix {
    bytes32 public constant CONTRACT_NAME = "Synthetix";
    bytes32 private constant CONTRACT_REWARD_ESCROW = "RewardEscrow";
    bytes32 private constant CONTRACT_SUPPLYSCHEDULE = "SupplySchedule";
    constructor(
        address payable _proxy,
        TokenState _tokenState,
        address _owner,
        uint _totalSupply,
        address _resolver
    ) public BaseSynthetix(_proxy, _tokenState, _owner, _totalSupply, _resolver) {}
    function resolverAddressesRequired() public view returns (bytes32[] memory addresses) {
        bytes32[] memory existingAddresses = BaseSynthetix.resolverAddressesRequired();
        bytes32[] memory newAddresses = new bytes32[](2);
        newAddresses[0] = CONTRACT_REWARD_ESCROW;
        newAddresses[1] = CONTRACT_SUPPLYSCHEDULE;
        return combineArrays(existingAddresses, newAddresses);
    }
    function rewardEscrow() internal view returns (IRewardEscrow) {
        return IRewardEscrow(requireAndGetAddress(CONTRACT_REWARD_ESCROW));
    }
    function supplySchedule() internal view returns (ISupplySchedule) {
        return ISupplySchedule(requireAndGetAddress(CONTRACT_SUPPLYSCHEDULE));
    }
    function exchangeWithVirtual(
        bytes32 sourceCurrencyKey,
        uint sourceAmount,
        bytes32 destinationCurrencyKey,
        bytes32 trackingCode
    )
        external
        exchangeActive(sourceCurrencyKey, destinationCurrencyKey)
        optionalProxy
        returns (uint amountReceived, IVirtualSynth vSynth)
    {
        return
            exchanger().exchange(
                messageSender,
                messageSender,
                sourceCurrencyKey,
                sourceAmount,
                destinationCurrencyKey,
                messageSender,
                true,
                messageSender,
                trackingCode
            );
    }
    function exchangeWithTrackingForInitiator(
        bytes32 sourceCurrencyKey,
        uint sourceAmount,
        bytes32 destinationCurrencyKey,
        address rewardAddress,
        bytes32 trackingCode
    ) external exchangeActive(sourceCurrencyKey, destinationCurrencyKey) optionalProxy returns (uint amountReceived) {
        (amountReceived, ) = exchanger().exchange(
            messageSender,
            messageSender,
            sourceCurrencyKey,
            sourceAmount,
            destinationCurrencyKey,
            tx.origin,
            false,
            rewardAddress,
            trackingCode
        );
    }
    function exchangeAtomically(
        bytes32 sourceCurrencyKey,
        uint sourceAmount,
        bytes32 destinationCurrencyKey,
        bytes32 trackingCode,
        uint minAmount
    ) external exchangeActive(sourceCurrencyKey, destinationCurrencyKey) optionalProxy returns (uint amountReceived) {
        return
            exchanger().exchangeAtomically(
                messageSender,
                sourceCurrencyKey,
                sourceAmount,
                destinationCurrencyKey,
                messageSender,
                trackingCode,
                minAmount
            );
    }
    function settle(bytes32 currencyKey)
        external
        optionalProxy
        returns (
            uint reclaimed,
            uint refunded,
            uint numEntriesSettled
        )
    {
        return exchanger().settle(messageSender, currencyKey);
    }
    function mint() external issuanceActive returns (bool) {
        require(address(rewardsDistribution()) != address(0), "RewardsDistribution not set");
        ISupplySchedule _supplySchedule = supplySchedule();
        IRewardsDistribution _rewardsDistribution = rewardsDistribution();
        uint supplyToMint = _supplySchedule.mintableSupply();
        require(supplyToMint > 0, "No supply is mintable");
        emitTransfer(address(0), address(this), supplyToMint);
        uint minterReward = _supplySchedule.recordMintEvent(supplyToMint);
        uint amountToDistribute = supplyToMint.sub(minterReward);
        tokenState.setBalanceOf(
            address(_rewardsDistribution),
            tokenState.balanceOf(address(_rewardsDistribution)).add(amountToDistribute)
        );
        emitTransfer(address(this), address(_rewardsDistribution), amountToDistribute);
        _rewardsDistribution.distributeRewards(amountToDistribute);
        tokenState.setBalanceOf(msg.sender, tokenState.balanceOf(msg.sender).add(minterReward));
        emitTransfer(address(this), msg.sender, minterReward);
        totalSupply = totalSupply.add(supplyToMint);
        return true;
    }
    function migrateEscrowBalanceToRewardEscrowV2() external onlyOwner {
        uint rewardEscrowBalance = tokenState.balanceOf(address(rewardEscrow()));
        _internalTransfer(address(rewardEscrow()), address(rewardEscrowV2()), rewardEscrowBalance);
    }
    event AtomicSynthExchange(
        address indexed account,
        bytes32 fromCurrencyKey,
        uint256 fromAmount,
        bytes32 toCurrencyKey,
        uint256 toAmount,
        address toAddress
    );
    bytes32 internal constant ATOMIC_SYNTH_EXCHANGE_SIG =
        keccak256("AtomicSynthExchange(address,bytes32,uint256,bytes32,uint256,address)");
    function emitAtomicSynthExchange(
        address account,
        bytes32 fromCurrencyKey,
        uint256 fromAmount,
        bytes32 toCurrencyKey,
        uint256 toAmount,
        address toAddress
    ) external onlyExchanger {
        proxy._emit(
            abi.encode(fromCurrencyKey, fromAmount, toCurrencyKey, toAmount, toAddress),
            2,
            ATOMIC_SYNTH_EXCHANGE_SIG,
            addressToBytes32(account),
            0,
            0
        );
    }
}

pragma solidity ^0.8.17;
import "ImmutableOwner.sol";
import "DataTypes.sol";
import "ITierer.sol";
import "ITierStrategy.sol";
contract ActionTierConfig is ImmutableOwner, ITierer {
    mapping(bytes32 => ITierStrategy) internal _tierStrategies;
    constructor(
        address _owner,
        StrategyConfig[] memory configs
    ) ImmutableOwner(_owner) {
        for (uint256 i; i < configs.length; i++) {
            if (configs[i]._contract == address(0)) {
                configs[i]._contract = address(this);
            }
        }
        _batchSetStrategy(configs, true);
    }
    struct StrategyConfig {
        address _contract;
        bytes4 _sig;
        address _strategy;
    }
    function _ruleKey(
        address _contract,
        bytes4 _sig
    ) internal pure returns (bytes32) {
        return keccak256(abi.encodePacked(_contract, _sig));
    }
    function initializeStrategy(
        address _contract,
        bytes4 _sig,
        address _strategy
    ) external onlyOwner {
        bytes32 ruleKey = _ruleKey(_contract, _sig);
        require(
            address(_tierStrategies[ruleKey]) == address(0),
            "strategy already set"
        );
        _setTier(_contract, _sig, _strategy);
    }
    function batchInitializeStrategy(
        StrategyConfig[] calldata configs
    ) external onlyOwner {
        _batchSetStrategy(configs, true);
    }
    function setStrategy(
        address _contract,
        bytes4 _sig,
        address _strategy
    ) external onlyOwner {
        _setTier(_contract, _sig, _strategy);
    }
    function batchSetStrategy(
        StrategyConfig[] calldata configs
    ) external onlyOwner {
        _batchSetStrategy(configs, false);
    }
    function _batchSetStrategy(
        StrategyConfig[] memory configs,
        bool initializing
    ) internal {
        for (uint256 i; i < configs.length; i++) {
            bytes32 ruleKey = _ruleKey(configs[i]._contract, configs[i]._sig);
            require(
                initializing ==
                    (address(_tierStrategies[ruleKey]) == address(0)),
                "invalid initializing value"
            );
            _setTier(
                configs[i]._contract,
                configs[i]._sig,
                configs[i]._strategy
            );
        }
    }
    function getStrategy(
        address _contract,
        bytes4 _sig
    ) external view returns (address) {
        return address(_getStrategy(_contract, _sig));
    }
    function _getStrategy(
        address _contract,
        bytes4 _sig
    ) internal view returns (ITierStrategy) {
        ITierStrategy s = _tierStrategies[_ruleKey(_contract, _sig)];
        require(address(s) != address(0), "strategy not found");
        return s;
    }
    function _setTier(
        address _contract,
        bytes4 _sig,
        address _strategy
    ) internal {
        _tierStrategies[_ruleKey(_contract, _sig)] = ITierStrategy(_strategy);
        emit TierSet(_contract, _sig, _strategy);
    }
    function getTier(
        address _contract,
        bytes calldata _calldata
    ) external view returns (DataTypes.Tier memory) {
        ITierStrategy strategy = _getStrategy(
            _contract,
            _getSelector(_calldata)
        );
        return strategy.getTier(_calldata);
    }
    function _getSelector(
        bytes memory _calldata
    ) internal pure returns (bytes4 out) {
        assembly {
            out := and(
                mload(add(_calldata, 32)),
                0xFFFFFFFF00000000000000000000000000000000000000000000000000000000
            )
        }
    }
}

