pragma solidity ^0.8.0;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

interface IDexRouter {
    function factory() external pure returns (address);
    function WETH() external pure returns (address);
    function addLiquidity(
        address tokenA,
        address tokenB,
        uint256 amountADesired,
        uint256 amountBDesired,
        uint256 amountAMin,
        uint256 amountBMin,
        address to,
        uint256 deadline
    )
        external
        returns (
            uint256 amountA,
            uint256 amountB,
            uint256 liquidity
        );

    function swapExactTokensForTokensSupportingFeeOnTransferTokens(
        uint256 amountIn,
        uint256 amountOutMin,
        address[] calldata path,
        address to,
        uint256 deadline
    ) external;
}

interface IDexFactory {
    function createPair(address tokenA, address tokenB) external returns (address pair);
}

contract AdvancedERC20 is ERC20, Ownable, ReentrancyGuard {
    // Fee structure
    struct Fees {
        uint256 operations;
        uint256 development;
        uint256 liquidity;
        uint256 burn;
    }

    Fees public buyFees;
    Fees public sellFees;

    // Addresses
    address public operationsWallet;
    address public developmentWallet;
    address public constant DEAD = 0x000000000000000000000000000000000000dEaD;

    // Trading parameters
    IDexRouter public dexRouter;
    address public immutable dexPair;
    bool public inSwap;
    bool public tradingActive;
    bool public swapEnabled;
    uint256 public swapTokensAtAmount;
    uint256 public maxTransactionAmount;
    uint256 public maxWallet;

    // Bot protection
    mapping(address => bool) public isBot;
    mapping(address => bool) public isExcludedFromFees;
    mapping(address => bool) public isExcludedFromMaxTransaction;
    mapping(address => bool) public isExcludedFromMaxWallet;
    mapping(address => bool) public isExemptFromEarlySellPenalty;
    mapping(address => uint256) public firstBuy;
    uint256 public earlySellPenaltyDuration = 7 days;
    uint256 public maxEarlySellPenalty = 25; // 25%

    event TradingEnabled(uint256 timestamp);
    event FeesUpdated(Fees buyFees, Fees sellFees);
    event WalletsUpdated(address operations, address development);
    event SwapAndLiquify(uint256 tokensSwapped, uint256 ethReceived);
    event BotDetected(address indexed bot);
    event EarlySellPenaltyApplied(address indexed seller, uint256 penaltyAmount);

    modifier lockTheSwap() {
        inSwap = true;
        _;
        inSwap = false;
    }

    constructor() ERC20("AdvancedToken", "ADV") {
        // Initialize router (example for BSC)
        dexRouter = IDexRouter(0x10ED43C718714eb63d5aA57B78B54704E256024E);
        dexPair = IDexFactory(dexRouter.factory()).createPair(address(this), dexRouter.WETH());

        // Set initial fees (example: 5% total)
        buyFees = Fees(2, 1, 1, 1); // 2% ops, 1% dev, 1% liq, 1% burn
        sellFees = Fees(2, 1, 1, 1);

        // Set wallets
        operationsWallet = owner();
        developmentWallet = owner();

        // Set limits
        uint256 totalSupply = 1000000 * 10**18;
        maxTransactionAmount = totalSupply / 200; // 0.5%
        maxWallet = totalSupply / 100; // 1%
        swapTokensAtAmount = totalSupply / 2000; // 0.05%

        // Exclude important addresses from fees and limits
        excludeFromFees(owner());
        excludeFromFees(address(this));
        excludeFromFees(address(DEAD));
        excludeFromMaxTransaction(owner());
        excludeFromMaxTransaction(address(this));
        excludeFromMaxWallet(owner());
        excludeFromMaxWallet(address(this));
        excludeFromMaxWallet(address(DEAD));
        excludeFromMaxWallet(dexPair);

        // Mint initial supply
        _mint(owner(), totalSupply);
    }

    function enableTrading() external onlyOwner {
        require(!tradingActive, "Trading already active");
        tradingActive = true;
        swapEnabled = true;
        emit TradingEnabled(block.timestamp);
    }

    function setFees(Fees calldata newBuyFees, Fees calldata newSellFees) external onlyOwner {
        require(
            newBuyFees.operations + newBuyFees.development + newBuyFees.liquidity + newBuyFees.burn <= 25, // Max 25%
            "Buy fees too high"
        );
        require(
            newSellFees.operations + newSellFees.development + newSellFees.liquidity + newSellFees.burn <= 25, // Max 25%
            "Sell fees too high"
        );
        buyFees = newBuyFees;
        sellFees = newSellFees;
        emit FeesUpdated(newBuyFees, newSellFees);
    }

    function updateWallets(address newOperations, address newDevelopment) external onlyOwner {
        require(newOperations != address(0), "Invalid operations wallet");
        require(newDevelopment != address(0), "Invalid development wallet");
        operationsWallet = newOperations;
        developmentWallet = newDevelopment;
        emit WalletsUpdated(newOperations, newDevelopment);
    }

    function excludeFromFees(address account, bool excluded) public onlyOwner {
        isExcludedFromFees[account] = excluded;
    }

    function excludeFromMaxTransaction(address account, bool excluded) public onlyOwner {
        isExcludedFromMaxTransaction[account] = excluded;
    }

    function excludeFromMaxWallet(address account, bool excluded) public onlyOwner {
        isExcludedFromMaxWallet[account] = excluded;
    }

    function setExemptFromEarlySellPenalty(address account, bool exempt) external onlyOwner {
        isExemptFromEarlySellPenalty[account] = exempt;
    }

    function setEarlySellPenaltyDuration(uint256 duration) external onlyOwner {
        require(duration <= 14 days, "Penalty duration too long");
        earlySellPenaltyDuration = duration;
    }

    function setMaxEarlySellPenalty(uint256 penalty) external onlyOwner {
        require(penalty <= 50, "Penalty too high");
        maxEarlySellPenalty = penalty;
    }

    function setSwapTokensAtAmount(uint256 amount) external onlyOwner {
        swapTokensAtAmount = amount;
    }

    function setMaxTransactionAmount(uint256 amount) external onlyOwner {
        maxTransactionAmount = amount;
    }

    function setMaxWallet(uint256 amount) external onlyOwner {
        maxWallet = amount;
    }

    function detectBot(address botAddress) external onlyOwner {
        require(botAddress != address(0), "Invalid address");
        require(!isBot[botAddress], "Already marked as bot");
        isBot[botAddress] = true;
        emit BotDetected(botAddress);
    }

    function _transfer(
        address sender,
        address recipient,
        uint256 amount
    ) internal override {
        require(sender != address(0), "ERC20: transfer from zero");
        require(recipient != address(0), "ERC20: transfer to zero");
        require(amount > 0, "Transfer amount must be > 0");
        require(!isBot[sender], "Bot detected");

        if (!tradingActive) {
            require(
                isExcludedFromMaxTransaction[sender] || isExcludedFromMaxTransaction[recipient],
                "Trading not active"
            );
        }

        // Max transaction check
        if (
            !isExcludedFromMaxTransaction[sender] &&
            !isExcludedFromMaxTransaction[recipient]
        ) {
            require(amount <= maxTransactionAmount, "Exceeds max transaction");
        }

        // Max wallet check (on recipient)
        if (!isExcludedFromMaxWallet[recipient]) {
            require(
                balanceOf(recipient) + amount <= maxWallet,
                "Exceeds max wallet"
            );
        }

        // Early sell penalty
        if (
            tradingActive &&
            sender == dexPair && // Buy
            firstBuy[recipient] == 0
        ) {
            firstBuy[recipient] = block.timestamp;
        }

        // Swap and liquify
        if (
            !inSwap &&
            swapEnabled &&
            sender != dexPair &&
            balanceOf(address(this)) >= swapTokensAtAmount
        ) {
            swapAndLiquify(swapTokensAtAmount);
        }

        // Calculate fees
        bool takeFee = !isExcludedFromFees[sender] && !isExcludedFromFees[recipient] && tradingActive;
        uint256 fees = 0;
        Fees memory feesToUse;

        if (takeFee) {
            if (recipient == dexPair) {
                // SELL
                feesToUse = sellFees;

                // Apply early sell penalty
                if (
                    !isExemptFromEarlySellPenalty[sender] &&
                    block.timestamp < firstBuy[sender] + earlySellPenaltyDuration
                ) {
                    uint256 penalty = (amount * maxEarlySellPenalty) / 100;
                    _transfer(sender, DEAD, penalty);
                    emit EarlySellPenaltyApplied(sender, penalty);
                    amount -= penalty;
                }

            } else {
                // BUY
                feesToUse = buyFees;
            }

            fees = (amount * 
                (feesToUse.operations + feesToUse.development + feesToUse.liquidity + feesToUse.burn)
            ) / 100;
        }

        if (fees > 0) {
            super._transfer(sender, address(this), fees);
            amount -= fees;
        }

        super._transfer(sender, recipient, amount);
    }

    function swapAndLiquify(uint256 tokens) private lockTheSwap {
        uint256 totalFees = buyFees.operations + buyFees.development + buyFees.liquidity + buyFees.burn +
                            sellFees.operations + sellFees.development + sellFees.liquidity + sellFees.burn;
        if (totalFees == 0) return;

        uint256 liquidityTokens = (tokens * sellFees.liquidity) / totalFees / 2; // Half for LP
        uint256 swapTokens = tokens - liquidityTokens;

        uint256 initialBalance = address(this).balance;
        _swapTokensForETH(swapTokens);
        uint256 ethReceived = address(this).balance - initialBalance;

        uint256 ethForOperations = (ethReceived * sellFees.operations) / (sellFees.operations + sellFees.development + sellFees.liquidity);
        uint256 ethForDevelopment = (ethReceived * sellFees.development) / (sellFees.operations + sellFees.development + sellFees.liquidity);
        uint256 ethForLiquidity = ethReceived - ethForOperations - ethForDevelopment;

        if (ethForOperations > 0) {
            payable(operationsWallet).sendValue(ethForOperations);
        }
        if (ethForDevelopment > 0) {
            payable(developmentWallet).sendValue(ethForDevelopment);
        }

        if (liquidityTokens > 0 && ethForLiquidity > 0) {
            _addLiquidity(liquidityTokens, ethForLiquidity);
            emit SwapAndLiquify(liquidityTokens, ethForLiquidity);
        }
    }

    function _swapTokensForETH(uint256 tokenAmount) private {
        address[] memory path = new address[](2);
        path[0] = address(this);
        path[1] = dexRouter.WETH();

        _approve(address(this), address(dexRouter), tokenAmount);
        dexRouter.swapExactTokensForTokensSupportingFeeOnTransferTokens(
            tokenAmount,
            0,
            path,
            address(this),
            block.timestamp
        );
    }

    function _addLiquidity(uint256 tokenAmount, uint256 ethAmount) private {
        _approve(address(this), address(dexRouter), tokenAmount);
        dexRouter.addLiquidity(
            address(this),
            dexRouter.WETH(),
            tokenAmount,
            ethAmount,
            0,
            0,
            owner(),
            block.timestamp
        );
    }

    // Withdraw ETH that might be stuck
    function withdrawStuckETH() external onlyOwner {
        payable(owner()).sendValue(address(this).balance);
    }

    // Withdraw tokens that might be stuck
    function withdrawStuckTokens(address token, uint256 amount) external onlyOwner {
        require(token != address(this), "Can't withdraw own token");
        IERC20(token).transfer(owner(), amount);
    }
}

pragma solidity ^0.5.16;
pragma experimental ABIEncoderV2;
import "./PerpsV2MarketProxyable.sol";
import "./interfaces/IPerpsV2MarketDelayedIntent.sol";
import "./interfaces/IPerpsV2MarketBaseTypes.sol";
contract PerpsV2MarketDelayedIntent is IPerpsV2MarketDelayedIntent, PerpsV2MarketProxyable {
    constructor(
        address payable _proxy,
        address _marketState,
        address _owner,
        address _resolver
    ) public PerpsV2MarketProxyable(_proxy, _marketState, _owner, _resolver) {}
    function submitCloseOffchainDelayedOrderWithTracking(uint desiredFillPrice, bytes32 trackingCode)
        external
        onlyProxy
        notFlagged(messageSender)
    {
        _submitCloseDelayedOrder(0, desiredFillPrice, trackingCode, IPerpsV2MarketBaseTypes.OrderType.Offchain);
    }
    function submitCloseDelayedOrderWithTracking(
        uint desiredTimeDelta,
        uint desiredFillPrice,
        bytes32 trackingCode
    ) external onlyProxy notFlagged(messageSender) {
        _submitCloseDelayedOrder(
            desiredTimeDelta,
            desiredFillPrice,
            trackingCode,
            IPerpsV2MarketBaseTypes.OrderType.Delayed
        );
    }
    function submitDelayedOrder(
        int sizeDelta,
        uint desiredTimeDelta,
        uint desiredFillPrice
    ) external onlyProxy notFlagged(messageSender) {
        _submitDelayedOrder(_marketKey(), sizeDelta, desiredTimeDelta, desiredFillPrice, bytes32(0), false);
    }
    function submitDelayedOrderWithTracking(
        int sizeDelta,
        uint desiredTimeDelta,
        uint desiredFillPrice,
        bytes32 trackingCode
    ) external onlyProxy notFlagged(messageSender) {
        _submitDelayedOrder(_marketKey(), sizeDelta, desiredTimeDelta, desiredFillPrice, trackingCode, false);
    }
    function submitOffchainDelayedOrder(int sizeDelta, uint desiredFillPrice) external onlyProxy notFlagged(messageSender) {

        _submitDelayedOrder(_marketKey(), sizeDelta, 0, desiredFillPrice, bytes32(0), true);
    }
    function submitOffchainDelayedOrderWithTracking(
        int sizeDelta,
        uint desiredFillPrice,
        bytes32 trackingCode
    ) external onlyProxy notFlagged(messageSender) {
        _submitDelayedOrder(_marketKey(), sizeDelta, 0, desiredFillPrice, trackingCode, true);
    }
    function _submitCloseDelayedOrder(
        uint desiredTimeDelta,
        uint desiredFillPrice,
        bytes32 trackingCode,
        IPerpsV2MarketBaseTypes.OrderType orderType
    ) internal {
        Position memory position = marketState.positions(messageSender);
        _revertIfError(position.size == 0, Status.NoPositionOpen);

        require(orderType != IPerpsV2MarketBaseTypes.OrderType.Atomic, "invalid order type");
        _submitDelayedOrder(
            _marketKey(),
            -position.size,
            desiredTimeDelta,
            desiredFillPrice,
            trackingCode,
            orderType == IPerpsV2MarketBaseTypes.OrderType.Offchain
        );
    }
    function _submitDelayedOrder(
        bytes32 marketKey,
        int sizeDelta,
        uint desiredTimeDelta,
        uint desiredFillPrice,
        bytes32 trackingCode,
        bool isOffchain
    ) internal {
        require(marketState.delayedOrders(messageSender).sizeDelta == 0, "previous order exists");
        if (desiredTimeDelta == 0) {
            desiredTimeDelta = _minDelayTimeDelta(marketKey);
        }
        require(
            desiredTimeDelta >= _minDelayTimeDelta(marketKey) && desiredTimeDelta <= _maxDelayTimeDelta(marketKey),
            "delay out of bounds"
        );
        Position memory position = marketState.positions(messageSender);
        uint price = _assetPriceRequireSystemChecks(isOffchain);
        uint fillPrice = _fillPrice(sizeDelta, price);
        uint fundingIndex = _recomputeFunding(price);
        TradeParams memory params =
            TradeParams({
                sizeDelta: sizeDelta,
                oraclePrice: price,
                fillPrice: fillPrice,
                takerFee: isOffchain ? _takerFeeOffchainDelayedOrder(marketKey) : _takerFeeDelayedOrder(marketKey),
                makerFee: isOffchain ? _makerFeeOffchainDelayedOrder(marketKey) : _makerFeeDelayedOrder(marketKey),
                desiredFillPrice: desiredFillPrice,
                trackingCode: trackingCode
            });
        {
            (, , Status status) = _postTradeDetails(position, params);
            _revertIfError(status);
        }
        uint keeperDeposit = _minKeeperFee();
        _updatePositionMargin(messageSender, position, sizeDelta, fillPrice, -int(keeperDeposit));
        emitPositionModified(
            position.id,
            messageSender,
            position.margin,
            position.size,
            0,
            fillPrice,
            fundingIndex,
            0,
            marketState.marketSkew()
        );
        uint targetRoundId = _exchangeRates().getCurrentRoundId(_baseAsset()) + 1; 
        DelayedOrder memory order =
            DelayedOrder({
                isOffchain: isOffchain,
                sizeDelta: int128(sizeDelta),
                desiredFillPrice: uint128(desiredFillPrice),
                targetRoundId: isOffchain ? 0 : uint128(targetRoundId),
                commitDeposit: 0, 
                keeperDeposit: uint128(keeperDeposit), 
                executableAtTime: isOffchain ? 0 : block.timestamp + desiredTimeDelta, 
                intentionTime: block.timestamp,
                trackingCode: trackingCode
            });
        emitDelayedOrderSubmitted(messageSender, order);
        marketState.updateDelayedOrder(
            messageSender,
            order.isOffchain,
            order.sizeDelta,
            order.desiredFillPrice,
            order.targetRoundId,
            order.commitDeposit,
            order.keeperDeposit,
            order.executableAtTime,
            order.intentionTime,
            order.trackingCode
        );
    }
    event DelayedOrderSubmitted(
        address indexed account,
        bool isOffchain,
        int sizeDelta,
        uint targetRoundId,
        uint intentionTime,
        uint executableAtTime,
        uint commitDeposit,
        uint keeperDeposit,
        bytes32 trackingCode
    );
    bytes32 internal constant DELAYEDORDERSUBMITTED_SIG =
        keccak256("DelayedOrderSubmitted(address,bool,int256,uint256,uint256,uint256,uint256,uint256,bytes32)");
    function emitDelayedOrderSubmitted(address account, DelayedOrder memory order) internal {
        proxy._emit(
            abi.encode(
                order.isOffchain,
                order.sizeDelta,
                order.targetRoundId,
                order.intentionTime,
                order.executableAtTime,
                order.commitDeposit,
                order.keeperDeposit,
                order.trackingCode
            ),
            2,
            DELAYEDORDERSUBMITTED_SIG,
            addressToBytes32(account),
            0,
            0
        );
    }
}

