    function _updateBurningLimits(address bridge, uint256 newLimit) private {
        BridgeLimits storage limits = burningLimits[bridge];
        uint256 oldLimit = limits.maxLimit;
        uint256 currentLimit = burningCurrentLimitOf(bridge);
        limits.maxLimit = newLimit;
        limits.currentLimit = _calculateNewCurrentLimit(newLimit, oldLimit, currentLimit);
        limits.ratePerSecond = newLimit / 1 days;
        limits.timestamp = block.timestamp;
    }
    function _useMintingLimit(address bridge, uint256 amount) private {
        BridgeLimits storage limits = mintingLimits[bridge];
        limits.currentLimit -= amount;
        limits.timestamp = block.timestamp;
    }
    function _useBurningLimit(address bridge, uint256 amount) private {
        BridgeLimits storage limits = burningLimits[bridge];
        limits.currentLimit -= amount;
        limits.timestamp = block.timestamp;
    }
    function _calculateCurrentLimit(uint256 currentLimit, uint256 maxLimit, uint256 timestamp, uint256 ratePerSecond) private view returns (uint256) {
        if (currentLimit == maxLimit) return maxLimit;
        uint256 timePassed = block.timestamp - timestamp;
        uint256 replenished = timePassed * ratePerSecond;
        uint256 newLimit = currentLimit + replenished;
        return newLimit > maxLimit ? maxLimit : newLimit;
    }
    function _calculateNewCurrentLimit(uint256 newLimit, uint256 oldLimit, uint256 currentLimit) private pure returns (uint256) {
        if (newLimit > oldLimit) {
            return currentLimit + (newLimit - oldLimit);
        } else {
            uint256 reduction = oldLimit - newLimit;
            return currentLimit > reduction ? currentLimit - reduction : 0;
        }
    }
    function transferOwnership(address newOwner) external onlyOwner {
        require(newOwner != address(0), "Invalid owner");
        owner = newOwner;
    }
}

