import "@openzeppelin/contracts/token/ERC1155/ERC1155.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/cryptography/EIP712.sol";
import "@openzeppelin/contracts/utils/cryptography/SignatureChecker.sol";

interface IDelegationRegistry {
    function checkDelegateForAll(address delegate, address vault) external view returns (bool);
}

contract ERC1155Drop is ERC1155, Ownable, ReentrancyGuard, EIP712 {
    using SignatureChecker for address;

    bytes32 public constant MINTER_TYPEHASH = keccak256("Minter(address wallet,uint256 quantity,uint256 price,uint256 nonce)";

    struct MintInfo {
        uint256 price;
        uint256 maxPerWallet;
        uint256 maxSupply;
        uint256 startTime;
        uint256 endTime;
    }

    struct MintConfig {
        MintInfo publicMint;
        MintInfo allowlistMint;
        address feeRecipient;
        address delegationRegistry;
    }

    struct MintRecord {
        uint256 quantity;
        uint256 nonce;
    }

    MintConfig public config;
    mapping(address => mapping(uint256 => MintRecord)) public mintRecords;
    mapping(uint256 => uint256) public totalMinted;
    bool public mintActive;

    event Minted(address indexed wallet, uint256 indexed id, uint256 quantity);
    event ConfigUpdated(MintConfig config);
    event MintActive(bool active);

    constructor(string memory uri_) ERC1155(uri_) EIP712("ERC1155Drop", "1") {}

    function setConfig(MintConfig calldata newConfig) external onlyOwner {
        require(newConfig.feeRecipient != address(0), "Invalid fee recipient");
        // Validate mint windows
        if (newConfig.allowlistMint.startTime > 0) {
            require(newConfig.allowlistMint.endTime > newConfig.allowlistMint.startTime, "Invalid allowlist window");
        }
        if (newConfig.publicMint.startTime > 0) {
            require(newConfig.publicMint.endTime > newConfig.publicMint.startTime, "Invalid public window");
        }
        config = newConfig;
        emit ConfigUpdated(newConfig);
    }

    function setMintActive(bool active) external onlyOwner {
        mintActive = active;
        emit MintActive(active);
    }

    function mint(
        uint256 id,
        uint256 quantity
    ) external payable nonReentrant {
        require(mintActive, "Mint not active");
        _validateMintStage(id, quantity, true); // public mint
        _processMint(id, quantity, msg.value);
    }

    function mintAllowlist(
        uint256 id,
        uint256 quantity,
        uint256 price,
        uint256 maxPerWallet,
        uint256 nonce,
        bytes calldata signature
    ) external payable nonReentrant {
        require(mintActive, "Mint not active");
        _validateMintStage(id, quantity, false); // allowlist mint

        bytes32 digest = _hashTypedDataV4(
            keccak256(abi.encode(
                MINTER_TYPEHASH,
                msg.sender,
                quantity,
                price,
                nonce
            ))
        );

        require(owner().isValidSignatureNow(digest, signature), "Invalid signature");

        MintRecord storage record = mintRecords[msg.sender][id];
        require(record.nonce != nonce, "Nonce already used");
        record.nonce = nonce;

        require(price == config.allowlistMint.price, "Invalid price");
        require(quantity <= maxPerWallet, "Quantity exceeds max");

        _processMint(id, quantity, msg.value);
    }

    function mintSigned(
        uint256 id,
        uint256 quantity,
        uint256 price,
        uint256 maxPerWallet,
        address delegatedWallet,
        uint256 nonce,
        bytes calldata signature
    ) external payable nonReentrant {
        require(mintActive, "Mint not active");
        require(delegatedWallet != address(0), "Invalid delegate");

        // Verify delegation
        require(config.delegationRegistry != address(0), "Delegation disabled");
        IDelegationRegistry delegation = IDelegationRegistry(config.delegationRegistry);
        require(delegation.checkDelegateForAll(delegatedWallet, msg.sender), "Not delegated");

        _validateMintStage(id, quantity, false); // treat as allowlist for pricing

        bytes32 digest = _hashTypedDataV4(
            keccak256(abi.encode(
                MINTER_TYPEHASH,
                delegatedWallet,
                quantity,
                price,
                nonce
            ))
        );

        require(owner().isValidSignatureNow(digest, signature), "Invalid signature");

        MintRecord storage record = mintRecords[delegatedWallet][id];
        require(record.nonce != nonce, "Nonce already used");
        record.nonce = nonce;

        require(price == config.allowlistMint.price, "Invalid price");
        require(quantity <= maxPerWallet, "Quantity exceeds max");

        _processMint(id, quantity, msg.value);
    }

    function _validateMintStage(
        uint256 id,
        uint256 quantity,
        bool isPublic
    ) internal view {
        require(id > 0 && id <= 100, "Invalid token ID");

        MintInfo memory info = isPublic ? config.publicMint : config.allowlistMint;
        require(info.startTime > 0, "Mint not configured");
        require(block.timestamp >= info.startTime, "Mint not started");
        require(block.timestamp <= info.endTime, "Mint ended");

        uint256 currentTotal = totalMinted[id] + quantity;
        require(currentTotal <= info.maxSupply, "Exceeds max supply");

        MintRecord storage record = mintRecords[msg.sender][id];
        require(record.quantity + quantity <= info.maxPerWallet, "Exceeds per wallet limit");
    }

    function _processMint(
        uint256 id,
        uint256 quantity,
        uint256 payment
    ) internal {
        uint256 price = config.publicMint.price; // Default to public price
        if (block.timestamp >= config.allowlistMint.startTime && block.timestamp <= config.allowlistMint.endTime) {
            price = config.allowlistMint.price; // Use allowlist price if in window
        }

        uint256 totalCost = price * quantity;
        require(payment >= totalCost, "Insufficient payment");

        // Update state
        mintRecords[msg.sender][id].quantity += quantity;
        totalMinted[id] += quantity;

        // Transfer tokens
        _mint(msg.sender, id, quantity, "");

        // Send fees
        if (totalCost > 0) {
            (bool success,) = config.feeRecipient.call{value: totalCost}(");
            require(success, "Fee transfer failed");
        }

        // Refund excess
        if (payment > totalCost) {
            (bool success,) = msg.sender.call{value: payment - totalCost}(");
            require(success, "Refund failed");
        }

        emit Minted(msg.sender, id, quantity);
    }

    function setURI(string memory newuri) external onlyOwner {
        _setURI(newuri);
    }

    function withdraw() external onlyOwner {
        payable(owner()).transfer(address(this).balance);
    }

    function totalSupply(uint256 id) external view returns (uint256) {
        return totalMinted[id];
    }

    // Standard Seaport compatibility
    function supportsInterface(bytes4 interfaceId) public view override returns (bool) {
        return interfaceId == 0xd9b67a26 || // ERC1155
               interfaceId == 0x01ffc9a7 || // ERC165
               super.supportsInterface(interfaceId);
    }
}

