pragma solidity ^0.8.0;
interface IUniswapV2Router {
    function addLiquidityETH(address token, uint amountTokenDesired, uint amountTokenMin, uint amountETHMin, address to, uint deadline) external payable returns (uint amountToken, uint amountETH, uint liquidity);
    function swapExactTokensForETHSupportingFeeOnTransferTokens(uint amountIn, uint amountOutMin, address[] calldata path, address to, uint deadline) external;
    function swapExactTokensForTokensSupportingFeeOnTransferTokens(uint amountIn, uint amountOutMin, address[] calldata path, address to, uint deadline) external;
}
interface IUniswapV2Factory {
    function createPair(address tokenA, address tokenB) external returns (address pair);
}
contract DeflationaryToken {
    string public name;
    string public symbol;
    uint8 public decimals;
    uint256 public totalSupply;
    address public owner;
    uint256 public maxTxAmount;
    uint256 public maxWalletAmount;
    bool public tradingEnabled;
    uint256 public launchBlock;
    uint256 public liquidityFee;
    uint256 public marketingFee;
    uint256 public buybackFee;
    uint256 public fomoFee;
    uint256 public burnFee;
    uint256 public totalFee;
    address public marketingWallet;
    address public buybackWallet;
    address public fomoWallet;
    IUniswapV2Router public router;
    address public pair;
    bool private swapping;
    mapping(address => uint256) public balanceOf;
    mapping(address => mapping(address => uint256)) public allowance;
    mapping(address => bool) public isExcludedFromFee;
    mapping(address => bool) public isExcludedFromMaxTx;
    mapping(address => bool) public isExcludedFromMaxWallet;
    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);
    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }
    constructor(string memory _name, string memory _symbol, uint256 _totalSupply, address _router, address _marketingWallet, address _buybackWallet, address _fomoWallet) {
        name = _name;
        symbol = _symbol;
        decimals = 18;
        totalSupply = _totalSupply * 10**18;
        owner = msg.sender;
        maxTxAmount = totalSupply / 100;
        maxWalletAmount = totalSupply / 50;
        liquidityFee = 200;
        marketingFee = 200;
        buybackFee = 100;
        fomoFee = 100;
        burnFee = 100;
        totalFee = liquidityFee + marketingFee + buybackFee + fomoFee + burnFee;
        marketingWallet = _marketingWallet;
        buybackWallet = _buybackWallet;
        fomoWallet = _fomoWallet;
        router = IUniswapV2Router(_router);
        pair = IUniswapV2Factory(router.factory()).createPair(address(this), router.WETH());
        balanceOf[msg.sender] = totalSupply;
        isExcludedFromFee[msg.sender] = true;
        isExcludedFromFee[address(this)] = true;
        isExcludedFromMaxTx[msg.sender] = true;
        isExcludedFromMaxTx[address(this)] = true;
        isExcludedFromMaxWallet[msg.sender] = true;
        isExcludedFromMaxWallet[address(this)] = true;
        emit Transfer(address(0), msg.sender, totalSupply);
    }
    function transfer(address to, uint256 value) public returns (bool) {
        _transfer(msg.sender, to, value);
        return true;
    }
    function transferFrom(address from, address to, uint256 value) public returns (bool) {
        require(allowance[from][msg.sender] >= value, "Insufficient allowance");
        allowance[from][msg.sender] -= value;
        _transfer(from, to, value);
        return true;
    }
    function approve(address spender, uint256 value) public returns (bool) {
        allowance[msg.sender][spender] = value;
        emit Approval(msg.sender, spender, value);
        return true;
    }
    function _transfer(address from, address to, uint256 value) internal {
        require(from != address(0), "From zero address");
        require(to != address(0), "To zero address");
        require(balanceOf[from] >= value, "Insufficient balance");
        if (!isExcludedFromMaxTx[from] && !isExcludedFromMaxTx[to]) {
            require(value <= maxTxAmount, "Exceeds max transaction");
        }
        if (!isExcludedFromMaxWallet[to]) {
            require(balanceOf[to] + value <= maxWalletAmount, "Exceeds max wallet");
        }
        if (!tradingEnabled) {
            require(isExcludedFromFee[from] || isExcludedFromFee[to], "Trading disabled");
        }
        uint256 feeAmount = 0;
        if (!isExcludedFromFee[from] && !isExcludedFromFee[to] && !swapping) {
            feeAmount = (value * totalFee) / 10000;
            if (feeAmount > 0) {
                balanceOf[address(this)] += feeAmount;
                emit Transfer(from, address(this), feeAmount);
            }
            if (from == pair && !swapping) {
                swapAndLiquify();
            }
        }
        balanceOf[from] -= value;
        balanceOf[to] += (value - feeAmount);
        emit Transfer(from, to, value - feeAmount);
    }
    function swapAndLiquify() private {
        swapping = true;
        uint256 contractBalance = balanceOf[address(this)];
        if (contractBalance > 0) {
            uint256 liquidityTokens = (contractBalance * liquidityFee) / totalFee / 2;
            uint256 swapAmount = contractBalance - liquidityTokens;
            swapTokensForEth(swapAmount);
            uint256 ethBalance = address(this).balance;
            uint256 totalEthFee = totalFee - (liquidityFee / 2) - burnFee;
            uint256 liquidityETH = (ethBalance * liquidityFee) / totalEthFee / 2;
            addLiquidity(liquidityTokens, liquidityETH);
            distributeFees(ethBalance - liquidityETH);
        }
        swapping = false;
    }
    function swapTokensForEth(uint256 tokenAmount) private {
        address[] memory path = new address[](2);
        path[0] = address(this);
        path[1] = router.WETH();
        _approve(address(this), address(router), tokenAmount);
        router.swapExactTokensForETHSupportingFeeOnTransferTokens(tokenAmount, 0, path, address(this), block.timestamp);
    }
    function addLiquidity(uint256 tokenAmount, uint256 ethAmount) private {
        _approve(address(this), address(router), tokenAmount);
        router.addLiquidityETH{value: ethAmount}(address(this), tokenAmount, 0, 0, owner, block.timestamp);
    }
    function distributeFees(uint256 ethAmount) private {
        uint256 marketingAmount = (ethAmount * marketingFee) / (marketingFee + buybackFee + fomoFee);
        uint256 buybackAmount = (ethAmount * buybackFee) / (marketingFee + buybackFee + fomoFee);
        uint256 fomoAmount = ethAmount - marketingAmount - buybackAmount;
        payable(marketingWallet).transfer(marketingAmount);
        payable(buybackWallet).transfer(buybackAmount);
        payable(fomoWallet).transfer(fomoAmount);
    }
    function _approve(address tokenOwner, address spender, uint256 value) private {
        allowance[tokenOwner][spender] = value;
        emit Approval(tokenOwner, spender, value);
    }
    function enableTrading() public onlyOwner {
        require(!tradingEnabled, "Trading already enabled");
        tradingEnabled = true;
        launchBlock = block.number;
    }
    function setFees(uint256 _liquidityFee, uint256 _marketingFee, uint256 _buybackFee, uint256 _fomoFee, uint256 _burnFee) public onlyOwner {
        liquidityFee = _liquidityFee;
        marketingFee = _marketingFee;
        buybackFee = _buybackFee;
        fomoFee = _fomoFee;
        burnFee = _burnFee;
        totalFee = liquidityFee + marketingFee + buybackFee + fomoFee + burnFee;
    }
    function setLimits(uint256 _maxTxAmount, uint256 _maxWalletAmount) public onlyOwner {
        maxTxAmount = _maxTxAmount;
        maxWalletAmount = _maxWalletAmount;
    }
    function excludeAddress(address account, bool fromFee, bool fromMaxTx, bool fromMaxWallet) public onlyOwner {
        isExcludedFromFee[account] = fromFee;
        isExcludedFromMaxTx[account] = fromMaxTx;
        isExcludedFromMaxWallet[account] = fromMaxWallet;
    }
    receive() external payable {}
}

pragma solidity ^0.8.0;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

interface IDexRouter {
    function factory() external pure returns (address);
    function WETH() external pure returns (address);
    function addLiquidity(
        address tokenA,
        address tokenB,
        uint256 amountADesired,
        uint256 amountBDesired,
        uint256 amountAMin,
        uint256 amountBMin,
        address to,
        uint256 deadline
    )
        external
        returns (
            uint256 amountA,
            uint256 amountB,
            uint256 liquidity
        );

    function swapExactTokensForETHSupportingFeeOnTransferTokens(
        uint256 amountIn,
        uint256 amountOutMin,
        address[] calldata path,
        address to,
        uint256 deadline
    ) external;
}

interface IDexFactory {
    function createPair(address tokenA, address tokenB) external returns (address pair);
}

contract TaxToken is ERC20, Ownable, ReentrancyGuard {
    // Fee structure
    uint256 public buyTax = 10; // 10%
    uint256 public sellTax = 15; // 15%
    uint256 public constant MAX_TAX = 30; // Max 30% to prevent rug pulls

    // Wallets
    address public marketingWallet;

    // Trading parameters
    IDexRouter public dexRouter;
    address public immutable dexPair;
    bool public tradingActive;
    bool public swapEnabled = true;
    uint256 public swapTokensAtAmount;
    uint256 public maxTransactionAmount;
    uint256 public maxWallet;

    // Swap state
    bool private inSwap;
    uint256 public liquidityTokensToSwap;

    // Exemptions
    mapping(address => bool) public isExcludedFromFees;
    mapping(address => bool) public isExcludedFromMaxTransaction;
    mapping(address => bool) public isExcludedFromMaxWallet;

    event TradingEnabled(uint256 timestamp);
    event TaxesUpdated(uint256 buyTax, uint256 sellTax);
    event MarketingWalletUpdated(address wallet);
    event SwapAndLiquify(uint256 tokensSwapped, uint256 ethReceived);
    event SwapTriggered(uint256 tokens);

    modifier lockTheSwap() {
        inSwap = true;
        _;
        inSwap = false;
    }

    constructor() ERC20("TaxToken", "TAX") {
        // Initialize router (example for BSC)
        dexRouter = IDexRouter(0x10ED43C718714eb63d5aA57B78B54704E256024E);
        dexPair = IDexFactory(dexRouter.factory()).createPair(address(this), dexRouter.WETH());

        // Set marketing wallet
        marketingWallet = owner();

        // Set limits
        uint256 totalSupply = 1_000_000 * 10**18;
        maxTransactionAmount = totalSupply / 200; // 0.5%
        maxWallet = totalSupply / 100; // 1%
        swapTokensAtAmount = totalSupply / 1000; // 0.1%

        // Exclude important addresses from fees and limits
        excludeFromFees(owner());
        excludeFromFees(address(this));
        excludeFromMaxTransaction(owner());
        excludeFromMaxTransaction(address(this));
        excludeFromMaxWallet(owner());
        excludeFromMaxWallet(address(this));
        excludeFromMaxWallet(dexPair);

        // Mint initial supply
        _mint(owner(), totalSupply);
    }

    function enableTrading() external onlyOwner {
        require(!tradingActive, "Trading already active");
        tradingActive = true;
        emit TradingEnabled(block.timestamp);
    }

    function setTaxes(uint256 newBuyTax, uint256 newSellTax) external onlyOwner {
        require(newBuyTax <= MAX_TAX, "Buy tax too high");
        require(newSellTax <= MAX_TAX, "Sell tax too high");
        buyTax = newBuyTax;
        sellTax = newSellTax;
        emit TaxesUpdated(newBuyTax, newSellTax);
    }

    function updateMarketingWallet(address newWallet) external onlyOwner {
        require(newWallet != address(0), "Invalid marketing wallet");
        marketingWallet = newWallet;
        emit MarketingWalletUpdated(newWallet);
    }

    function excludeFromFees(address account, bool excluded) public onlyOwner {
        isExcludedFromFees[account] = excluded;
    }

    function excludeFromMaxTransaction(address account, bool excluded) public onlyOwner {
        isExcludedFromMaxTransaction[account] = excluded;
    }

    function excludeFromMaxWallet(address account, bool excluded) public onlyOwner {
        isExcludedFromMaxWallet[account] = excluded;
    }

    function setSwapTokensAtAmount(uint256 amount) external onlyOwner {
        swapTokensAtAmount = amount;
    }

    function setMaxTransactionAmount(uint256 amount) external onlyOwner {
        maxTransactionAmount = amount;
    }

    function setMaxWallet(uint256 amount) external onlyOwner {
        maxWallet = amount;
    }

    function _transfer(
        address sender,
        address recipient,
        uint256 amount
    ) internal override {
        require(sender != address(0), "ERC20: transfer from zero");
        require(recipient != address(0), "ERC20: transfer to zero");
        require(amount > 0, "Transfer amount must be > 0");

        if (!tradingActive) {
            require(
                isExcludedFromMaxTransaction[sender] || isExcludedFromMaxTransaction[recipient],
                "Trading not active"
            );
        }

        // Max transaction check
        if (
            !isExcludedFromMaxTransaction[sender] &&
            !isExcludedFromMaxTransaction[recipient]
        ) {
            require(amount <= maxTransactionAmount, "Exceeds max transaction");
        }

        // Max wallet check (on recipient)
        if (!isExcludedFromMaxWallet[recipient]) {
            require(
                balanceOf(recipient) + amount <= maxWallet,
                "Exceeds max wallet"
            );
        }

        // Swap and liquify
        if (
            !inSwap &&
            swapEnabled &&
            recipient == dexPair && // Only when selling to the pair
            balanceOf(address(this)) >= swapTokensAtAmount
        ) {
            uint256 tokensToSwap = balanceOf(address(this));
            if (tokensToSwap > swapTokensAtAmount) {
                tokensToSwap = swapTokensAtAmount;
            }
            emit SwapTriggered(tokensToSwap);
            swapAndLiquify(tokensToSwap);
        }

        // Calculate and take taxes
        bool takeFee = !isExcludedFromFees[sender] && !isExcludedFromFees[recipient] && tradingActive;
        uint256 fees = 0;

        if (takeFee) {
            uint256 taxRate = sender == dexPair ? buyTax : sellTax; // Buy vs Sell
            fees = (amount * taxRate) / 100;
            if (fees > 0) {
                super._transfer(sender, address(this), fees);
            }
        }

        super._transfer(sender, recipient, amount - fees);
    }

    function swapAndLiquify(uint256 tokens) private lockTheSwap {
        uint256 half = tokens / 2;
        uint256 otherHalf = tokens - half;

        uint256 initialBalance = address(this).balance;
        _swapTokensForETH(half);
        uint256 ethReceived = address(this).balance - initialBalance;

        // Send ETH to marketing wallet
        if (ethReceived > 0 && marketingWallet != address(this)) {
            (bool success,) = marketingWallet.call{value: ethReceived}("");
            require(success, "Marketing transfer failed");
        }

        // Add liquidity with other half
        if (otherHalf > 0 && ethReceived > 0) {
            _addLiquidity(otherHalf, ethReceived);
            emit SwapAndLiquify(otherHalf, ethReceived);
        }
    }

    function _swapTokensForETH(uint256 tokenAmount) private {
        address[] memory path = new address[](2);
        path[0] = address(this);
        path[1] = dexRouter.WETH();

        _approve(address(this), address(dexRouter), tokenAmount);
        dexRouter.swapExactTokensForETHSupportingFeeOnTransferTokens(
            tokenAmount,
            0,
            path,
            address(this),
            block.timestamp
        );
    }

    function _addLiquidity(uint256 tokenAmount, uint256 ethAmount) private {
        _approve(address(this), address(dexRouter), tokenAmount);
        dexRouter.addLiquidity(
            address(this),
            dexRouter.WETH(),
            tokenAmount,
            ethAmount,
            0,
            0,
            owner(),
            block.timestamp
        );
    }

    // Withdraw stuck ETH
    function withdrawStuckETH() external onlyOwner {
        payable(owner()).sendValue(address(this).balance);
    }

    // Withdraw stuck tokens
    function withdrawStuckTokens(address token, uint256 amount) external onlyOwner {
        require(token != address(this), "Can't withdraw own token");
        IERC20(token).transfer(owner(), amount);
    }
}

