        address _want,
        address _hook,
        address _governance
    ) external returns (address) {
        return
            _createNewAuction(
                _want,
                _hook,
                _governance,
                DEFAULT_AUCTION_LENGTH,
                DEFAULT_AUCTION_COOLDOWN,
                DEFAULT_STARTING_PRICE
            );
    }
    function createNewAuction(
        address _want,
        address _hook,
        address _governance,
        uint256 _auctionLength
    ) external returns (address) {
        return
            _createNewAuction(
                _want,
                _hook,
                _governance,
                _auctionLength,
                DEFAULT_AUCTION_COOLDOWN,
                DEFAULT_STARTING_PRICE
            );
    }
    function createNewAuction(
        address _want,
        address _hook,
        address _governance,
        uint256 _auctionLength,
        uint256 _auctionCooldown
    ) external returns (address) {
        return
            _createNewAuction(
                _want,
                _hook,
                _governance,
                _auctionLength,
                _auctionCooldown,
                DEFAULT_STARTING_PRICE
            );
    }
    function createNewAuction(
        address _want,
        address _hook,
        address _governance,
        uint256 _auctionLength,
        uint256 _auctionCooldown,
        uint256 _startingPrice
    ) external returns (address) {
        return
            _createNewAuction(
                _want,
                _hook,
                _governance,
                _auctionLength,
                _auctionCooldown,
                _startingPrice
            );
    }
    function _createNewAuction(
        address _want,
        address _hook,
        address _governance,
        uint256 _auctionLength,
        uint256 _auctionCooldown,
        uint256 _startingPrice
    ) internal returns (address _newAuction) {
        _newAuction = _clone();
        Auction(_newAuction).initialize(
            _want,
            _hook,
            _governance,
            _auctionLength,
            _auctionCooldown,
            _startingPrice
        );
        auctions.push(_newAuction);
        emit DeployedNewAuction(_newAuction, _want);
    }
    function getAllAuctions() external view returns (address[] memory) {
        return auctions;
    }
    function numberOfAuctions() external view returns (uint256) {
        return auctions.length;
    }
}

pragma solidity ^0.8.0;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

contract CrossChainBridge is Ownable, ReentrancyGuard {
    using SafeERC20 for IERC20;

    // ============ Enums ============
    enum ChainID {
        Ethereum,
        Injective
    }

    // ============ Structs ============
    struct Validator {
        address addr;
        uint256 power; // voting power
    }

    struct Transaction {
        bytes32 txHash;
        address sender;
        address token;
        uint256 amount;
        address recipient;
        ChainID sourceChain;
        ChainID destinationChain;
        uint256 nonce;
        bool executed;
    }

    struct Checkpoint {
        bytes32 root;
        uint256 index;
        uint256 timestamp;
        mapping(address => bool) processedValidators;
    }

    // ============ Events ============
    event ValidatorSetUpdated(address[] validators, uint256[] powers);
    event TokensLocked(address indexed token, address indexed sender, uint256 amount, address indexed recipient, ChainID destChain, uint256 nonce);
    event TokensMinted(address indexed token, address indexed recipient, uint256 amount, uint256 indexed nonce);
    event CheckpointSubmitted(bytes32 indexed root, uint256 indexed index, address validator);
    event TransactionExecuted(bytes32 indexed txHash, uint256 indexed nonce);
    event TokenMapped(address indexed originToken, address indexed localToken, string symbol);

    // ============ State Variables ============
    mapping(address => bool) public isValidator;
    Validator[] public validators;
    uint256 public totalValidatorPower;

    mapping(ChainID => mapping(bytes32 => bool)) public executedTransactions;
    mapping(bytes32 => Transaction) public transactions;

    mapping(address => address) public originToLocalToken;
    mapping(address => address) public localToOriginToken;

    mapping(uint256 => Checkpoint) public checkpoints;
    uint256 public checkpointIndex;
    uint256 public constant MIN_VALIDATOR_SIGNERS = 2; // 2/3+ for BFT
    uint256 public constant CHECKPOINT_INTERVAL = 10; // Submit every N transactions

    ChainID public currentChain;
    address public governance;

    // ============ Modifiers ============
    modifier onlyValidator() {
        require(isValidator[msg.sender], "Not a validator");
        _;
    }

    modifier onlyGovernance() {
        require(msg.sender == governance, "Not governance");
        _;
    }

    // ============ Constructor ============
    constructor(ChainID _chainId, address[] memory _initialValidators, uint256[] memory _powers) {
        currentChain = _chainId;
        governance = msg.sender;

        require(_initialValidators.length == _powers.length, "Length mismatch");
        require(_initialValidators.length >= MIN_VALIDATOR_SIGNERS, "Not enough validators");

        for (uint256 i = 0; i < _initialValidators.length; i++) {
            require(_initialValidators[i] != address(0), "Invalid validator");
            require(_powers[i] > 0, "Zero power");

            validators.push(Validator({
                addr: _initialValidators[i],
                power: _powers[i]
            }));
            isValidator[_initialValidators[i]] = true;
            totalValidatorPower += _powers[i];
        }

        emit ValidatorSetUpdated(_initialValidators, _powers);
    }

    // ============ Governance Functions ============
    function updateValidators(address[] calldata _validators, uint256[] calldata _powers) external onlyGovernance {
        require(_validators.length == _powers.length, "Length mismatch");
        require(_validators.length >= MIN_VALIDATOR_SIGNERS, "Not enough validators");

        // Clear old validators
        for (uint256 i = 0; i < validators.length; i++) {
            isValidator[validators[i].addr] = false;
        }

        delete validators;
        totalValidatorPower = 0;

        // Add new validators
        for (uint256 i = 0; i < _validators.length; i++) {
            require(_validators[i] != address(0), "Invalid validator");
            require(_powers[i] > 0, "Zero power");

            validators.push(Validator({
                addr: _validators[i],
                power: _powers[i]
            }));
            isValidator[_validators[i]] = true;
            totalValidatorPower += _powers[i];
        }

        emit ValidatorSetUpdated(_validators, _powers);
    }

    function setGovernance(address _governance) external onlyOwner {
        require(_governance != address(0), "Invalid governance");
        governance = _governance;
    }

    // ============ Token Management ============
    function deployAndMapToken(
        string memory _name,
        string memory _symbol,
        uint8 _decimals,
        address _originToken
    ) external onlyGovernance returns (address) {
        require(_originToken != address(0), "Invalid origin token");
        require(originToLocalToken[_originToken] == address(0), "Token already mapped");

        ERC20Mintable token = new ERC20Mintable(_name, _symbol, _decimals);
        address localAddress = address(token);

        originToLocalToken[_originToken] = localAddress;
        localToOriginToken[localAddress] = _originToken;

        emit TokenMapped(_originToken, localAddress, _symbol);
        return localAddress;
    }

    function mapExistingToken(address _originToken, address _localToken) external onlyGovernance {
        require(_originToken != address(0), "Invalid origin");
        require(_localToken != address(0), "Invalid local");
        require(originToLocalToken[_originToken] == address(0), "Already mapped");
        require(localToOriginToken[_localToken] == address(0), "Local taken");

        originToLocalToken[_originToken] = _localToken;
        localToOriginToken[_localToken] = _originToken;

        emit TokenMapped(_originToken, _localToken, ERC20(_localToken).symbol());
    }

    // ============ User Functions ============
    function lockTokens(
        address _token,
        uint256 _amount,
        address _recipient,
        ChainID _destinationChain
    ) external nonReentrant {
        require(_destinationChain != currentChain, "Same chain");
        require(_recipient != address(0), "Invalid recipient");
        require(_amount > 0, "Amount zero");
        require(originToLocalToken[_token] != address(0) || _token == address(0), "Unsupported token");

        bytes32 txHash = keccak256(abi.encode(
            _token,
            msg.sender,
            _amount,
            _recipient,
            currentChain,
            _destinationChain,
            block.timestamp,
            block.number
        ));

        require(!executedTransactions[_destinationChain][txHash], "Already executed");

        if (_token != address(0)) {
            IERC20(_token).safeTransferFrom(msg.sender, address(this), _amount);
        } else {
            require(msg.value == _amount, "Incorrect ETH value");
        }

        transactions[txHash] = Transaction(
            txHash,
            msg.sender,
            _token,
            _amount,
            _recipient,
            currentChain,
            _destinationChain,
            checkpointIndex,
            false
        );

        emit TokensLocked(_token, msg.sender, _amount, _recipient, _destinationChain, checkpointIndex);

        // Submit checkpoint if needed
        if (checkpointIndex % CHECKPOINT_INTERVAL == 0) {
            _submitCheckpoint();
        }
    }

    // Called on destination chain
    function mintTokens(
        bytes32 _txHash,
        bytes[] calldata _signatures
    ) external nonReentrant {
        require(!transactions[_txHash].executed, "Already minted");
        require(_verifyCheckpointSignatures(_txHash, _signatures), "Invalid signatures");

        Transaction storage tx = transactions[_txHash];
        tx.executed = true;

        if (tx.token == address(0)) {
            // Handle ETH (WETH or direct transfer)
            payable(tx.recipient).transfer(tx.amount);
        } else {
            address localToken = originToLocalToken[tx.token];
            require(localToken != address(0), "Token not mapped");
            ERC20Mintable(localToken).mint(tx.recipient, tx.amount);
        }

        emit TokensMinted(tx.token, tx.recipient, tx.amount, tx.nonce);
        emit TransactionExecuted(_txHash, tx.nonce);
    }

    // ============ Validator Functions ============
    function _submitCheckpoint() internal {
        bytes32 root = _calculateCheckpointRoot();
        checkpoints[checkpointIndex] = Checkpoint({
            root: root,
            index: checkpointIndex,
            timestamp: block.timestamp
        });

        emit CheckpointSubmitted(root, checkpointIndex, msg.sender);
        checkpointIndex++;
    }

    function _calculateCheckpointRoot() internal view returns (bytes32) {
        // In practice, this would be a Merkle root of recent transactions
        // For simplicity, we hash the latest transaction batch
        bytes32 acc = 0x0;
        uint256 start = checkpointIndex * CHECKPOINT_INTERVAL;
        uint256 end = start + CHECKPOINT_INTERVAL;

        // This is a simplified placeholder
        for (uint256 i = start; i < end && i < checkpointIndex * CHECKPOINT_INTERVAL; i++) {
            // In reality, accumulate transaction hashes
            acc = keccak256(abi.encode(acc, i));
        }
        return acc;
    }

    function _verifyCheckpointSignatures(bytes32 _txHash, bytes[] memory _signatures) internal view returns (bool) {
        Transaction memory tx = transactions[_txHash];
        require(tx.executed == false, "Already executed");

        Checkpoint storage cp = checkpoints[tx.nonce];
        require(cp.index == tx.nonce, "Checkpoint not found");

        uint256 power = 0;
        bytes32 digest = keccak256(abi.encodePacked(
            "\x19Ethereum Signed Message:\n32",
            cp.root
        ));

        for (uint256 i = 0; i < _signatures.length; i++) {
            address signer = ecrecover(digest, _signatures[i]);
            if (isValidator[signer] && !cp.processedValidators[signer]) {
                power += getValidatorPower(signer);
                cp.processedValidators[signer] = true;
            }
        }

        return power >= (totalValidatorPower * 2) / 3; // 2/3+ BFT threshold
    }

    function getValidatorPower(address _validator) public view returns (uint256) {
        for (uint256 i = 0; i < validators.length; i++) {
            if (validators[i].addr == _validator) {
                return validators[i].power;
            }
        }
        return 0;
    }

    // ============ Withdraw & Rescue ============
    function withdrawStuckTokens(address _token, address _to) external onlyOwner {
        require(_to != address(0), "Invalid recipient");
        if (_token == address(0)) {
            payable(_to).transfer(address(this).balance);
        } else {
            uint256 balance = IERC20(_token).balanceOf(address(this));
            IERC20(_token).safeTransfer(_to, balance);
        }
    }
}

