    function balanceOf(address account) external view returns (uint256);
}
contract OCR2Aggregator {
    address public owner;
    LinkTokenInterface public linkToken;
    uint256 public paymentAmount;
    uint256 public minAnswer;
    uint256 public maxAnswer;
    uint256 public latestAnswer;
    uint256 public latestTimestamp;
    mapping(address => bool) public signers;
    mapping(address => bool) public transmitters;
    struct Config {
        uint32 maxAnswer;
        uint32 minAnswer;
        uint32 paymentAmount;
        uint64 timeout;
    }
    Config public config;
    event AnswerUpdated(int256 indexed current, uint256 indexed roundId, uint256 updatedAt);
    event ConfigSet(uint32 maxAnswer, uint32 minAnswer, uint32 paymentAmount, uint64 timeout);
    event SignerUpdated(address signer, bool authorized);
    event TransmitterUpdated(address transmitter, bool authorized);
    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }
    modifier onlySigner() {
        require(signers[msg.sender], "Not signer");
        _;
    }
    modifier onlyTransmitter() {
        require(transmitters[msg.sender], "Not transmitter");
        _;
    }
    constructor(address _linkToken, uint256 _paymentAmount) {
        owner = msg.sender;
        linkToken = LinkTokenInterface(_linkToken);
        paymentAmount = _paymentAmount;
    }
    function submit(uint256 _answer, uint256 _timestamp, bytes calldata _signature) external onlySigner {
        require(_answer >= minAnswer && _answer <= maxAnswer, "Answer out of bounds");
        require(_timestamp <= block.timestamp, "Invalid timestamp");
        latestAnswer = _answer;
        latestTimestamp = _timestamp;
        emit AnswerUpdated(int256(_answer), 1, _timestamp);
    }
    function transmit(uint256 _answer, uint256 _timestamp) external onlyTransmitter {
        require(_answer >= minAnswer && _answer <= maxAnswer, "Answer out of bounds");
        require(_timestamp <= block.timestamp, "Invalid timestamp");
        latestAnswer = _answer;
        latestTimestamp = _timestamp;
        linkToken.transferAndCall(msg.sender, paymentAmount, "");
        emit AnswerUpdated(int256(_answer), 1, _timestamp);
    }
    function setConfig(uint32 _maxAnswer, uint32 _minAnswer, uint32 _paymentAmount, uint64 _timeout) external onlyOwner {
        require(_minAnswer < _maxAnswer, "Invalid bounds");
        config = Config(_maxAnswer, _minAnswer, _paymentAmount, _timeout);
        maxAnswer = _maxAnswer;
        minAnswer = _minAnswer;
        paymentAmount = _paymentAmount;
        emit ConfigSet(_maxAnswer, _minAnswer, _paymentAmount, _timeout);
    }
    function updateSigner(address _signer, bool _authorized) external onlyOwner {
        signers[_signer] = _authorized;
        emit SignerUpdated(_signer, _authorized);
    }
    function updateTransmitter(address _transmitter, bool _authorized) external onlyOwner {
        transmitters[_transmitter] = _authorized;
        emit TransmitterUpdated(_transmitter, _authorized);
    }
    function withdrawLink(address _to, uint256 _amount) external onlyOwner {
        require(linkToken.balanceOf(address(this)) >= _amount, "Insufficient balance");
        linkToken.transferAndCall(_to, _amount, "");
    }
    function latestRoundData() external view returns (uint80, int256, uint256, uint256, uint80) {
        return (0, int256(latestAnswer), latestTimestamp, latestTimestamp, 0);
    }
}

