import {EVMFetcher} from '@ensdomains/evm-verifier/contracts/EVMFetcher.sol';
import {EVMFetchTarget} from '@ensdomains/evm-verifier/contracts/EVMFetchTarget.sol';
import {BytesUtils} from '@ensdomains/ens-contracts/contracts/dnssec-oracle/BytesUtils.sol';
import {IAddrResolver} from '@ensdomains/ens-contracts/contracts/resolvers/profiles/IAddrResolver.sol';
import {ITextResolver} from '@ensdomains/ens-contracts/contracts/resolvers/profiles/ITextResolver.sol';
import {INameResolver} from '@ensdomains/ens-contracts/contracts/resolvers/profiles/INameResolver.sol';
import {IEVMVerifier} from '@ensdomains/evm-verifier/contracts/IEVMVerifier.sol';
import '@openzeppelin/contracts/access/Ownable.sol';
import './strings.sol';
contract Dm3NameRegistrarEVMFetcher is EVMFetchTarget, Ownable {
    using EVMFetcher for EVMFetcher.EVMFetchRequest;
    using BytesUtils for bytes;
    using strings for *;
    IEVMVerifier public verifier;
    address public target;
    string public parentDomain;
    uint256 private constant RECORD_VERSIONS_SLOT = 201;
    uint256 private constant PARENT_NODE_SLOT = 202;
    uint256 private constant OWNER_SLOT = 203;
    uint256 private constant REVERSE_SLOT = 204;
    uint256 private constant TEXTS_SLOT = 205;
    error UnknownSelector();
    constructor(
        IEVMVerifier _verifier,
        address _target,
        string memory _parentDomain
    ) Ownable(msg.sender) {
        verifier = _verifier;
        target = _target;
        parentDomain = _parentDomain;
    }
    function setVerifier(IEVMVerifier _verifier) external onlyOwner {
        verifier = _verifier;
    }
    function setTarget(address _target) external onlyOwner {
        target = _target;
    }
    function setParentDomain(string memory _parentDomain) external onlyOwner {
        parentDomain = _parentDomain;
    }
    function resolve(
        bytes calldata,
        bytes calldata data
    ) external view returns (bytes memory result) {
        bytes4 selector = bytes4(data);
        if (selector == INameResolver.name.selector) {
            bytes32 node = abi.decode(data[4:], (bytes32));
            return _name(node);
        }
        if (selector == ITextResolver.text.selector) {
            (bytes32 node, string memory key) = abi.decode(
                data[4:],
                (bytes32, string)
            );
            return bytes(_text(node, key));
        }
        if (selector == IAddrResolver.addr.selector) {
            bytes32 node = abi.decode(data[4:], (bytes32));
            return _addr(node);
        }
        revert UnknownSelector();
    }
    function _addr(bytes32 node) private view returns (bytes memory) {
        EVMFetcher
            .newFetchRequest(verifier, target)
            .getStatic(OWNER_SLOT)
            .element(node)
            .fetch(this.addrCallback.selector, '');
    }
    function _name(bytes32 node) private view returns (bytes memory) {
        EVMFetcher
            .newFetchRequest(verifier, target)
            .getStatic(PARENT_NODE_SLOT)
            .getDynamic(REVERSE_SLOT)
            .element(node)
            .fetch(this.nameCallback.selector, '');
    }
    function _text(
        bytes32 node,
        string memory key
    ) private view returns (bytes memory) {
        EVMFetcher
            .newFetchRequest(verifier, target)
            .getStatic(RECORD_VERSIONS_SLOT)
            .element(node)
            .getDynamic(TEXTS_SLOT)
            .ref(0)
            .element(node)
            .element(key)
            .fetch(this.textCallback.selector, '');
    }
    function textCallback(
        bytes[] memory values,
        bytes memory
    ) public pure returns (bytes memory) {
        return abi.encode(string(values[1]));
    }
    function nameCallback(
        bytes[] memory values,
        bytes memory
    ) public view returns (bytes memory) {
        strings.slice[] memory s = new strings.slice[](3);
        s[0] = string(values[1]).toSlice();
        s[1] = '.'.toSlice();
        s[2] = parentDomain.toSlice();
        return abi.encode(''.toSlice().join(s));
    }
    function addrCallback(
        bytes[] memory values,
        bytes memory
    ) public pure returns (bytes memory) {
        return abi.encode(address(uint160(uint256(bytes32(values[0])))));
    }
}

pragma solidity ^0.8.24;
contract Tstorish {
    bool private _tstoreSupport;
    uint256 constant _TLOAD_TEST_PAYLOAD = 0x6002_601e_613d5c_3d_52_f3;
    uint256 constant _TLOAD_TEST_PAYLOAD_LENGTH = 0x0a;
    uint256 constant _TLOAD_TEST_PAYLOAD_OFFSET = 0x16;
    bool private immutable _tstoreInitialSupport;
    address private immutable _tloadTestContract;
    error TStoreAlreadyActivated();
    error TStoreNotSupported();
    error TloadTestContractDeploymentFailed();
    error OnlyDirectCalls();
    constructor() {
        address tloadTestContract = _prepareTloadTest();
        if (tloadTestContract == address(0)) {
            revert TloadTestContractDeploymentFailed();
        }
        bool tstoreInitialSupport = _testTload(tloadTestContract);
        _tstoreInitialSupport = tstoreInitialSupport;
        _tloadTestContract = tloadTestContract;
    }
    function __activateTstore() external {
        if (msg.sender != tx.origin) {
            revert OnlyDirectCalls();
        }
        if (_tstoreInitialSupport || _tstoreSupport) {
            revert TStoreAlreadyActivated();
        }
        if (!_testTload(_tloadTestContract)) {
            revert TStoreNotSupported();
        }
        _tstoreSupport = true;
    }
    function _setTstorish(uint256 storageSlot, uint256 value) internal {
        if (_tstoreInitialSupport) {
            assembly {
                tstore(storageSlot, value)
            }
        } else if (_tstoreSupport) {
            assembly {
                tstore(storageSlot, value)
            }
        } else {
            assembly {
                sstore(storageSlot, value)
            }
        }
    }
    function _getTstorish(
        uint256 storageSlot
    ) internal view returns (uint256 value) {
        if (_tstoreInitialSupport) {
            assembly {
                value := tload(storageSlot)
            }
        } else if (_tstoreSupport) {
            assembly {
                value := tload(storageSlot)
            }
        } else {
            assembly {
                value := sload(storageSlot)
            }
        }
    }
    function _clearTstorish(uint256 storageSlot) internal {
        if (_tstoreInitialSupport) {
            assembly {
                tstore(storageSlot, 0)
            }
        } else if (_tstoreSupport) {
            assembly {
                tstore(storageSlot, 0)
            }
        } else {
            assembly {
                sstore(storageSlot, 0)
            }
        }
    }
    function _prepareTloadTest() private returns (address contractAddress) {
        assembly {
            mstore(0, _TLOAD_TEST_PAYLOAD)
            contractAddress := create(
                0,
                _TLOAD_TEST_PAYLOAD_OFFSET,
                _TLOAD_TEST_PAYLOAD_LENGTH
            )
        }
    }
    function _testTload(
        address tloadTestContract
    ) private view returns (bool ok) {

        (ok, ) = tloadTestContract.staticcall{ gas: gasleft() / 10 }("");
    }
}

