pragma solidity ^0.8.0;
interface IUniswapV2Router {
    function swapExactTokensForETHSupportingFeeOnTransferTokens(uint amountIn, uint amountOutMin, address[] calldata path, address to, uint deadline) external;
    function addLiquidityETH(address token, uint amountTokenDesired, uint amountTokenMin, uint amountETHMin, address to, uint deadline) external payable returns (uint amountToken, uint amountETH, uint liquidity);
}
contract BOBToken {
    string public name = "BOB";
    string public symbol = "BOB";
    uint8 public decimals = 18;
    uint256 public totalSupply;
    address public owner;
    uint256 public maxTxAmount;
    uint256 public maxWalletAmount;
    bool public tradingEnabled;
    uint256 public launchBlock;
    uint256 public buyTax = 1500;
    uint256 public sellTax = 4000;
    uint256 public taxDivisor = 10000;
    address public taxWallet;
    IUniswapV2Router public router;
    address public pair;
    bool private swapping;
    uint256 public swapThreshold;
    mapping(address => uint256) public balanceOf;
    mapping(address => mapping(address => uint256)) public allowance;
    mapping(address => bool) public isExcludedFromFee;
    mapping(address => bool) public isExcludedFromMaxTx;
    mapping(address => bool) public isExcludedFromMaxWallet;
    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);
    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }
    constructor(uint256 _totalSupply, address _router, address _taxWallet) {
        totalSupply = _totalSupply * 10**18;
        owner = msg.sender;
        maxTxAmount = totalSupply * 2 / 100;
        maxWalletAmount = totalSupply * 3 / 100;
        taxWallet = _taxWallet;
        router = IUniswapV2Router(_router);
        pair = IUniswapV2Factory(router.factory()).createPair(address(this), router.WETH());
        swapThreshold = totalSupply / 1000;
        balanceOf[msg.sender] = totalSupply;
        isExcludedFromFee[msg.sender] = true;
        isExcludedFromFee[address(this)] = true;
        isExcludedFromMaxTx[msg.sender] = true;
        isExcludedFromMaxTx[address(this)] = true;
        isExcludedFromMaxWallet[msg.sender] = true;
        isExcludedFromMaxWallet[address(this)] = true;
        emit Transfer(address(0), msg.sender, totalSupply);
    }
    function transfer(address to, uint256 value) public returns (bool) {
        _transfer(msg.sender, to, value);
        return true;
    }
    function transferFrom(address from, address to, uint256 value) public returns (bool) {
        require(allowance[from][msg.sender] >= value, "Insufficient allowance");
        allowance[from][msg.sender] -= value;
        _transfer(from, to, value);
        return true;
    }
    function approve(address spender, uint256 value) public returns (bool) {
        allowance[msg.sender][spender] = value;
        emit Approval(msg.sender, spender, value);
        return true;
    }
    function _transfer(address from, address to, uint256 value) internal {
        require(from != address(0), "From zero address");
        require(to != address(0), "To zero address");
        require(balanceOf[from] >= value, "Insufficient balance");
        if (!isExcludedFromMaxTx[from] && !isExcludedFromMaxTx[to]) {
            require(value <= maxTxAmount, "Exceeds max transaction");
        }
        if (!isExcludedFromMaxWallet[to]) {
            require(balanceOf[to] + value <= maxWalletAmount, "Exceeds max wallet");
        }
        if (!tradingEnabled) {
            require(isExcludedFromFee[from] || isExcludedFromFee[to], "Trading disabled");
        }
        if (block.number <= launchBlock + 2) {
            require(isExcludedFromFee[from] || isExcludedFromFee[to], "Anti-bot protection");
        }
        uint256 taxAmount = 0;
        if (!isExcludedFromFee[from] && !isExcludedFromFee[to] && !swapping) {
            if (from == pair) {
                taxAmount = (value * buyTax) / taxDivisor;
            } else if (to == pair) {
                taxAmount = (value * sellTax) / taxDivisor;
            }
            if (taxAmount > 0) {
                balanceOf[address(this)] += taxAmount;
                emit Transfer(from, address(this), taxAmount);
            }
            if (from != pair && !swapping && balanceOf[address(this)] >= swapThreshold) {
                swapBack();
            }
        }
        balanceOf[from] -= value;
        balanceOf[to] += (value - taxAmount);
        emit Transfer(from, to, value - taxAmount);
    }
    function swapBack() private {
        swapping = true;
        uint256 contractBalance = balanceOf[address(this)];
        swapTokensForEth(contractBalance);
        swapping = false;
    }
    function swapTokensForEth(uint256 tokenAmount) private {
        address[] memory path = new address[](2);
        path[0] = address(this);
        path[1] = router.WETH();
        _approve(address(this), address(router), tokenAmount);
        router.swapExactTokensForETHSupportingFeeOnTransferTokens(tokenAmount, 0, path, taxWallet, block.timestamp);
    }
    function _approve(address tokenOwner, address spender, uint256 value) private {
        allowance[tokenOwner][spender] = value;
        emit Approval(tokenOwner, spender, value);
    }
    function enableTrading() public onlyOwner {
        require(!tradingEnabled, "Trading already enabled");
        tradingEnabled = true;
        launchBlock = block.number;
    }
    function setTaxes(uint256 _buyTax, uint256 _sellTax) public onlyOwner {
        require(_buyTax <= 2500 && _sellTax <= 5000, "Tax too high");
        buyTax = _buyTax;
        sellTax = _sellTax;
    }
    function setLimits(uint256 _maxTxAmount, uint256 _maxWalletAmount) public onlyOwner {
        maxTxAmount = _maxTxAmount;
        maxWalletAmount = _maxWalletAmount;
    }
    function setTaxWallet(address _taxWallet) public onlyOwner {
        taxWallet = _taxWallet;
    }
    function excludeAddress(address account, bool fromFee, bool fromMaxTx, bool fromMaxWallet) public onlyOwner {
        isExcludedFromFee[account] = fromFee;
        isExcludedFromMaxTx[account] = fromMaxTx;
        isExcludedFromMaxWallet[account] = fromMaxWallet;
    }
    receive() external payable {}
}
interface IUniswapV2Factory {
    function createPair(address tokenA, address tokenB) external returns (address pair);
}

pragma solidity ^0.8.0;
import "../ERC721Upgradeable.sol";
import "./IERC721EnumerableUpgradeable.sol";
import "../../../proxy/utils/Initializable.sol";
abstract contract ERC721EnumerableUpgradeable is Initializable, ERC721Upgradeable, IERC721EnumerableUpgradeable {
    function __ERC721Enumerable_init() internal onlyInitializing {
    }
    function __ERC721Enumerable_init_unchained() internal onlyInitializing {
    }
    mapping(address => mapping(uint256 => uint256)) private _ownedTokens;
    mapping(uint256 => uint256) private _ownedTokensIndex;
    uint256[] private _allTokens;
    mapping(uint256 => uint256) private _allTokensIndex;
    function supportsInterface(bytes4 interfaceId) public view virtual override(IERC165Upgradeable, ERC721Upgradeable) returns (bool) {
        return interfaceId == type(IERC721EnumerableUpgradeable).interfaceId || super.supportsInterface(interfaceId);
    }
    function tokenOfOwnerByIndex(address owner, uint256 index) public view virtual override returns (uint256) {
        require(index < ERC721Upgradeable.balanceOf(owner), "ERC721Enumerable: owner index out of bounds");
        return _ownedTokens[owner][index];
    }
    function totalSupply() public view virtual override returns (uint256) {
        return _allTokens.length;
    }
    function tokenByIndex(uint256 index) public view virtual override returns (uint256) {
        require(index < ERC721EnumerableUpgradeable.totalSupply(), "ERC721Enumerable: global index out of bounds");
        return _allTokens[index];
    }
    function _beforeTokenTransfer(
        address from,
        address to,
        uint256 firstTokenId,
        uint256 batchSize
    ) internal virtual override {
        super._beforeTokenTransfer(from, to, firstTokenId, batchSize);
        if (batchSize > 1) {
            revert("ERC721Enumerable: consecutive transfers not supported");
        }
        uint256 tokenId = firstTokenId;
        if (from == address(0)) {
            _addTokenToAllTokensEnumeration(tokenId);
        } else if (from != to) {
            _removeTokenFromOwnerEnumeration(from, tokenId);
        }
        if (to == address(0)) {
            _removeTokenFromAllTokensEnumeration(tokenId);
        } else if (to != from) {
            _addTokenToOwnerEnumeration(to, tokenId);
        }
    }
    function _addTokenToOwnerEnumeration(address to, uint256 tokenId) private {
        uint256 length = ERC721Upgradeable.balanceOf(to);
        _ownedTokens[to][length] = tokenId;
        _ownedTokensIndex[tokenId] = length;
    }
    function _addTokenToAllTokensEnumeration(uint256 tokenId) private {
        _allTokensIndex[tokenId] = _allTokens.length;
        _allTokens.push(tokenId);
    }
    function _removeTokenFromOwnerEnumeration(address from, uint256 tokenId) private {
        uint256 lastTokenIndex = ERC721Upgradeable.balanceOf(from) - 1;
        uint256 tokenIndex = _ownedTokensIndex[tokenId];
        if (tokenIndex != lastTokenIndex) {
            uint256 lastTokenId = _ownedTokens[from][lastTokenIndex];
            _ownedTokens[from][tokenIndex] = lastTokenId; 
            _ownedTokensIndex[lastTokenId] = tokenIndex; 
        }
        delete _ownedTokensIndex[tokenId];
        delete _ownedTokens[from][lastTokenIndex];
    }
    function _removeTokenFromAllTokensEnumeration(uint256 tokenId) private {
        uint256 lastTokenIndex = _allTokens.length - 1;
        uint256 tokenIndex = _allTokensIndex[tokenId];

        uint256 lastTokenId = _allTokens[lastTokenIndex];
        _allTokens[tokenIndex] = lastTokenId; 
        _allTokensIndex[lastTokenId] = tokenIndex; 
        delete _allTokensIndex[tokenId];
        _allTokens.pop();
    }
    uint256[46] private __gap;
}

pragma solidity 0.8.24;
import {IBoosterCardStakePool} from "./IBoosterCard.sol";
import {ERC721} from "solady/tokens/ERC721.sol";
import {Ownable} from "solady/auth/Ownable.sol";
import {ECDSA} from "openzeppelin/utils/cryptography/ECDSA.sol";
contract BoosterCard is ERC721, Ownable, IBoosterCardStakePool {
    string private _tokenURI;
    struct slot0 {
        address signer; 
        uint32 minted;  
    }
    slot0 private _slot0; 
    uint64 private haltTime;  
    uint96 constant TOKEN_TRANSFERABLE = 0;
    uint96 constant TOKEN_LOCKED = 1 << 95;
    constructor(string memory uri,  address signer) {
        require(signer != address(0), "BoosterCard: signer is zero address");
        _tokenURI = uri;
        _slot0 = slot0(signer, 0);
        _initializeOwner(msg.sender);
    }
    function name() public view virtual override returns (string memory) {
        return "Flap Booster Card";
    }
    function symbol() public view virtual override returns (string memory) {
        return "FS2C";
    }
    function tokenURI(
        uint256
    ) public view virtual override returns (string memory) {
        return _tokenURI;
    }
    function mint(
        uint32 _count,
        uint32 _max,
        bytes memory _proof,
        bool _stake
    ) external override {
        address signer = _slot0.signer;
        uint32 totalMinted = _slot0.minted;
        require(signer != address(0), "BoosterCard: minting is disabled");
        {
            bytes32 msgHash = ECDSA.toEthSignedMessageHash(keccak256(abi.encode(msg.sender, _max)));
            address recovered = ECDSA.recover(msgHash, _proof);
            require(recovered == signer, "BoosterCard: invalid proof");
        }
        uint224 aux = _getAux(msg.sender);
        (uint32 staking ,uint32 userMinted ,uint64 lastBlockTime ,uint96 realizedAccumulatedSeconds )= _unpackBalanceAux(aux);
        if(_count + userMinted > _max) {
           revert("BoosterCard: minting exceeds the limit");
        }
        userMinted += uint32(_count);
        totalMinted += uint32(_count);
        if(_stake){
            realizedAccumulatedSeconds += uint96((block.timestamp - lastBlockTime)) * uint96(staking);
            staking += uint32(_count);
            lastBlockTime = uint64(block.timestamp);
        }
        _setAux(msg.sender, _packBalanceAux(staking, userMinted, lastBlockTime, realizedAccumulatedSeconds));
        _slot0.minted = totalMinted;
        _slot0 = slot0(signer, totalMinted);
        uint[] memory tokenIDs = new uint[](_count);

        for(uint i = 0; i < _count; i++) {
            uint id = uint(totalMinted - _count + i);
            _mint(msg.sender, uint256(id));
            tokenIDs[i] = id;
            if(_stake){
                _setExtraData(uint256(id), TOKEN_LOCKED);
            }
        }
        if (_stake){
            emit Staked(msg.sender, tokenIDs);
            for(uint i = 0; i < tokenIDs.length; i++) {
                emit Transfer(msg.sender, address(this), tokenIDs[i]);
            }
        }
    }
    function stake(uint[] memory _tokenIds) external override {
        require(haltTime == 0, "BoosterCard: staking is disabled");
        for(uint i = 0; i < _tokenIds.length; i++) {
            uint tokenId = _tokenIds[i];
            require(ownerOf(tokenId) == msg.sender, "BoosterCard: not the owner");
            require(_getExtraData(tokenId) == TOKEN_TRANSFERABLE, "BoosterCard: token is locked(staked)");
            _setExtraData(tokenId, TOKEN_LOCKED);
        }
        {
            uint224 aux = _getAux(msg.sender);
            (uint32 staking ,uint32 minted ,uint64 lastBlockTime ,uint96 realizedAccumulatedSeconds )= _unpackBalanceAux(aux);
            realizedAccumulatedSeconds += uint96((block.timestamp - lastBlockTime)) * uint96(staking);
            staking += uint32(_tokenIds.length);
            lastBlockTime = uint64(block.timestamp);
            _setAux(msg.sender, _packBalanceAux(staking, minted, lastBlockTime, realizedAccumulatedSeconds));
        }
        emit Staked(msg.sender, _tokenIds);
        for(uint i = 0; i < _tokenIds.length; i++) {
            emit Transfer(msg.sender, address(this), _tokenIds[i]);
        }
    }
    function unstake(uint[] memory _tokenIds) external override {
        uint64 latestTime = haltTime == 0 ? uint64(block.timestamp) : haltTime;
        for(uint i = 0; i < _tokenIds.length; i++) {
            uint tokenId = _tokenIds[i];
            require(ownerOf(tokenId) == msg.sender, "BoosterCard: not the owner");
            require(_getExtraData(tokenId) == TOKEN_LOCKED, "BoosterCard: token is not locked(staked)");
            _setExtraData(tokenId, TOKEN_TRANSFERABLE);
        }
        {
            uint224 aux = _getAux(msg.sender);
            (uint32 staking ,uint32 minted ,uint64 lastBlockTime ,uint96 realizedAccumulatedSeconds )= _unpackBalanceAux(aux);
            realizedAccumulatedSeconds += uint96((latestTime - lastBlockTime)) * uint96(staking);
            staking -= uint32(_tokenIds.length);
            lastBlockTime = uint64(latestTime);
            _setAux(msg.sender, _packBalanceAux(staking, minted, lastBlockTime, realizedAccumulatedSeconds));
        }
        emit Unstaked(msg.sender, _tokenIds);
        for(uint i = 0; i < _tokenIds.length; i++) {
            emit Transfer(address(this), msg.sender, _tokenIds[i]);
        }
    }
    function halt() onlyOwner external override {
        _slot0.signer = address(0);
        haltTime = uint64(block.timestamp);
    }
    function changeSigner(address _signer) onlyOwner external override {
        require(_slot0.signer != address(0), "BoosterCard: minting is disabled");
        _slot0.signer = _signer;
    }
    function staked(address _user) external view override returns (uint) {
        uint224 aux = _getAux(_user);
        (uint32 staking,,,)= _unpackBalanceAux(aux);
        return staking;
    }
    function accumulatedSeconds(
        address _user
    ) external view override returns (uint) {
        uint224 aux = _getAux(_user);
        (uint32 staking ,,uint64 lastBlockTime ,uint96 realizedAccumulatedSeconds )= _unpackBalanceAux(aux);
        uint64 latestTime = haltTime == 0 ? uint64(block.timestamp) : haltTime;
        return realizedAccumulatedSeconds + uint96((latestTime - lastBlockTime)) * uint96(staking);
    }
    function _unpackBalanceAux(uint224 aux) internal pure returns (uint32 staking ,uint32 minted ,uint64 lastBlockTime ,uint96 realizedAccumulatedSeconds ) {
        return (uint32(aux >> 192), uint32(aux >> 160), uint64(aux >> 96), uint96(aux));
    }
    function _packBalanceAux(uint32 staking ,uint32 minted ,uint64 lastBlockTime ,uint96 realizedAccumulatedSeconds ) internal pure returns (uint224) {
        return uint224(staking) << 192 | uint224(minted) << 160 | uint224(lastBlockTime) << 96 | uint224(realizedAccumulatedSeconds);
    }
    function _beforeTokenTransfer(
        address from,
        address to,
        uint256 tokenId
    ) internal virtual override {
        if(from != address(0) && _getExtraData(tokenId) == TOKEN_LOCKED) {
            revert("BoosterCard: token is locked(staked)");
        }
        if(to == address(this)) {
            revert("BoosterCard: cannot transfer to this contract");
        }
    }
}

