import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

/**
 * @title Staking Contract
 * @dev A comprehensive staking contract with multiple plans, reward calculation, and admin controls.
 */
contract Staking is Ownable, ReentrancyGuard {
    using SafeERC20 for IERC20;

    // ============ Events ============

    event Staked(address indexed user, uint256 amount, uint256 planId, uint256 stakeId);
    event Unstaked(address indexed user, uint256 stakeId, uint256 amount, uint256 reward);
    event RewardClaimed(address indexed user, uint256 stakeId, uint256 reward);
    event PlanAdded(uint256 indexed planId, uint256 apr, uint256 lockPeriod);
    event PlanUpdated(uint256 indexed planId, uint256 apr, uint256 lockPeriod);
    event PlanRemoved(uint256 indexed planId);
    event Blacklisted(address indexed user, bool status);
    event EmergencyWithdraw(address indexed user, uint256 amount);
    event RewardsDeposited(uint256 amount);

    // ============ Structs ============

    struct StakingPlan {
        uint256 apr; // Annual Percentage Rate (e.g., 1000 = 10.00%)
        uint256 lockPeriod; // In seconds (e.g., 30 days = 30 * 86400)
        bool active;
    }

    struct Stake {
        uint256 planId;
        uint256 amount;
        uint256 startDate;
        uint256 lastClaim;
        bool active;
    }

    // ============ State Variables ============

    IERC20 public stakingToken;
    IERC20 public rewardToken;

    uint256 public totalStaked;
    uint256 public totalRewardsDistributed;

    mapping(uint256 => StakingPlan) public plans;
    uint256 public planCount;

    mapping(address => Stake[]) public userStakes;
    mapping(address => bool) public isBlacklisted;

    // ============ Modifiers ============

    modifier notBlacklisted() {
        require(!isBlacklisted[msg.sender], "User is blacklisted");
        _;
    }

    modifier planExists(uint256 planId) {
        require(planId < planCount && plans[planId].active, "Invalid or inactive plan");
        _;
    }

    // ============ Constructor ============

    constructor(address _stakingToken, address _rewardToken) {
        require(_stakingToken != address(0), "Invalid staking token");
        require(_rewardToken != address(0), "Invalid reward token");

        stakingToken = IERC20(_stakingToken);
        rewardToken = IERC20(_rewardToken);
    }

    // ============ Owner Functions ============

    /**
     * @dev Adds a new staking plan.
     * @param apr The annual percentage rate (in basis points, e.g., 1000 = 10.00%).
     * @param lockPeriod The lock period in seconds.
     */
    function addPlan(uint256 apr, uint256 lockPeriod) external onlyOwner {
        require(apr > 0, "APR must be > 0");
        require(lockPeriod > 0, "Lock period must be > 0");

        plans[planCount] = StakingPlan({
            apr: apr,
            lockPeriod: lockPeriod,
            active: true
        });

        emit PlanAdded(planCount, apr, lockPeriod);
        planCount++;
    }

    /**
     * @dev Updates an existing staking plan.
     * @param planId The ID of the plan to update.
     * @param apr The new APR.
     * @param lockPeriod The new lock period.
     */
    function updatePlan(uint256 planId, uint256 apr, uint256 lockPeriod) external onlyOwner planExists(planId) {
        require(apr > 0, "APR must be > 0");
        require(lockPeriod > 0, "Lock period must be > 0");

        StakingPlan storage plan = plans[planId];
        plan.apr = apr;
        plan.lockPeriod = lockPeriod;

        emit PlanUpdated(planId, apr, lockPeriod);
    }

    /**
     * @dev Deactivates a staking plan.
     * @param planId The ID of the plan to remove.
     */
    function removePlan(uint256 planId) external onlyOwner planExists(planId) {
        plans[planId].active = false;
        emit PlanRemoved(planId);
    }

    /**
     * @dev Adds or removes a user from the blacklist.
     * Blacklisted users cannot stake or claim rewards.
     * @param user The address to blacklist/whitelist.
     * @param status True to blacklist, false to whitelist.
     */
    function setBlacklist(address user, bool status) external onlyOwner {
        require(user != address(0), "Invalid user address");
        isBlacklisted[user] = status;
        emit Blacklisted(user, status);
    }

    /**
     * @dev Deposits reward tokens into the contract for distribution.
     * @param amount The amount of reward tokens to deposit.
     */
    function depositRewards(uint256 amount) external onlyOwner {
        require(amount > 0, "Amount must be > 0");
        rewardToken.safeTransferFrom(msg.sender, address(this), amount);
        emit RewardsDeposited(amount);
    }

    // ============ User Functions ============

    /**
     * @dev Allows a user to stake tokens in a specific plan.
     * @param amount The amount of tokens to stake.
     * @param planId The ID of the staking plan.
     */
    function stake(uint256 amount, uint256 planId)
        external
        nonReentrant
        notBlacklisted
        planExists(planId)
    {
        require(amount > 0, "Stake amount must be > 0");

        // Transfer tokens from user to contract
        stakingToken.safeTransferFrom(msg.sender, address(this), amount);

        // Create new stake
        Stake memory newStake = Stake({
            planId: planId,
            amount: amount,
            startDate: block.timestamp,
            lastClaim: block.timestamp,
            active: true
        });

        userStakes[msg.sender].push(newStake);
        totalStaked += amount;

        emit Staked(msg.sender, amount, planId, userStakes[msg.sender].length - 1);
    }

    /**
     * @dev Calculates the reward for a specific stake.
     * @param user The address of the staker.
     * @param stakeId The ID of the stake.
     * @return The calculated reward amount.
     */
    function calculateReward(address user, uint256 stakeId)
        public
        view
        returns (uint256)
    {
        Stake memory stake = userStakes[user][stakeId];
        require(stake.active, "Stake is inactive");

        if (block.timestamp <= stake.lastClaim) {
            return 0;
        }

        StakingPlan memory plan = plans[stake.planId];

        // Calculate time passed since last claim (in seconds)
        uint256 timeElapsed = block.timestamp - stake.lastClaim;

        // Calculate reward: (amount * apr * timeElapsed) / (10000 * 365 days)
        uint256 reward = (stake.amount * plan.apr * timeElapsed) /
            (10000 * 365 * 86400);

        return reward;
    }

    /**
     * @dev Claims rewards for a specific stake without unstaking.
     * @param stakeId The ID of the stake to claim rewards for.
     */
    function claimReward(uint256 stakeId) external nonReentrant notBlacklisted {
        Stake storage stake = userStakes[msg.sender][stakeId];
        require(stake.active, "Stake is inactive");
        require(stake.amount > 0, "No tokens staked");

        uint256 reward = calculateReward(msg.sender, stakeId);
        require(reward > 0, "No rewards to claim");

        // Update last claim time
        stake.lastClaim = block.timestamp;

        // Transfer reward
        rewardToken.safeTransfer(msg.sender, reward);
        totalRewardsDistributed += reward;

        emit RewardClaimed(msg.sender, stakeId, reward);
    }

    /**
     * @dev Unstakes tokens and claims accumulated rewards.
     * If the lock period has not passed, a penalty may apply.
     * @param stakeId The ID of the stake to unstake.
     */
    function unstake(uint256 stakeId) external nonReentrant notBlacklisted {
        Stake storage stake = userStakes[msg.sender][stakeId];
        require(stake.active, "Stake is inactive");
        require(stake.amount > 0, "No tokens staked");

        StakingPlan memory plan = plans[stake.planId];
        uint256 amount = stake.amount;

        // Check if lock period has passed
        bool lockPeriodPassed = block.timestamp >= (stake.startDate + plan.lockPeriod);

        // Calculate reward
        uint256 reward = calculateReward(msg.sender, stakeId);

        // Deactivate stake
        stake.active = false;
        stake.amount = 0;
        totalStaked -= amount;

        // Transfer staked tokens back
        stakingToken.safeTransfer(msg.sender, amount);

        // Transfer reward if lock period passed
        if (reward > 0 && lockPeriodPassed) {
            rewardToken.safeTransfer(msg.sender, reward);
            totalRewardsDistributed += reward;
        }

        emit Unstaked(msg.sender, stakeId, amount, lockPeriodPassed ? reward : 0);
    }

    /**
     * @dev Emergency function to withdraw staked tokens without rewards.
     * Only callable if the user is blacklisted.
     */
    function emergencyWithdraw() external nonReentrant {
        require(isBlacklisted[msg.sender], "User not blacklisted");

        Stake[] storage stakes = userStakes[msg.sender];
        uint256 totalAmount;

        for (uint256 i = 0; i < stakes.length; i++) {
            if (stakes[i].active && stakes[i].amount > 0) {
                totalAmount += stakes[i].amount;
                stakes[i].active = false;
                stakes[i].amount = 0;
            }
        }

        require(totalAmount > 0, "No tokens to withdraw");

        totalStaked -= totalAmount;
        stakingToken.safeTransfer(msg.sender, totalAmount);

        emit EmergencyWithdraw(msg.sender, totalAmount);
    }

    // ============ View Functions ============

    /**
     * @dev Returns the number of stakes for a user.
     */
    function getUserStakeCount(address user) external view returns (uint256) {
        return userStakes[user].length;
    }

    /**
     * @dev Returns detailed information about a user's stake.
     */
    function getUserStake(address user, uint256 stakeId)
        external
        view
        returns (
            uint256 planId,
            uint256 amount,
            uint256 startDate,
            uint256 lastClaim,
            bool active,
            uint256 reward
        )
    {
        Stake memory stake = userStakes[user][stakeId];
        uint256 pendingReward = stake.active ? calculateReward(user, stakeId) : 0;
        return (stake.planId, stake.amount, stake.startDate, stake.lastClaim, stake.active, pendingReward);
    }
}

