pragma solidity ^0.8.0;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

/**
 * @title Collateralized Loan Manager
 * @dev Manages loans backed by collateral within a synthetic asset system.
 * Enforces minimum collateralization ratios and integrates with system components.
 */
contract LoanManager is Ownable, ReentrancyGuard {
    using SafeERC20 for IERC20;

    // ============ Events ============

    event LoanOpened(
        address indexed borrower,
        uint256 loanId,
        address indexed collateralToken,
        uint256 collateralAmount,
        address indexed debtToken,
        uint256 debtAmount
    );
    event LoanAdjusted(
        address indexed borrower,
        uint256 loanId,
        int256 collateralDelta,
        int256 debtDelta
    );
    event LoanClosed(address indexed borrower, uint256 loanId);
    event LoanLiquidated(
        address indexed borrower,
        uint256 loanId,
        address indexed liquidator,
        uint256 reward
    );
    event CollateralRatioUpdated(address indexed token, uint256 minRatio);
    event FeePoolSet(address indexed feePool);
    event ExchangeRatesSet(address indexed exchangeRates);
    event SyntheticsManagerSet(address indexed syntheticsManager);

    // ============ Structs ============

    struct Loan {
        address borrower;
        address collateralToken;
        uint256 collateralAmount;
        address debtToken;
        uint256 debtAmount;
        bool active;
    }

    struct CollateralConfig {
        uint256 minCollateralRatio; // 18 decimals (e.g., 1.5e18 = 150%)
        bool enabled;
    }

    // ============ State Variables ============

    mapping(address => mapping(uint256 => Loan)) public userLoans;
    mapping(address => uint256) public userLoanCount;

    mapping(address => CollateralConfig) public collateralConfigs;
    address[] public collateralTokens;

    address public feePool;
    address public exchangeRates;
    address public syntheticsManager;

    uint256 public totalLoans;

    // ============ Modifiers ============

    modifier onlyActiveLoan(address borrower, uint256 loanId) {
        require(
            userLoans[borrower][loanId].active,
            "Loan: Loan not active"
        );
        _;
    }

    modifier collateralEnabled(address token) {
        require(
            collateralConfigs[token].enabled,
            "LoanManager: Collateral disabled"
        );
        _;
    }

    modifier systemAddressesSet() {
        require(
            feePool != address(0) &&
            exchangeRates != address(0) &&
            syntheticsManager != address(0),
            "LoanManager: System addresses not set"
        );
        _;
    }

    // ============ Constructor ============

    constructor() {
        // Constructor can be extended if needed
    }

    // ============ Owner Functions ============

    /**
     * @dev Adds or updates a collateral token configuration.
     * @param token The collateral token address.
     * @param minRatio The minimum collateralization ratio (e.g., 1.5e18 for 150%).
     */
    function setCollateralConfig(
        address token,
        uint256 minRatio
    ) external onlyOwner {
        require(token != address(0), "LoanManager: Invalid token");
        require(minRatio >= 1e18, "LoanManager: Ratio < 100%"); // Must be >= 100%

        if (!collateralConfigs[token].enabled) {
            collateralTokens.push(token);
        }

        collateralConfigs[token] = CollateralConfig({
            minCollateralRatio: minRatio,
            enabled: true
        });

        emit CollateralRatioUpdated(token, minRatio);
    }

    /**
     * @dev Disables a collateral token.
     * @param token The token to disable.
     */
    function disableCollateral(address token) external onlyOwner {
        require(collateralConfigs[token].enabled, "LoanManager: Already disabled");
        collateralConfigs[token].enabled = false;
    }

    /**
     * @dev Sets the address of the fee pool.
     * @param _feePool The fee pool contract address.
     */
    function setFeePool(address _feePool) external onlyOwner {
        require(_feePool != address(0), "LoanManager: Zero address");
        feePool = _feePool;
        emit FeePoolSet(_feePool);
    }

    /**
     * @dev Sets the address of the exchange rates oracle.
     * @param _exchangeRates The exchange rates contract address.
     */
    function setExchangeRates(address _exchangeRates) external onlyOwner {
        require(_exchangeRates != address(0), "LoanManager: Zero address");
        exchangeRates = _exchangeRates;
        emit ExchangeRatesSet(_exchangeRates);
    }

    /**
     * @dev Sets the address of the synthetics manager.
     * @param _syntheticsManager The synthetics manager contract address.
     */
    function setSyntheticsManager(address _syntheticsManager) external onlyOwner {
        require(_syntheticsManager != address(0), "LoanManager: Zero address");
        syntheticsManager = _syntheticsManager;
        emit SyntheticsManagerSet(_syntheticsManager);
    }

    // ============ User Functions ============

    /**
     * @dev Opens a new loan with specified collateral and debt.
     * @param collateralToken The token used as collateral.
     * @param collateralAmount The amount of collateral to deposit.
     * @param debtToken The synthetic token to borrow.
     * @param debtAmount The amount of debt to create.
     */
    function openLoan(
        address collateralToken,
        uint256 collateralAmount,
        address debtToken,
        uint256 debtAmount
    )
        external
        nonReentrant
        collateralEnabled(collateralToken)
        systemAddressesSet
    {
        require(collateralAmount > 0, "LoanManager: Zero collateral");
        require(debtAmount > 0, "LoanManager: Zero debt");

        // Transfer collateral to this contract
        IERC20(collateralToken).safeTransferFrom(
            msg.sender,
            address(this),
            collateralAmount
        );

        // Record the loan
        uint256 loanId = userLoanCount[msg.sender];
        userLoans[msg.sender][loanId] = Loan({
            borrower: msg.sender,
            collateralToken: collateralToken,
            collateralAmount: collateralAmount,
            debtToken: debtToken,
            debtAmount: debtAmount,
            active: true
        });

        // Interact with synthetics system to issue debt
        _issueDebt(debtToken, debtAmount);

        userLoanCount[msg.sender]++;
        totalLoans++;

        // Ensure collateralization ratio is met
        require(
            _getCollateralizationRatio(msg.sender, loanId) >= collateralConfigs[collateralToken].minCollateralRatio,
            "LoanManager: Insufficient collateral"
        );

        emit LoanOpened(
            msg.sender,
            loanId,
            collateralToken,
            collateralAmount,
            debtToken,
            debtAmount
        );
    }

    /**
     * @dev Adjusts an existing loan by adding/removing collateral or debt.
     * @param loanId The ID of the loan to adjust.
     * @param collateralDelta Positive to add, negative to remove collateral.
     * @param debtDelta Positive to borrow more, negative to repay debt.
     */
    function adjustLoan(
        uint256 loanId,
        int256 collateralDelta,
        int256 debtDelta
    )
        external
        nonReentrant
        onlyActiveLoan(msg.sender, loanId)
        systemAddressesSet
    {
        Loan storage loan = userLoans[msg.sender][loanId];
        CollateralConfig storage config = collateralConfigs[loan.collateralToken];

        // Handle collateral change
        if (collateralDelta > 0) {
            IERC20(loan.collateralToken).safeTransferFrom(
                msg.sender,
                address(this),
                uint256(collateralDelta)
            );
            loan.collateralAmount += uint256(collateralDelta);
        } else if (collateralDelta < 0) {
            uint256 amount = uint256(-collateralDelta);
            require(amount <= loan.collateralAmount, "LoanManager: Over-withdraw");
            loan.collateralAmount -= amount;
            IERC20(loan.collateralToken).safeTransfer(msg.sender, amount);
        }

        // Handle debt change
        if (debtDelta > 0) {
            loan.debtAmount += uint256(debtDelta);
            _issueDebt(loan.debtToken, uint256(debtDelta));
        } else if (debtDelta < 0) {
            uint256 amount = uint256(-debtDelta);
            require(amount <= loan.debtAmount, "LoanManager: Over-repay");
            loan.debtAmount -= amount;
            _burnDebt(loan.debtToken, amount);
        }

        // Validate collateralization after adjustment
        require(
            _getCollateralizationRatio(msg.sender, loanId) >= config.minCollateralRatio,
            "LoanManager: Insufficient collateral after adjustment"
        );

        emit LoanAdjusted(msg.sender, loanId, collateralDelta, debtDelta);
    }

    /**
     * @dev Closes an active loan by repaying all debt and withdrawing all collateral.
     * @param loanId The ID of the loan to close.
     */
    function closeLoan(uint256 loanId)
        external
        nonReentrant
        onlyActiveLoan(msg.sender, loanId)
    {
        Loan storage loan = userLoans[msg.sender][loanId];

        // Repay debt
        _burnDebt(loan.debtToken, loan.debtAmount);

        // Withdraw collateral
        uint256 collateralAmount = loan.collateralAmount;
        IERC20(loan.collateralToken).safeTransfer(msg.sender, collateralAmount);

        // Deactivate loan
        loan.active = false;
        loan.collateralAmount = 0;
        loan.debtAmount = 0;

        emit LoanClosed(msg.sender, loanId);
    }

    // ============ Liquidation Functions ============

    /**
     * @dev Liquidates an undercollateralized loan.
     * @param borrower The borrower's address.
     * @param loanId The ID of the loan to liquidate.
     */
    function liquidateLoan(address borrower, uint256 loanId)
        external
        nonReentrant
        onlyActiveLoan(borrower, loanId)
    {
        Loan storage loan = userLoans[borrower][loanId];

        // Check if undercollateralized
        require(
            _getCollateralizationRatio(borrower, loanId) < collateralConfigs[loan.collateralToken].minCollateralRatio,
            "LoanManager: Not undercollateralized"
        );

        // Calculate liquidation reward (e.g., 5% bonus)
        uint256 reward = (loan.collateralAmount * 5) / 100; // 5%
        uint256 liquidatorShare = loan.collateralAmount - reward;

        // Transfer collateral to liquidator and reward to fee pool
        IERC20(loan.collateralToken).safeTransfer(msg.sender, liquidatorShare);
        IERC20(loan.collateralToken).safeTransfer(feePool, reward);

        // Burn the debt
        _burnDebt(loan.debtToken, loan.debtAmount);

        // Deactivate loan
        loan.active = false;
        loan.collateralAmount = 0;
        loan.debtAmount = 0;

        emit LoanLiquidated(borrower, loanId, msg.sender, reward);
    }

    // ============ Internal Functions ============

    /**
     * @dev Issues synthetic debt tokens via the synthetics manager.
     * @param synthToken The synthetic token to issue.
     * @param amount The amount to issue.
     */
