        uint256 ratio = loan.active ? _getCollateralizationRatio(borrower, loanId) : 0;
        uint256 minRatio = loan.active ? collateralConfigs[loan.collateralToken].minCollateralRatio : 0;

        return (
            loan.collateralToken,
            loan.collateralAmount,
            loan.debtToken,
