contract DiscountSwapToken {
    string public name;
    string public symbol;
    uint8 public decimals;
    uint256 public totalSupply;
    address public owner;
    uint256 public constant DISCOUNT_RATE = 11000;
    uint256 public constant RATE_DIVISOR = 10000;
    uint256 public developerAllocation;
    uint256 public developerVestingEnd;
    uint256 public constant VESTING_DURATION = 365 days;
    IUniswapV2Router public router;
    address public pair;
    mapping(address => uint256) public balanceOf;
    mapping(address => mapping(address => uint256)) public allowance;
    mapping(address => uint256) public nonces;
    bytes32 public constant PERMIT_TYPEHASH = keccak256("Permit(address owner,address spender,uint256 value,uint256 nonce,uint256 deadline)");
    bytes32 public DOMAIN_SEPARATOR;
    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);
    event DiscountSwap(address indexed user, uint256 inputAmount, uint256 outputAmount);
    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }
    constructor(string memory _name, string memory _symbol, uint256 _totalSupply, address _router, address _developer) {
        name = _name;
        symbol = _symbol;
        decimals = 18;
        totalSupply = _totalSupply * 10**18;
        owner = msg.sender;
        developerAllocation = totalSupply * 10 / 100;
        developerVestingEnd = block.timestamp + VESTING_DURATION;
        router = IUniswapV2Router(_router);
        pair = IUniswapV2Factory(router.factory()).createPair(address(this), router.WETH());
        balanceOf[msg.sender] = totalSupply - developerAllocation;
        balanceOf[_developer] = developerAllocation;
        DOMAIN_SEPARATOR = keccak256(abi.encode(keccak256("EIP712Domain(string name,string version,uint256 chainId,address verifyingContract)"), keccak256(bytes(name)), keccak256(bytes("1")), block.chainid, address(this)));
        emit Transfer(address(0), msg.sender, totalSupply - developerAllocation);
        emit Transfer(address(0), _developer, developerAllocation);
    }
    function transfer(address to, uint256 value) public returns (bool) {
        _transfer(msg.sender, to, value);
        return true;
    }
    function transferFrom(address from, address to, uint256 value) public returns (bool) {
        require(allowance[from][msg.sender] >= value, "Insufficient allowance");
        allowance[from][msg.sender] -= value;
        _transfer(from, to, value);
        return true;
    }
    function approve(address spender, uint256 value) public returns (bool) {
        allowance[msg.sender][spender] = value;
        emit Approval(msg.sender, spender, value);
        return true;
    }
    function permit(address owner, address spender, uint256 value, uint256 deadline, uint8 v, bytes32 r, bytes32 s) external {
        require(deadline >= block.timestamp, "Permit expired");
        bytes32 digest = keccak256(abi.encodePacked("\x19\x01", DOMAIN_SEPARATOR, keccak256(abi.encode(PERMIT_TYPEHASH, owner, spender, value, nonces[owner]++, deadline))));
        address recoveredAddress = ecrecover(digest, v, r, s);
        require(recoveredAddress != address(0) && recoveredAddress == owner, "Invalid permit");
        allowance[owner][spender] = value;
        emit Approval(owner, spender, value);
    }
    function _transfer(address from, address to, uint256 value) internal {
        require(from != address(0), "From zero address");
        require(to != address(0), "To zero address");
        require(balanceOf[from] >= value, "Insufficient balance");
        if (from == balanceOf[developerAllocation] && block.timestamp < developerVestingEnd) {
            uint256 vested = (developerAllocation * (block.timestamp - (developerVestingEnd - VESTING_DURATION))) / VESTING_DURATION;
            require(value <= vested - balanceOf[from], "Vesting limit");
        }
        balanceOf[from] -= value;
        balanceOf[to] += value;
        emit Transfer(from, to, value);
    }
    function discountedSwap(uint256 amountIn, uint256 amountOutMin, address[] calldata path, uint256 deadline) external {
        require(path[0] == address(this), "Invalid path");
        uint256 balanceBefore = balanceOf[msg.sender];
        require(balanceBefore >= amountIn, "Insufficient balance");
        uint256 bonusAmount = (amountIn * (DISCOUNT_RATE - RATE_DIVISOR)) / RATE_DIVISOR;
        require(totalSupply + bonusAmount <= type(uint256).max, "Supply overflow");
        balanceOf[msg.sender] -= amountIn;
        totalSupply += bonusAmount;
        balanceOf[address(this)] += amountIn + bonusAmount;
        _approve(address(this), address(router), amountIn + bonusAmount);
        router.swapExactTokensForTokensSupportingFeeOnTransferTokens(amountIn + bonusAmount, amountOutMin, path, msg.sender, deadline);
        emit DiscountSwap(msg.sender, amountIn, amountIn + bonusAmount);
    }
    function addLiquidity(uint256 tokenAmount, uint256 ethAmount, uint256 minTokenAmount, uint256 minEthAmount, uint256 deadline) external onlyOwner {
        _approve(address(this), address(router), tokenAmount);
        router.addLiquidity{value: ethAmount}(address(this), router.WETH(), tokenAmount, ethAmount, minTokenAmount, minEthAmount, owner, deadline);
    }
    function _approve(address tokenOwner, address spender, uint256 value) private {
        allowance[tokenOwner][spender] = value;
        emit Approval(tokenOwner, spender, value);
    }
    function withdrawDeveloperTokens() external {
        require(block.timestamp >= developerVestingEnd, "Vesting not ended");
        uint256 amount = balanceOf[msg.sender];
        require(amount > 0, "No tokens to withdraw");
        _transfer(msg.sender, owner, amount);
    }
    receive() external payable {}
}
