contract Lock365days is Ownable {
    using SafeERC20 for IERC20;
    using SafeMath for uint256;
    uint256 public lockedTokens;
    uint256 public availableTokens;
    uint256 public expiry;
    uint256 public startTime;
    bool public locked = false;
    IERC20 public immutable token = IERC20(0x7efBAC35B65e73484764Fd00F18E64929E782855);
    address public walletOne = 0x8d6B1DE33CC3b78BBD5C29bCF3EE4F430A1FF7fa;
    address public walletTwo = 0x6b2Ad6AD2f1E988f7c101E612e017B015d6cD756;
    address public walletThree = 0xc1De4Ee2A136BCA566F7141eb0000a8DA9088257;
    address public walletFour = 0x8C70dD1b68C20A9c766ecA84B888666824F232dA;
    address public walletFive = 0x0ecb0A170ad60205fB4d8cdd03A277B28d49bDb2;
    uint256 public percentageOne = 20;
    uint256 public percentageTwo = 20;
    uint256 public percentageThree = 20;
    uint256 public percentageFour = 20;
    uint256 public percentageFive = 20;
    function lockTokens(uint256 _amount) external onlyOwner {
        require(!locked, "funds have been locked already");
        token.safeTransferFrom(msg.sender, address(this), _amount);
        lockedTokens = _amount;
        availableTokens = _amount;
        expiry = block.timestamp + 365 days;
        startTime = block.timestamp;
        locked = true;
    }
    function unLock() external onlyOwner {
        require(locked, "funds have not been locked yet");
        require(block.timestamp > expiry, "Cannot be withdrawn until time is complete");
        require(availableTokens > 0, "No tokens to be unlocked");
       uint256 amountOne = lockedTokens.mul(percentageOne).div(100);
       uint256 amountTwo = lockedTokens.mul(percentageTwo).div(100);
       uint256 amountThree = lockedTokens.mul(percentageThree).div(100);
       uint256 amountFour = lockedTokens.mul(percentageFour).div(100);
       uint256 amountFive = lockedTokens.mul(percentageFive).div(100);
       token.safeTransfer(walletOne, amountOne);
       token.safeTransfer(walletTwo, amountTwo);
       token.safeTransfer(walletThree, amountThree);
       token.safeTransfer(walletFour, amountFour);
       token.safeTransfer(walletFive, amountFive);
       locked = false;
       availableTokens = 0;
    }
    function safeUnlock() external onlyOwner {
        require(block.timestamp > expiry, "Cannot be withdrawn until time is complete");
        token.safeTransfer(msg.sender, token.balanceOf(address(this)));
    }

}

