pragma solidity ^0.8.2;
contract CarbonCreditToken is ERC20, Ownable {
    string private _uriBase;
    string private _burnUriBase; 
    string private _tokenLogoUrl;
    mapping(uint256 => string) private _tokenData;
    mapping(address => bool) private _burner; 
    mapping(uint256 => PreservationArea) private _preservationAreas; 
    event TokenURI(string indexed uriBase, uint256 indexed tokenId);
    event BurnToken(address indexed burner, uint256 indexed amount, string burnUri); 
    struct PreservationArea {
        string info;
        string governmentApproval; 
    }
    constructor(
        uint256 initialSupply,
        string memory name_,
        string memory symbol_,
        string memory uriBase_,
        string memory burnUriBase_, 
        string memory tokenLogoUrl_,
        address initialOwner
    ) ERC20(name_, symbol_) Ownable(initialOwner) {
        _mint(initialOwner, initialSupply);
        _uriBase = uriBase_;
        _burnUriBase = burnUriBase_; 
        _tokenLogoUrl = tokenLogoUrl_;
    }
    function mint(address account, uint256 amount, string memory tokenUri, string memory preservationArea, string memory governmentApproval) external onlyOwner {
        _mint(account, amount);
        uint256 tokenId = totalSupply();
        _setTokenURI(tokenId, tokenUri);
        _setPreservationArea(tokenId, preservationArea, governmentApproval);
    }
    function burn(uint256 amount, string memory tokenUri) external {
        require(_burner[_msgSender()], "Only authorized burner can burn tokens");
        _burn(_msgSender(), amount);
        emit BurnToken(_msgSender(), amount, tokenUri); 
    }
    function _setTokenURI(uint256 tokenId, string memory uri) internal {
        require(bytes(uri).length > 0, "URI must be non-empty");
        emit TokenURI(_uriBase, tokenId);
        _tokenData[tokenId] = uri;
    }
    function getTokenData(uint256 tokenId) external view returns (string memory) {
        return _tokenData[tokenId];
    }
    function getPreservationArea(uint256 tokenId) external view returns (string memory info, string memory governmentApproval) {
        PreservationArea memory area = _preservationAreas[tokenId];
        return (area.info, area.governmentApproval);
    }
    function _setPreservationArea(uint256 tokenId, string memory info, string memory governmentApproval) internal {
        _preservationAreas[tokenId] = PreservationArea(info, governmentApproval);
    }
    function authorizeBurner(address burner) external onlyOwner {
        _burner[burner] = true;
    }
    function revokeBurner(address burner) external onlyOwner {
        _burner[burner] = false;
    }
    function decimals() public pure override returns (uint8) {
        return 3;
    }
    function transferWithZeroDecimals(address recipient, uint256 amount) external returns (bool) {
        uint256 adjustedAmount = amount * (10 ** uint256(decimals()));
        require(adjustedAmount % (10 ** uint256(decimals())) == 0, "Amount must have 0 decimals");
        adjustedAmount = adjustedAmount / (10 ** uint256(decimals()));
        return super.transfer(recipient, adjustedAmount);
    }
}

pragma solidity ^0.8.15;
import {ECDSA} from "@openzeppelin/contracts/utils/cryptography/ECDSA.sol";
import {EIP712} from "@openzeppelin/contracts/utils/cryptography/EIP712.sol";
import {EarnAssetHolder, Asset, AssetType} from "./EarnAssetHolder.sol";
contract EarnStakingPool is EIP712, EarnAssetHolder {
    struct StakePosition {
        uint256 stakingAssetId;
        uint256 amount;
        uint256 timestamp;
        uint256[] erc721tokenIds;
        uint256 unstakeDate;
        uint256 previousStakePositionId;
        bool liquidated;
    }
    struct StakeInputData {
        address executor;
        bytes32 assetId;
        address contractAddress;
        uint256 erc1155tokenId;
        uint256[] erc721TokenIds;
        uint256 amount;
        uint256 durationSeconds;
        uint256 transactionNonce;
        AssetType assetType;
        uint256 deadline;
    }
    struct LiquidationData {
        address executor;
        bytes32 assetId;
        uint256 stakePositionId;
        uint256 nonce;
        uint256 amountToTreasury;
        uint256 deadline;
    }
    mapping(address => mapping(bytes32 => uint256))
        internal currentStakePositionOfUser;
    mapping(uint256 => StakePosition) internal stakePosition;
    uint256 public transactionsIndex;
    mapping(bytes32 => uint256) public tokensStaked;
    constructor(
        address _stakingManager
    ) EIP712("EarnNetwork", "1") EarnAssetHolder(_stakingManager) {}
    function stakePositionOf(
        address _staker,
        bytes32 _assetId
    ) public view returns (StakePosition memory) {
        return stakePosition[currentStakePositionOfUser[_staker][_assetId]];
    }
    function _updatePositionForStaker(
        bytes32 _assetId,
        address _staker,
        uint256 updateNum,
        uint256 amountToAdd,
        uint256[] memory erc721TokenIds,
        uint256 unstakeDate,
        bool removeAmount,
        bool liquidated
    ) internal returns (StakePosition memory spu) {
        if (erc721TokenIds.length > 0) {
            require(
                erc721TokenIds.length == amountToAdd,
                "ESP: amountToAdd != erc721TokenIds.length"
            );
        }
        if (removeAmount) {
            require(unstakeDate == 0, "ESP: unstakeDate != 0");
            require(amountToAdd == 0, "ESP: amountToAdd != 0");
        }
        spu = stakePositionOf(_staker, _assetId);
        if (unstakeDate > spu.unstakeDate && !removeAmount) {
            spu.unstakeDate = unstakeDate;
        }
        spu.timestamp = block.timestamp;
        spu.liquidated = liquidated;
        if (removeAmount) {
            spu.erc721tokenIds = new uint256[](0);
            spu.amount = 0;
        } else {
            spu.amount = spu.amount + amountToAdd;
            uint256[] memory tokenIds = new uint256[](
                spu.erc721tokenIds.length + erc721TokenIds.length
            );
            for (uint256 i = 0; i < spu.erc721tokenIds.length; i++) {
                tokenIds[i] = spu.erc721tokenIds[i];
            }
            for (uint256 i = 0; i < erc721TokenIds.length; i++) {
                tokenIds[spu.erc721tokenIds.length + i] = erc721TokenIds[i];
            }
            spu.erc721tokenIds = tokenIds;
        }
        stakePosition[updateNum] = spu;
        currentStakePositionOfUser[_staker][_assetId] = updateNum;
    }
    function _verify(
        StakeInputData memory stakeData,
        bytes memory signature
    ) internal view {
        require(stakeData.deadline >= block.timestamp, "ESP: deadline not reached");
        bytes32 typedHash = _hashTypedDataV4(
            keccak256(
                abi.encode(
                    keccak256(
                        "StakeInputData(address executor,bytes32 assetId,address contractAddress,uint256 erc1155tokenId,uint256[] erc721TokenIds,uint256 amount,uint256 durationSeconds,uint256 transactionNonce,uint256 assetType,uint256 deadline)"
                    ),
                    stakeData.executor == address(0) ? address(0) : msg.sender,
                    stakeData.assetId,
                    stakeData.contractAddress,
                    stakeData.erc1155tokenId,
                    keccak256(abi.encodePacked(stakeData.erc721TokenIds)),
                    stakeData.amount,
                    stakeData.durationSeconds,
                    stakeData.transactionNonce,
                    stakeData.assetType,
                    stakeData.deadline
                )
            )
        );
        address signer = ECDSA.recover(typedHash, signature);
        require(signer == stakingManager.signer(), "ESP: Invalid signature");
    }
    function deposit(
        StakeInputData memory stakeData,
        bytes memory signature
    ) external payable {
        require(stakeData.amount > 0, "ESP: amount cannot be zero");
        _verify(stakeData, signature);
        if (stakeData.transactionNonce > 0) {
            _useNonce(stakeData.transactionNonce);
        }
        Asset memory sa = stakingManager.getOrCreateAsset(
            stakeData.assetId,
            stakeData.contractAddress,
            stakeData.erc1155tokenId,
            stakeData.assetType
        );
        _depositAsset(
            address(this),
            stakeData.amount,
            sa,
            stakeData.erc721TokenIds
        );
        transactionsIndex++;
        StakePosition memory sp = _updatePositionForStaker(
            stakeData.assetId,
            msg.sender,
            transactionsIndex,
            stakeData.amount,
            stakeData.erc721TokenIds,
            block.timestamp + stakeData.durationSeconds,
            false,
            false
        );
        tokensStaked[stakeData.assetId] += stakeData.amount;
        stakingManager.stakePositionUpdate(
            msg.sender,
            stakeData.assetId,
            stakeData.transactionNonce,
            sp.amount,
            tokensStaked[stakeData.assetId],
            transactionsIndex,
            block.timestamp,
            sp.unstakeDate,
            sp.erc721tokenIds,
            false
        );
    }
    function _verifyLiquidate(
        bytes32 assetId,
        uint256 nonce,
        uint256 amountToTreasury,
        uint256 deadline,
        bytes memory signature
    ) internal {
        require(deadline >= block.timestamp, "ESP: deadline not reached");
        _useNonce(nonce);
        bytes32 typedHash = _hashTypedDataV4(
            keccak256(
                abi.encode(
                    keccak256(
                        "Liquidate(address executor,bytes32 assetId,uint256 amountToTreasury,uint256 nonce,uint256 deadline)"
                    ),
                    msg.sender,
                    assetId,
                    amountToTreasury,
                    nonce,
                    deadline
                )
            )
        );
        address signer = ECDSA.recover(typedHash, signature);
        require(signer == stakingManager.signer(), "ESP: Invalid signature");
    }
    function liquidate(
        LiquidationData memory liqData,
        bytes memory signature
    ) external {
        require(msg.sender == liqData.executor, "ESP: executor != msg.sender");
        StakePosition memory sp = stakePositionOf(msg.sender, liqData.assetId);
        require(sp.amount > 0, "ESP: amount cannot be zero");
        require(sp.unstakeDate >= block.timestamp, "ESP: can be liquidated");
        _verifyLiquidate(
            liqData.assetId,
            liqData.nonce,
            liqData.amountToTreasury,
            liqData.deadline,
            signature
        );
        uint256 newTransactionsIndex = transactionsIndex + 1;
        StakePosition memory updated = _updatePositionForStaker(
            liqData.assetId,
            msg.sender,
            newTransactionsIndex,
            0,
            new uint256[](0),
            0,
            true,
            true
        );
        transactionsIndex++;
        tokensStaked[liqData.assetId] -= sp.amount;
        _withdrawAssets(
            msg.sender,
            sp.amount - liqData.amountToTreasury,
            sp.erc721tokenIds,
            liqData.assetId
        );
        if (liqData.amountToTreasury > 0) {
            _withdrawAssets(
                stakingManager.treasury(),
                liqData.amountToTreasury,
                new uint256[](0),
                liqData.assetId
            );
        }
        stakingManager.stakePositionUpdate(
            msg.sender,
            liqData.assetId,
            liqData.nonce,
            0,
            tokensStaked[liqData.assetId],
            newTransactionsIndex,
            block.timestamp,
            updated.unstakeDate,
            new uint256[](0),
            true
        );
    }
    function withdraw(bytes32 assetId) external {
        StakePosition memory sp = stakePositionOf(msg.sender, assetId);
        require(sp.amount > 0, "ESP: amount cannot be zero");
        require(
            sp.unstakeDate <= block.timestamp,
            "ESP: unstakeDate not reached"
        );
        uint256 newTransactionsIndex = transactionsIndex + 1;
        StakePosition memory updated = _updatePositionForStaker(
            assetId,
            msg.sender,
            newTransactionsIndex,
            0,
            new uint256[](0),
            0,
            true,
            false
        );
        transactionsIndex++;
        tokensStaked[assetId] -= sp.amount;
        _withdrawAssets(msg.sender, sp.amount, sp.erc721tokenIds, assetId);
        stakingManager.stakePositionUpdate(
            msg.sender,
            assetId,
            0,
            0,
            tokensStaked[assetId],
            newTransactionsIndex,
            block.timestamp,
            updated.unstakeDate,
            new uint256[](0),
            false
        );
    }
}

