        uint256 low = 0;
        uint256 high = length - 1;
        while (low < high) {
            uint256 mid = (low + high + 1) / 2;
            if (self._checkpoints[mid].key <= key) {
                low = mid;
            } else {
                high = mid - 1;
            }
        }
        return self._checkpoints[low].value;
    }
