    constructor(bytes32 _merkleRoot, address _airdropTokenAddress, address _tokenOwner)  {
        merkleRoot = _merkleRoot;
        airdropTokenAddress = _airdropTokenAddress;
        tokenOwner = _tokenOwner;
    }
    function onlyOwner_updateAirdropOpen(bool _airdropOpen) public onlyOwner {
        airdropOpen = _airdropOpen;
    }
    function onlyOwner_setRound(uint256 _roundNumber, bytes32 _merkleRoot) public onlyOwner {
        roundNumber = _roundNumber;
        merkleRoot = _merkleRoot;
    }
    function claim(
        address _receiver,
        uint256 _amount,
        bytes32[] calldata _proof
    ) external {
        uint256 amount = _amount*decimalMultiplier;
        require(airdropOpen, "Airdrop not open");
        require(claimedByWallet[_receiver] < roundNumber, "Address already claimed this round");
        require(verify(_receiver, _amount, _proof), "Invalid proof and/or amount");
        claimedByWallet[_receiver] = roundNumber;
        require(IERC20(airdropTokenAddress).transferFrom(tokenOwner, _receiver, amount), "transfer failed");
    }
    function verify(
        address _receiver,
        uint256 _amount,
        bytes32[] calldata _proof
    ) public view returns (bool){
        bytes32 leaf = keccak256(bytes.concat(keccak256(abi.encode(_receiver, _amount))));
        return MerkleProof.verify(_proof, merkleRoot, leaf);
    }
    function currentRound(
    ) public view returns (uint256){
        return roundNumber;
    }
}

