pragma solidity ^0.8.0;
contract MultiSigWallet {
    address[] public owners;
    mapping(address => bool) public isOwner;
    uint public required;
    uint public transactionCount;
    struct Transaction {
        address destination;
        uint value;
        bytes data;
        bool executed;
        uint confirmationCount;
    }
    mapping(uint => Transaction) public transactions;
    mapping(uint => mapping(address => bool)) public confirmations;
    event Submission(uint indexed transactionId);
    event Confirmation(address indexed sender, uint indexed transactionId);
    event Execution(uint indexed transactionId);
    event OwnerAddition(address indexed owner);
    event OwnerRemoval(address indexed owner);
    event RequirementChange(uint required);
    modifier onlyWallet() {
        require(msg.sender == address(this), "Not wallet");
        _;
    }
    modifier ownerExists(address owner) {
        require(isOwner[owner], "Not owner");
        _;
    }
    modifier transactionExists(uint transactionId) {
        require(transactions[transactionId].destination != address(0), "Tx doesn't exist");
        _;
    }
    modifier notExecuted(uint transactionId) {
        require(!transactions[transactionId].executed, "Already executed");
        _;
    }
    constructor(address[] memory _owners, uint _required) {
        require(_owners.length > 0 && _required > 0 && _required <= _owners.length, "Invalid requirement");
        for (uint i = 0; i < _owners.length; i++) {
            require(_owners[i] != address(0) && !isOwner[_owners[i]], "Invalid owner");
            isOwner[_owners[i]] = true;
        }
        owners = _owners;
        required = _required;
    }
    receive() external payable {}
    function submitTransaction(address destination, uint value, bytes memory data) public ownerExists(msg.sender) returns (uint transactionId) {
        transactionId = transactionCount;
        transactions[transactionId] = Transaction(destination, value, data, false, 0);
        transactionCount += 1;
        emit Submission(transactionId);
        confirmTransaction(transactionId);
    }
    function confirmTransaction(uint transactionId) public ownerExists(msg.sender) transactionExists(transactionId) notExecuted(transactionId) {
        require(!confirmations[transactionId][msg.sender], "Already confirmed");
        confirmations[transactionId][msg.sender] = true;
        transactions[transactionId].confirmationCount += 1;
        emit Confirmation(msg.sender, transactionId);
        if (transactions[transactionId].confirmationCount >= required) {
            executeTransaction(transactionId);
        }
    }
    function executeTransaction(uint transactionId) public transactionExists(transactionId) notExecuted(transactionId) {
        require(transactions[transactionId].confirmationCount >= required, "Not enough confirmations");
        Transaction storage txn = transactions[transactionId];
        txn.executed = true;
        (bool success, ) = txn.destination.call{value: txn.value}(txn.data);
        require(success, "Execution failed");
        emit Execution(transactionId);
    }
    function revokeConfirmation(uint transactionId) public ownerExists(msg.sender) transactionExists(transactionId) notExecuted(transactionId) {
        require(confirmations[transactionId][msg.sender], "Not confirmed");
        confirmations[transactionId][msg.sender] = false;
        transactions[transactionId].confirmationCount -= 1;
    }
    function addOwner(address owner) public onlyWallet {
        require(owner != address(0) && !isOwner[owner], "Invalid owner");
        isOwner[owner] = true;
        owners.push(owner);
        emit OwnerAddition(owner);
    }
    function removeOwner(address owner) public onlyWallet {
        require(isOwner[owner], "Not owner");
        isOwner[owner] = false;
        for (uint i = 0; i < owners.length - 1; i++) {
            if (owners[i] == owner) {
                owners[i] = owners[owners.length - 1];
                break;
            }
        }
        owners.pop();
        if (required > owners.length) {
            changeRequirement(owners.length);
        }
        emit OwnerRemoval(owner);
    }
    function changeRequirement(uint _required) public onlyWallet {
        require(_required > 0 && _required <= owners.length, "Invalid requirement");
        required = _required;
        emit RequirementChange(_required);
    }
    function getOwners() public view returns (address[] memory) {
        return owners;
    }
    function getTransactionCount() public view returns (uint) {
        return transactionCount;
    }
    function isConfirmed(uint transactionId) public view returns (bool) {
        return transactions[transactionId].confirmationCount >= required;
    }
}

