contract CustomToken is IERC20 {
    string public constant name = "CustomToken";
    string public constant symbol = "CTK";
    uint8 public constant decimals = 18;
    uint256 private _totalSupply = 1000000 * 10**decimals;

    address public owner;
    address public uniswapV2Pair;
    IUniswapV2Router02 public uniswapV2Router;

    mapping(address => uint256) private _balances;
    mapping(address => mapping(address => uint256)) private _allowances;
    mapping(address => bool) public isBlacklisted;

    uint256 public buyTax = 5;
    uint256 public sellTax = 5;
    uint256 public maxTxAmount = _totalSupply / 100;
    uint256 public maxWalletBalance = _totalSupply / 50;
    bool public tradingEnabled = false;

    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }

    constructor() {
        owner = msg.sender;
        _balances[owner] = _totalSupply;
        emit Transfer(address(0), owner, _totalSupply);

        IUniswapV2Router02 _router = IUniswapV2Router02(0x7a250d5630B4cF539739dF2C5dAcb4c659F2488D);
        uniswapV2Router = _router;
        uniswapV2Pair = IUniswapV2Factory(_router.factory()).createPair(address(this), _router.WETH());
    }

    function totalSupply() external view override returns (uint256) { return _totalSupply; }
    function balanceOf(address account) public view override returns (uint256) { return _balances[account]; }
    function allowance(address holder, address spender) external view override returns (uint256) { return _allowances[holder][spender]; }

    function approve(address spender, uint256 amount) public override returns (bool) {
        _allowances[msg.sender][spender] = amount;
        emit Approval(msg.sender, spender, amount);
        return true;
    }

    function transfer(address recipient, uint256 amount) external override returns (bool) {
        return _transfer(msg.sender, recipient, amount);
    }

    function transferFrom(address sender, address recipient, uint256 amount) external override returns (bool) {
        uint256 currentAllowance = _allowances[sender][msg.sender];
        require(currentAllowance >= amount, "ERC20: transfer amount exceeds allowance");
        _approve(sender, msg.sender, currentAllowance - amount);
        return _transfer(sender, recipient, amount);
    }

    function _approve(address holder, address spender, uint256 amount) private {
        _allowances[holder][spender] = amount;
        emit Approval(holder, spender, amount);
    }

    function _transfer(address sender, address recipient, uint256 amount) private returns (bool) {
        require(!isBlacklisted[sender] && !isBlacklisted[recipient], "Blacklisted address");
        require(tradingEnabled || sender == owner || recipient == owner, "Trading not enabled");
        require(amount > 0, "Amount zero");
        require(amount <= maxTxAmount, "Exceeds max tx");

        if (recipient != uniswapV2Pair) {
            require(_balances[recipient] + amount <= maxWalletBalance, "Exceeds max wallet");
        }

        uint256 tax = 0;
        if (sender == uniswapV2Pair) {
            tax = (amount * buyTax) / 100;
        } else if (recipient == uniswapV2Pair) {
            tax = (amount * sellTax) / 100;
        }

        uint256 transferAmount = amount - tax;
        _balances[sender] = _balances[sender] - amount;
        _balances[recipient] = _balances[recipient] + transferAmount;

        if (tax > 0) {
            _balances[address(this)] = _balances[address(this)] + tax;
            emit Transfer(sender, address(this), tax);
        }

        emit Transfer(sender, recipient, transferAmount);
        return true;
    }

    function enableTrading() external onlyOwner {
        tradingEnabled = true;
    }

    function blacklist(address account) external onlyOwner {
        isBlacklisted[account] = true;
    }

    function unblacklist(address account) external onlyOwner {
        isBlacklisted[account] = false;
    }

    function setTaxes(uint256 newBuyTax, uint256 newSellTax) external onlyOwner {
        require(newBuyTax <= 20 && newSellTax <= 20, "Tax too high");
        buyTax = newBuyTax;
        sellTax = newSellTax;
    }

    function setMaxTxAmount(uint256 amount) external onlyOwner {
        maxTxAmount = amount;
    }

    function setMaxWalletBalance(uint256 amount) external onlyOwner {
        maxWalletBalance = amount;
    }

    function collectTaxes() external onlyOwner {
        uint256 amount = _balances[address(this)];
        _balances[address(this)] = 0;
        _balances[owner] = _balances[owner] + amount;
        emit Transfer(address(this), owner, amount);
    }

    function swapAndLiquify() external onlyOwner {
        uint256 tokensToSwap = _balances[address(this)];
        if (tokensToSwap == 0) return;

        address[] memory path = new address[](2);
        path[0] = address(this);
        path[1] = uniswapV2Router.WETH();

        _approve(address(this), address(uniswapV2Router), tokensToSwap);
        uniswapV2Router.swapExactTokensForETHSupportingFeeOnTransferTokens(
            tokensToSwap,
            0,
            path,
            owner,
            block.timestamp
        );
    }
}

