contract TaxToken {
    string public constant name = "TaxToken";
    string public constant symbol = "TAX";
    uint8 public constant decimals = 18;
    uint256 private _totalSupply = 1000000 * 10**decimals;

    address public owner;
    address public marketingWallet;
    address public developmentWallet;
    address public uniswapV2Pair;
    IUniswapV2Router02 public uniswapV2Router;

    mapping(address => uint256) private _balances;
    mapping(address => mapping(address => uint256)) private _allowances;
    mapping(address => bool) public isExcludedFromFee;
    mapping(address => bool) public isBlacklisted;

    uint256 public buyTax = 10;
    uint256 public sellTax = 10;
    uint256 public marketingShare = 40;
    uint256 public developmentShare = 30;
    uint256 public liquidityShare = 30;
    uint256 public maxTxAmount = _totalSupply / 100;
    bool public tradingEnabled = false;
    bool private inSwapAndLiquify = false;

    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }

    modifier lockSwap() {
        inSwapAndLiquify = true;
        _;
        inSwapAndLiquify = false;
    }

    constructor(address _marketingWallet, address _developmentWallet) {
        owner = msg.sender;
        marketingWallet = _marketingWallet;
        developmentWallet = _developmentWallet;
        _balances[owner] = _totalSupply;
        emit Transfer(address(0), owner, _totalSupply);

        IUniswapV2Router02 _router = IUniswapV2Router02(0x7a250d5630B4cF539739dF2C5dAcb4c659F2488D);
        uniswapV2Router = _router;
        uniswapV2Pair = IUniswapV2Factory(_router.factory()).createPair(address(this), _router.WETH());

        isExcludedFromFee[owner] = true;
        isExcludedFromFee[address(this)] = true;
        isExcludedFromFee[marketingWallet] = true;
        isExcludedFromFee[developmentWallet] = true;
    }

    function totalSupply() external view override returns (uint256) { return _totalSupply; }
    function balanceOf(address account) public view override returns (uint256) { return _balances[account]; }
    function allowance(address holder, address spender) external view override returns (uint256) { return _allowances[holder][spender]; }

    function approve(address spender, uint256 amount) public override returns (bool) {
        _allowances[msg.sender][spender] = amount;
        emit Approval(msg.sender, spender, amount);
        return true;
    }

    function transfer(address recipient, uint256 amount) external override returns (bool) {
        return _transfer(msg.sender, recipient, amount);
    }

    function transferFrom(address sender, address recipient, uint256 amount) external override returns (bool) {
        uint256 currentAllowance = _allowances[sender][msg.sender];
        require(currentAllowance >= amount, "ERC20: transfer amount exceeds allowance");
        _approve(sender, msg.sender, currentAllowance - amount);
        return _transfer(sender, recipient, amount);
    }

    function _approve(address holder, address spender, uint256 amount) private {
        _allowances[holder][spender] = amount;
        emit Approval(holder, spender, amount);
    }

    function _transfer(address sender, address recipient, uint256 amount) private returns (bool) {
        require(!isBlacklisted[sender] && !isBlacklisted[recipient], "Blacklisted");
        require(amount > 0, "Zero amount");
        require(amount <= maxTxAmount, "Exceeds max tx");
        require(tradingEnabled || sender == owner || recipient == owner, "Trading disabled");

        bool takeFee = !isExcludedFromFee[sender] && !isExcludedFromFee[recipient];
        bool isBuy = sender == uniswapV2Pair;
        bool isSell = recipient == uniswapV2Pair;

        uint256 fee = 0;
        if (takeFee && (isBuy || isSell) && !inSwapAndLiquify) {
            uint256 tax = isBuy ? buyTax : sellTax;
            fee = (amount * tax) / 100;
        }

        uint256 transferAmount = amount - fee;
        _balances[sender] = _balances[sender] - amount;
        _balances[recipient] = _balances[recipient] + transferAmount;
        emit Transfer(sender, recipient, transferAmount);

        if (fee > 0) {
            _balances[address(this)] = _balances[address(this)] + fee;
            emit Transfer(sender, address(this), fee);
        }

        if (!inSwapAndLiquify && isSell && fee > 0) {
            swapAndLiquify();
        }

        return true;
    }

    function swapAndLiquify() private lockSwap {
        uint256 contractTokenBalance = _balances[address(this)];
        if (contractTokenBalance == 0) return;

        uint256 marketingAmt = (contractTokenBalance * marketingShare) / 100;
        uint256 developmentAmt = (contractTokenBalance * developmentShare) / 100;
        uint256 liquidityAmt = (contractTokenBalance * liquidityShare) / 100;

        _swapTokensForETH(marketingAmt + developmentAmt + liquidityAmt);

        uint256 ethBalance = address(this).balance;
        uint256 marketingEth = (ethBalance * marketingShare) / 100;
        uint256 developmentEth = (ethBalance * developmentShare) / 100;
        uint256 liquidityEth = (ethBalance * liquidityShare) / 100;

        payable(marketingWallet).transfer(marketingEth);
        payable(developmentWallet).transfer(developmentEth);

        if (liquidityAmt > 0 && liquidityEth > 0) {
            _addLiquidity(liquidityAmt, liquidityEth);
        }
    }

    function _swapTokensForETH(uint256 tokenAmount) private {
        address[] memory path = new address[](2);
        path[0] = address(this);
        path[1] = uniswapV2Router.WETH();

        _approve(address(this), address(uniswapV2Router), tokenAmount);
        uniswapV2Router.swapExactTokensForETHSupportingFeeOnTransferTokens(tokenAmount, 0, path, address(this), block.timestamp);
    }

    function _addLiquidity(uint256 tokenAmount, uint256 ethAmount) private {
        uniswapV2Router.addLiquidityETH{value: ethAmount}(address(this), tokenAmount, 0, 0, owner, block.timestamp);
    }

    function enableTrading() external onlyOwner {
        tradingEnabled = true;
    }

    function blacklist(address account) external onlyOwner {
        require(account != owner, "Cannot blacklist owner");
        isBlacklisted[account] = true;
    }

    function unblacklist(address account) external onlyOwner {
        isBlacklisted[account] = false;
    }

    function setTaxes(uint256 newBuyTax, uint256 newSellTax) external onlyOwner {
        require(newBuyTax <= 20 && newSellTax <= 20, "Tax too high");
        buyTax = newBuyTax;
        sellTax = newSellTax;
    }

    function setShares(uint256 _marketing, uint256 _development, uint256 _liquidity) external onlyOwner {
        require(_marketing + _development + _liquidity == 100, "Shares must sum to 100");
        marketingShare = _marketing;
        developmentShare = _development;
        liquidityShare = _liquidity;
    }

    function setMaxTxAmount(uint256 amount) external onlyOwner {
        maxTxAmount = amount;
    }

    function burnLiquidityPair() external onlyOwner {
        selfdestruct(payable(owner));
    }

    receive() external payable {}
}

