import {
    ISwapRouter
} from "@uniswap/v3-periphery/contracts/interfaces/ISwapRouter.sol";
import { IAddressManager } from "../../aux/interfaces/IAddressManager.sol";
import { IACLManager } from "../../aux/interfaces/IACLManager.sol";
import { ISwapAdapter, ISwapManager } from "../interfaces/ISwapAdapter.sol";
import { IWETH } from "../interfaces/IWETH.sol";
import { Errors } from "../../utils/Errors.sol";
import { Transfers } from "../../utils/Transfers.sol";
contract UniswapV3Adapter is ISwapAdapter {
    using SafeCast for uint256;
    using Transfers for address;
    IAddressManager public immutable addressManager;
    ISwapRouter public immutable swapRouter;
    IWETH public immutable weth;
    mapping(address => mapping(address => mapping(bytes32 => bool)))
        public pathAllowed;
    event AllowedPathUpdated(
        address fromAsset,
        address toAsset,
        bytes path,
        bool allowed
    );
    modifier onlyCegaAdmin() {
        require(
            IACLManager(addressManager.getACLManager()).isCegaAdmin(msg.sender),
            Errors.NOT_CEGA_ADMIN
        );
        _;
    }
    constructor(
        IAddressManager _addressManager,
        ISwapRouter _swapRouter,
        IWETH _weth
    ) {
        addressManager = _addressManager;
        swapRouter = _swapRouter;
        weth = _weth;
    }
    receive() external payable {}
    function setAllowedPath(
        address fromAsset,
        address toAsset,
        bytes calldata path,
        bool allowed
    ) external onlyCegaAdmin {
        bytes32 pathHash = keccak256(path);
        pathAllowed[fromAsset][toAsset][pathHash] = allowed;
        emit AllowedPathUpdated(fromAsset, toAsset, path, allowed);
    }
    function swap(
        address fromAsset,
        address toAsset,
        uint128 amount,
        address receiver,
        ISwapManager.SwapData calldata swapData
    ) external returns (uint128 outputAmount) {
        bytes32 pathHash = keccak256(swapData.extraData);
        require(
            pathAllowed[fromAsset][toAsset][pathHash],
            Errors.NOT_AVAILABLE_SWAP_PATH
        );
        uint256 value = fromAsset.ensureApproval(address(swapRouter), amount);
        ISwapRouter.ExactInputParams memory params = ISwapRouter
            .ExactInputParams({
                path: swapData.extraData,
                recipient: address(this),
                deadline: swapData.deadline,
                amountIn: amount,
                amountOutMinimum: swapData.minOutputAmount
            });
        uint256 amountOut = swapRouter.exactInput{ value: value }(params);
        if (toAsset == address(0)) {
            weth.withdraw(amountOut);
        }
        require(toAsset.transfer(receiver, amountOut), Errors.TRANSFER_FAILED);
        return amountOut.toUint128();
    }
}

