        assembly {
            r := mload(add(signature, 0x20))
            s := mload(add(signature, 0x40))
            v := byte(0, mload(add(signature, 0x60)))
        }
        if (uint256(s) > 0x7FFFFFFFFFFFFFFFFFFFFFFFFFFFFFFF5D576E7357A4501DDFE92F46681B20A0) return address(0);
        if (v != 27 && v != 28) return address(0);
        return ecrecover(hash, v, r, s);
    }
}
contract ORIONO {
    using SafeMath for uint256;
    string public constant name = "ORIONO";
    string public constant symbol = "RONO";
    uint8 public constant decimals = 18;
    uint256 public totalSupply;
    address public owner;
    bytes32 public DOMAIN_SEPARATOR;
    bytes32 public constant PERMIT_TYPEHASH = keccak256("Permit(address owner,address spender,uint256 value,uint256 nonce,uint256 deadline)");
    mapping(address => uint256) public balanceOf;
    mapping(address => mapping(address => uint256)) public allowance;
    mapping(address => uint256) public nonces;
    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);
    event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);
    event Burn(address indexed burner, uint256 value);
    modifier onlyOwner() {
        require(msg.sender == owner, "ORIONO: caller is not owner");
        _;
    }
    constructor(uint256 _totalSupply) {
        owner = msg.sender;
        totalSupply = _totalSupply * 10**18;
        balanceOf[msg.sender] = totalSupply;
        DOMAIN_SEPARATOR = keccak256(abi.encode(keccak256("EIP712Domain(string name,string version,uint256 chainId,address verifyingContract)"), keccak256(bytes(name)), keccak256(bytes("1")), block.chainid, address(this)));
        emit Transfer(address(0), msg.sender, totalSupply);
    }
    function transfer(address to, uint256 value) public returns (bool) {
        _transfer(msg.sender, to, value);
        return true;
    }
    function transferFrom(address from, address to, uint256 value) public returns (bool) {
        _approve(from, msg.sender, allowance[from][msg.sender].sub(value));
        _transfer(from, to, value);
        return true;
    }
    function approve(address spender, uint256 value) public returns (bool) {
        _approve(msg.sender, spender, value);
        return true;
    }
    function permit(address owner, address spender, uint256 value, uint256 deadline, uint8 v, bytes32 r, bytes32 s) external {
        require(deadline >= block.timestamp, "ORIONO: expired deadline");
        bytes32 structHash = keccak256(abi.encode(PERMIT_TYPEHASH, owner, spender, value, nonces[owner]++, deadline));
        bytes32 digest = keccak256(abi.encodePacked("\x19\x01", DOMAIN_SEPARATOR, structHash));
        address recoveredAddress = ECDSA.recover(digest, abi.encodePacked(r, s, v));
        require(recoveredAddress != address(0) && recoveredAddress == owner, "ORIONO: invalid signature");
        _approve(owner, spender, value);
    }
    function burn(uint256 value) public {
        _burn(msg.sender, value);
    }
    function burnFrom(address account, uint256 value) public {
        _approve(account, msg.sender, allowance[account][msg.sender].sub(value));
        _burn(account, value);
    }
    function transferOwnership(address newOwner) public onlyOwner {
        require(newOwner != address(0), "ORIONO: new owner is zero address");
        emit OwnershipTransferred(owner, newOwner);
        owner = newOwner;
    }
    function _transfer(address from, address to, uint256 value) internal {
        require(from != address(0), "ORIONO: transfer from zero address");
        require(to != address(0), "ORIONO: transfer to zero address");
        balanceOf[from] = balanceOf[from].sub(value);
        balanceOf[to] = balanceOf[to].add(value);
        emit Transfer(from, to, value);
    }
    function _approve(address owner, address spender, uint256 value) internal {
        require(owner != address(0), "ORIONO: approve from zero address");
        require(spender != address(0), "ORIONO: approve to zero address");
        allowance[owner][spender] = value;
        emit Approval(owner, spender, value);
    }
    function _burn(address account, uint256 value) internal {
        require(account != address(0), "ORIONO: burn from zero address");
        balanceOf[account] = balanceOf[account].sub(value);
        totalSupply = totalSupply.sub(value);
        emit Burn(account, value);
        emit Transfer(account, address(0), value);
    }
}

