contract NFTMarketplaceAggregator {
    address public owner;
    uint256 public platformFee;
    address public feeRecipient;
    IWETH public weth;
    struct Marketplace {
        address router;
        bool enabled;
    }
    mapping(string => Marketplace) public marketplaces;
    struct PurchaseParams {
        string marketplace;
        address collection;
        uint256 tokenId;
        uint256 price;
        bytes tradeData;
        address currency;
    }
    event PurchaseExecuted(address indexed buyer, address collection, uint256 tokenId, uint256 price, string marketplace);
    event MarketplaceUpdated(string name, address router, bool enabled);
    event FeeUpdated(uint256 oldFee, uint256 newFee);
    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }
    constructor(address _weth, uint256 _platformFee, address _feeRecipient) {
        owner = msg.sender;
        weth = IWETH(_weth);
        platformFee = _platformFee;
        feeRecipient = _feeRecipient;
    }
    function purchase(PurchaseParams calldata params) external payable {
        Marketplace storage marketplace = marketplaces[params.marketplace];
        require(marketplace.enabled, "Marketplace disabled");
        uint256 totalCost = params.price;
        uint256 fee = (totalCost * platformFee) / 10000;
        uint256 netAmount = totalCost - fee;
        if (params.currency == address(0)) {
            require(msg.value >= totalCost, "Insufficient ETH");
            weth.deposit{value: totalCost}();
        } else {
            IERC20(params.currency).transferFrom(msg.sender, address(this), totalCost);
        }
        if (params.currency == address(0)) {
            weth.transfer(feeRecipient, fee);
            weth.transfer(marketplace.router, netAmount);
        } else {
            IERC20(params.currency).transfer(feeRecipient, fee);
            IERC20(params.currency).transfer(marketplace.router, netAmount);
        }
        (bool success, ) = marketplace.router.call(params.tradeData);
        require(success, "Trade failed");
        IERC721(params.collection).safeTransferFrom(address(this), msg.sender, params.tokenId);
        emit PurchaseExecuted(msg.sender, params.collection, params.tokenId, params.price, params.marketplace);
    }
    function batchPurchase(PurchaseParams[] calldata params) external payable {
        uint256 totalETH;
        for (uint256 i = 0; i < params.length; i++) {
            if (params[i].currency == address(0)) {
                totalETH += params[i].price;
            }
        }
        if (totalETH > 0) {
            require(msg.value >= totalETH, "Insufficient ETH");
        }
        for (uint256 i = 0; i < params.length; i++) {
            PurchaseParams memory param = params[i];
            Marketplace storage marketplace = marketplaces[param.marketplace];
            require(marketplace.enabled, "Marketplace disabled");
            uint256 totalCost = param.price;
            uint256 fee = (totalCost * platformFee) / 10000;
            uint256 netAmount = totalCost - fee;
            if (param.currency == address(0)) {
                weth.deposit{value: totalCost}();
                weth.transfer(feeRecipient, fee);
                weth.transfer(marketplace.router, netAmount);
            } else {
                IERC20(param.currency).transferFrom(msg.sender, address(this), totalCost);
                IERC20(param.currency).transfer(feeRecipient, fee);
                IERC20(param.currency).transfer(marketplace.router, netAmount);
            }
            (bool success, ) = marketplace.router.call(param.tradeData);
            require(success, "Trade failed");
            IERC721(param.collection).safeTransferFrom(address(this), msg.sender, param.tokenId);
            emit PurchaseExecuted(msg.sender, param.collection, param.tokenId, param.price, param.marketplace);
        }
    }
    function addMarketplace(string calldata name, address router) external onlyOwner {
        marketplaces[name] = Marketplace(router, true);
        emit MarketplaceUpdated(name, router, true);
    }
    function setMarketplaceStatus(string calldata name, bool enabled) external onlyOwner {
        marketplaces[name].enabled = enabled;
        emit MarketplaceUpdated(name, marketplaces[name].router, enabled);
    }
    function setPlatformFee(uint256 newFee) external onlyOwner {
        require(newFee <= 1000, "Fee too high");
        emit FeeUpdated(platformFee, newFee);
        platformFee = newFee;
    }
    function setFeeRecipient(address newRecipient) external onlyOwner {
        feeRecipient = newRecipient;
    }
    function withdrawETH(uint256 amount) external onlyOwner {
        payable(owner).transfer(amount);
    }
    function withdrawERC20(address token, uint256 amount) external onlyOwner {
        IERC20(token).transfer(owner, amount);
    }
    function onERC721Received(address, address, uint256, bytes calldata) external pure returns (bytes4) {
        return this.onERC721Received.selector;
    }
    receive() external payable {}
}

