contract RewardsDistributor {
    address public owner;
    IComptroller public comptroller;
    address public rewardToken;
    struct MarketState {
        uint224 index;
        uint32 block;
    }
    struct RewardSpeed {
        uint256 supplySpeed;
        uint256 borrowSpeed;
    }
    struct UserIndex {
        uint256 supplierIndex;
        uint256 borrowerIndex;
    }
    mapping(address => MarketState) public supplyState;
    mapping(address => MarketState) public borrowState;
    mapping(address => RewardSpeed) public rewardSpeeds;
    mapping(address => mapping(address => UserIndex)) public userIndexes;
    mapping(address => uint256) public supplierRewards;
    mapping(address => uint256) public borrowerRewards;
    event RewardDistributed(address user, uint256 supplierAmount, uint256 borrowerAmount);
    event RewardSpeedUpdated(address market, uint256 supplySpeed, uint256 borrowSpeed);
    event OwnershipTransferred(address oldOwner, address newOwner);
    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }
    modifier onlyComptrollerAdmin() {
        require(msg.sender == comptroller.admin(), "Not comptroller admin");
        _;
    }
    constructor(address _comptroller, address _rewardToken) {
        owner = msg.sender;
        comptroller = IComptroller(_comptroller);
        rewardToken = _rewardToken;
    }
    function updateRewardSpeed(address market, uint256 supplySpeed, uint256 borrowSpeed) external onlyComptrollerAdmin {
        require(comptroller.isMarketListed(market), "Market not listed");
        rewardSpeeds[market] = RewardSpeed(supplySpeed, borrowSpeed);
        emit RewardSpeedUpdated(market, supplySpeed, borrowSpeed);
    }
    function distributeSupplierReward(address market, address supplier, bool distributeAll) external {
        require(comptroller.isMarketListed(market), "Market not listed");
        updateSupplyIndex(market);
        uint256 supplierIndex = supplyState[market].index;
        uint256 supplierIndexStored = userIndexes[market][supplier].supplierIndex;
        if (supplierIndexStored == 0 && supplierIndex > 0) {
            supplierIndexStored = 1e36;
        }
        uint256 deltaIndex = supplierIndex - supplierIndexStored;
        if (deltaIndex > 0) {
            uint256 supplierTokens = getSupplierTokens(market, supplier);
            uint256 supplierDelta = (supplierTokens * deltaIndex) / 1e36;
            uint256 supplierAccrued = supplierRewards[supplier] + supplierDelta;
            supplierRewards[supplier] = supplierAccrued;
            userIndexes[market][supplier].supplierIndex = supplierIndex;
            if (distributeAll && supplierAccrued > 0) {
                claimReward(supplier);
            }
        }
    }
    function distributeBorrowerReward(address market, address borrower, bool distributeAll) external {
        require(comptroller.isMarketListed(market), "Market not listed");
        updateBorrowIndex(market);
        uint256 borrowerIndex = borrowState[market].index;
        uint256 borrowerIndexStored = userIndexes[market][borrower].borrowerIndex;
        if (borrowerIndexStored == 0 && borrowerIndex > 0) {
            borrowerIndexStored = 1e36;
        }
        uint256 deltaIndex = borrowerIndex - borrowerIndexStored;
        if (deltaIndex > 0) {
            uint256 borrowerTokens = getBorrowerTokens(market, borrower);
            uint256 borrowerDelta = (borrowerTokens * deltaIndex) / 1e36;
            uint256 borrowerAccrued = borrowerRewards[borrower] + borrowerDelta;
            borrowerRewards[borrower] = borrowerAccrued;
            userIndexes[market][borrower].borrowerIndex = borrowerIndex;
            if (distributeAll && borrowerAccrued > 0) {
                claimReward(borrower);
            }
        }
    }
    function updateSupplyIndex(address market) public {
        MarketState memory state = supplyState[market];
        if (state.block > 0) {
            uint256 blockDelta = block.number - state.block;
            if (blockDelta > 0) {
                uint256 supplyTokens = getTotalSupplyTokens(market);
                uint256 supplySpeed = rewardSpeeds[market].supplySpeed;
                if (supplySpeed > 0 && supplyTokens > 0) {
                    uint256 accrued = blockDelta * supplySpeed;
                    uint256 ratio = (accrued * 1e36) / supplyTokens;
                    state.index = uint224(uint256(state.index) + ratio);
                }
                state.block = uint32(block.number);
                supplyState[market] = state;
            }
        }
    }
    function updateBorrowIndex(address market) public {
        MarketState memory state = borrowState[market];
        if (state.block > 0) {
            uint256 blockDelta = block.number - state.block;
            if (blockDelta > 0) {
                uint256 borrowTokens = getTotalBorrowTokens(market);
                uint256 borrowSpeed = rewardSpeeds[market].borrowSpeed;
                if (borrowSpeed > 0 && borrowTokens > 0) {
                    uint256 accrued = blockDelta * borrowSpeed;
                    uint256 ratio = (accrued * 1e36) / borrowTokens;
                    state.index = uint224(uint256(state.index) + ratio);
                }
                state.block = uint32(block.number);
                borrowState[market] = state;
            }
        }
    }
    function claimReward(address user) public {
        uint256 totalReward = supplierRewards[user] + borrowerRewards[user];
        if (totalReward > 0) {
            supplierRewards[user] = 0;
            borrowerRewards[user] = 0;
