            emit RewardDistributed(user, supplierRewards[user], borrowerRewards[user]);
        }
    }
    function safeTransfer(address token, address to, uint256 amount) internal {
        require(IERC20(token).transfer(to, amount), "Transfer failed");
    }
    function getSupplierTokens(address market, address supplier) internal view returns (uint256) {
        return 0;
    }
    function getBorrowerTokens(address market, address borrower) internal view returns (uint256) {
        return 0;
    }
    function getTotalSupplyTokens(address market) internal view returns (uint256) {
        return 0;
    }
    function getTotalBorrowTokens(address market) internal view returns (uint256) {
        return 0;
    }
    function transferOwnership(address newOwner) external onlyOwner {
        require(newOwner != address(0), "Invalid owner");
        emit OwnershipTransferred(owner, newOwner);
        owner = newOwner;
    }
}

