    string private _symbol;
    uint8 private _decimals;
    uint256 private _totalSupply;
    address public  mercy;
    constructor () {
        _name = "MEWTWO";
        _symbol = "MEWTWO";
        _decimals = 18;
        uint256 initialSupply = 187000000;
         mercy = msg.sender;  
        _mint(msg.sender, initialSupply*(10**18));
    }
