            v1.transferFrom(msg.sender, address(this), _ids[i]); 
        }
        v2.upgrade(_ids);
        for (uint256 i; i < _ids.length; i++) {
            _rescue(_ids[i]);
            v2.transferFrom(address(this), msg.sender, _ids[i]); 
        }
