import {Bridge, IERC20, SafeERC20} from "./Bridge.sol";
contract BridgeOCTA is Bridge {
    using SafeERC20 for IERC20;
    uint256 public constant MAX_BRIDGED = 48000000 ether;
    uint256 public unlockedOCTA;
    uint256 public unlockedWOCTA;
    error MaxLimitExceeded();
    error IncorrectAmount(uint256 tryToSendWithFee, uint256 sended);
    constructor() Bridge() {}
    function sendTokens(uint256 amountWithFee, uint256 toChainId) public payable override returns (uint256 amount) {
        if (address(this).balance > MAX_BRIDGED) {
            revert MaxLimitExceeded();
        }
        amount = super.sendTokens(amountWithFee, toChainId);
        if (msg.value > 0) {
            if (amountWithFee != msg.value) revert IncorrectAmount(amountWithFee, msg.value);
            unlockedOCTA += getFee();
        } else {
            unlockedWOCTA += getFee();
            IERC20(getWOCTA()).safeTransferFrom(msg.sender, address(this), amountWithFee);
        }
    }
    function receiveTokens(Transaction calldata transaction, bytes memory signature) public override {
        super.receiveTokens(transaction, signature);
        _sendEth(msg.sender, transaction.amount);
    }
    function withdrawEth() external override onlyRole(DEFAULT_ADMIN_ROLE) {
        uint256 amount = unlockedOCTA;
        unlockedOCTA = 0;
        _sendEth(msg.sender, amount);
    }
    function withdrawERC20(IERC20 _token) external override onlyRole(DEFAULT_ADMIN_ROLE) {
        uint256 amount;
        if (_token != getWOCTA()) {
            amount = _token.balanceOf(address(this));
        } else {
            amount = unlockedWOCTA;
            unlockedWOCTA = 0;
        }
        _token.safeTransfer(msg.sender, amount);
        emit Erc20Withdrawn(address(_token), amount);
    }
}

