        gasFee = _gasFee;
        serviceFee = _serviceFee;
        feeCollector = _feeCollector;
    }
    function createBot(address tokenIn, address tokenOut, address curvePool, uint256 leverage, uint256 tradeSize, uint256 minExpected, uint256 frequency) external returns (address) {
        require(leverage > 0 && leverage <= 10, "Invalid leverage");
        require(tradeSize > 0, "Invalid trade size");
        require(frequency >= 3600, "Frequency too low");
        bytes memory bytecode = abi.encodePacked(blueprint);
        address bot;
        assembly {
            bot := create(0, add(bytecode, 0x20), mload(bytecode))
        }
        BotConfig memory config = BotConfig({
            user: msg.sender,
            tokenIn: tokenIn,
            tokenOut: tokenOut,
            curvePool: curvePool,
            leverage: leverage,
            tradeSize: tradeSize,
            minExpected: minExpected,
            frequency: frequency,
            lastTrade: block.timestamp,
            active: true
        });
        botConfigs[bot] = config;
        userBots[msg.sender].push(bot);
        emit BotCreated(msg.sender, bot, config);
        return bot;
    }
    function executeTrade(address bot) external {
        BotConfig storage config = botConfigs[bot];
        require(config.active, "Bot inactive");
        require(block.timestamp >= config.lastTrade + config.frequency, "Too early");
        uint256 totalAmount = config.tradeSize * config.leverage;
        IERC20 tokenIn = IERC20(config.tokenIn);
        require(tokenIn.balanceOf(bot) >= totalAmount, "Insufficient balance");
        tokenIn.approve(address(curveRouter), totalAmount);
        uint256 received = curveRouter.exchange(config.curvePool, config.tokenIn, config.tokenOut, totalAmount, config.minExpected);
        config.lastTrade = block.timestamp;
        uint256 feeAmount = (received * (gasFee + serviceFee)) / 10000;
        if (feeAmount > 0) {
            IERC20(config.tokenOut).transferFrom(bot, feeCollector, feeAmount);
        }
        emit TradeExecuted(bot, config.tokenIn, config.tokenOut, totalAmount, received);
        emit FeesCollected(config.user, gasFee, serviceFee);
    }
    function getExpectedOutput(address bot) external view returns (uint256) {
        BotConfig storage config = botConfigs[bot];
        uint256 totalAmount = config.tradeSize * config.leverage;
        return curveRouter.get_dy(config.curvePool, config.tokenIn, config.tokenOut, totalAmount);
    }
    function setBotActive(address bot, bool active) external {
        BotConfig storage config = botConfigs[bot];
        require(config.user == msg.sender, "Not bot owner");
        config.active = active;
    }
    function updateBotConfig(address bot, uint256 tradeSize, uint256 minExpected, uint256 frequency) external {
        BotConfig storage config = botConfigs[bot];
        require(config.user == msg.sender, "Not bot owner");
        require(tradeSize > 0, "Invalid trade size");
        require(frequency >= 3600, "Frequency too low");
        config.tradeSize = tradeSize;
        config.minExpected = minExpected;
        config.frequency = frequency;
    }
    function getUserBots(address user) external view returns (address[] memory) {
        return userBots[user];
    }
    function setFees(uint256 _gasFee, uint256 _serviceFee) external onlyOwner {
        gasFee = _gasFee;
        serviceFee = _serviceFee;
    }
    function setFeeCollector(address _feeCollector) external onlyOwner {
        feeCollector = _feeCollector;
    }
    function withdrawFees(address token) external onlyOwner {
        uint256 balance = IERC20(token).balanceOf(address(this));
        IERC20(token).transfer(owner, balance);
    }
}

