pragma solidity ^0.8.0;
interface IPriceFeed {
    function getPrice(address asset) external view returns (uint256);
}
interface ISystemStatus {
    function isSystemActive() external view returns (bool);
}
interface ICircuitBreaker {
    function checkCircuitBreaker(address market, uint256 size) external view returns (bool);
}
interface IFeePool {
    function collectFee(address trader, uint256 amount) external;
}
contract FuturesMarket {
    address public owner;
    IPriceFeed public priceFeed;
    ISystemStatus public systemStatus;
    ICircuitBreaker public circuitBreaker;
    IFeePool public feePool;
    address public baseAsset;
    uint256 public maxLeverage = 10;
    uint256 public minMargin = 100e18;
    uint256 public maxMarketSize = 1000000e18;
    uint256 public fundingRate;
    uint256 public lastFundingUpdate;
    uint256 public totalLongSize;
    uint256 public totalShortSize;
    struct Position {
        uint256 size;
        uint256 margin;
        int256 entryPrice;
        bool isLong;
        uint256 lastFundingAccrued;
    }
    mapping(address => Position) public positions;
    mapping(address => uint256) public marginBalances;
    event PositionOpened(address indexed trader, uint256 size, uint256 margin, bool isLong, int256 entryPrice);
    event PositionClosed(address indexed trader, uint256 size, int256 pnl);
    event MarginDeposited(address indexed trader, uint256 amount);
    event MarginWithdrawn(address indexed trader, uint256 amount);
    event FundingRateUpdated(uint256 newRate, uint256 timestamp);
    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }
    modifier systemActive() {
        require(systemStatus.isSystemActive(), "System inactive");
        _;
    }
    constructor(address _priceFeed, address _systemStatus, address _circuitBreaker, address _feePool, address _baseAsset) {
        owner = msg.sender;
        priceFeed = IPriceFeed(_priceFeed);
        systemStatus = ISystemStatus(_systemStatus);
        circuitBreaker = ICircuitBreaker(_circuitBreaker);
        feePool = IFeePool(_feePool);
        baseAsset = _baseAsset;
        lastFundingUpdate = block.timestamp;
    }
    function openPosition(uint256 size, uint256 margin, bool isLong) external systemActive {
        require(size > 0, "Invalid size");
        require(margin >= minMargin, "Insufficient margin");
        uint256 leverage = (size * 1e18) / margin;
        require(leverage <= maxLeverage * 1e18, "Exceeds max leverage");
        require(circuitBreaker.checkCircuitBreaker(address(this), size), "Circuit breaker active");
        if (isLong) {
            totalLongSize += size;
        } else {
            totalShortSize += size;
        }
        require(totalLongSize + totalShortSize <= maxMarketSize, "Exceeds market cap");
        Position storage position = positions[msg.sender];
        require(position.size == 0, "Position exists");
        uint256 currentPrice = getCurrentPrice();
        position.size = size;
        position.margin = margin;
        position.entryPrice = int256(currentPrice);
        position.isLong = isLong;
        position.lastFundingAccrued = fundingRate;
        marginBalances[msg.sender] -= margin;
        emit PositionOpened(msg.sender, size, margin, isLong, int256(currentPrice));
    }
    function closePosition() external systemActive {
        Position storage position = positions[msg.sender];
        require(position.size > 0, "No position");
        uint256 currentPrice = getCurrentPrice();
        int256 pnl = calculatePnL(msg.sender, currentPrice);
        uint256 size = position.size;
        if (position.isLong) {
            totalLongSize -= size;
        } else {
            totalShortSize -= size;
        }
        uint256 finalMargin = uint256(int256(position.margin) + pnl);
        if (finalMargin > 0) {
            marginBalances[msg.sender] += finalMargin;
        }
        delete positions[msg.sender];
        emit PositionClosed(msg.sender, size, pnl);
    }
    function depositMargin(uint256 amount) external {
        require(amount > 0, "Invalid amount");
        marginBalances[msg.sender] += amount;
        emit MarginDeposited(msg.sender, amount);
    }
    function withdrawMargin(uint256 amount) external {
        require(amount <= marginBalances[msg.sender], "Insufficient margin");
        Position storage position = positions[msg.sender];
        if (position.size > 0) {
            uint256 currentPrice = getCurrentPrice();
            int256 pnl = calculatePnL(msg.sender, currentPrice);
            uint256 availableMargin = uint256(int256(position.margin) + pnl);
            require(amount <= availableMargin, "Exceeds available margin");
        }
        marginBalances[msg.sender] -= amount;
        emit MarginWithdrawn(msg.sender, amount);
    }
    function updateFundingRate(uint256 newRate) external onlyOwner {
        fundingRate = newRate;
        lastFundingUpdate = block.timestamp;
        emit FundingRateUpdated(newRate, block.timestamp);
    }
    function calculatePnL(address trader, uint256 currentPrice) public view returns (int256) {
        Position storage position = positions[trader];
        if (position.size == 0) return 0;
        int256 priceDelta = int256(currentPrice) - position.entryPrice;
        int256 pnl;
        if (position.isLong) {
            pnl = (priceDelta * int256(position.size)) / int256(currentPrice);
        } else {
            pnl = (-priceDelta * int256(position.size)) / int256(currentPrice);
        }
        int256 fundingDelta = int256(fundingRate) - int256(position.lastFundingAccrued);
        int256 fundingPnl = (fundingDelta * int256(position.size)) / 1e18;
        return pnl + fundingPnl;
    }
    function getCurrentPrice() public view returns (uint256) {
        return priceFeed.getPrice(baseAsset);
    }
    function getLiquidationPrice(address trader) public view returns (uint256) {
        Position storage position = positions[trader];
        if (position.size == 0) return 0;
        uint256 maintenanceMargin = (position.margin * 8) / 10;
        if (position.isLong) {
            return uint256((position.entryPrice * (int256(position.margin) - int256(maintenanceMargin))) / int256(position.size));
        } else {
            return uint256((position.entryPrice * (int256(position.margin) + int256(maintenanceMargin))) / int256(position.size));
        }
    }
    function setMaxLeverage(uint256 _maxLeverage) external onlyOwner {
        maxLeverage = _maxLeverage;
    }
    function setMinMargin(uint256 _minMargin) external onlyOwner {
        minMargin = _minMargin;
    }
    function setMaxMarketSize(uint256 _maxMarketSize) external onlyOwner {
        maxMarketSize = _maxMarketSize;
    }
}

