}
contract RestrictedToken {
    string public name;
    string public symbol;
    uint8 public decimals;
    uint256 public totalSupply;
    address public owner;
    IUniswapV2Router public v2Router;
    address public v2Pair;
    uint256 public maxTxAmount;
    uint256 public maxWalletAmount;
    uint256 public bnbLimit;
    bool public tradingEnabled;
    mapping(address => uint256) public balanceOf;
    mapping(address => mapping(address => uint256)) public allowance;
    mapping(address => bool) public isExcludedFromRestrictions;
    mapping(address => uint256) public lastBuyTimestamp;
    mapping(address => uint256) public lastSellTimestamp;
    mapping(address => uint256) public totalBuyAmount;
    mapping(address => uint256) public totalSellAmount;
    mapping(address => bool) public isUniswapV3Pool;
    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);
    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }
    constructor(string memory _name, string memory _symbol, uint256 _totalSupply, address _v2Router) {
        name = _name;
        symbol = _symbol;
        decimals = 18;
        totalSupply = _totalSupply * 10**18;
        owner = msg.sender;
        v2Router = IUniswapV2Router(_v2Router);
        v2Pair = IUniswapV2Factory(v2Router.factory()).createPair(address(this), v2Router.WETH());
        maxTxAmount = totalSupply * 2 / 100;
        maxWalletAmount = totalSupply * 3 / 100;
        bnbLimit = 1 ether;
        balanceOf[msg.sender] = totalSupply;
        isExcludedFromRestrictions[msg.sender] = true;
        isExcludedFromRestrictions[address(this)] = true;
        emit Transfer(address(0), msg.sender, totalSupply);
    }
    function transfer(address to, uint256 value) public returns (bool) {
        _transfer(msg.sender, to, value);
        return true;
    }
    function transferFrom(address from, address to, uint256 value) public returns (bool) {
        require(allowance[from][msg.sender] >= value, "Insufficient allowance");
        allowance[from][msg.sender] -= value;
        _transfer(from, to, value);
        return true;
    }
    function approve(address spender, uint256 value) public returns (bool) {
        allowance[msg.sender][spender] = value;
        emit Approval(msg.sender, spender, value);
        return true;
    }
    function _transfer(address from, address to, uint256 value) internal {
        require(from != address(0), "From zero address");
        require(to != address(0), "To zero address");
        require(balanceOf[from] >= value, "Insufficient balance");
        if (!isExcludedFromRestrictions[from] && !isExcludedFromRestrictions[to]) {
            require(!isUniswapV3Pool[to], "V3 pool transfers disabled");
            if (from == v2Pair) {
                require(value <= maxTxAmount, "Exceeds max buy");
                uint256 bnbValue = getBNBValue(value);
                require(bnbValue <= bnbLimit, "Exceeds BNB limit");
                lastBuyTimestamp[to] = block.timestamp;
                totalBuyAmount[to] += value;
            } else if (to == v2Pair) {
                require(value <= maxTxAmount, "Exceeds max sell");
                require(block.timestamp >= lastBuyTimestamp[from] + 1 hours, "Sell cooldown active");
                lastSellTimestamp[from] = block.timestamp;
                totalSellAmount[from] += value;
            } else {
                require(value <= maxTxAmount, "Exceeds max transfer");
            }
            if (to != v2Pair) {
                require(balanceOf[to] + value <= maxWalletAmount, "Exceeds max wallet");
            }
        }
        if (!tradingEnabled) {
            require(isExcludedFromRestrictions[from] || isExcludedFromRestrictions[to], "Trading disabled");
