            if (from == pair) {
                feeAmount = (value * totalBuyFee) / 10000;
            } else if (to == pair) {
                feeAmount = (value * totalSellFee) / 10000;
            } else {
                feeAmount = (value * totalTransferFee) / 10000;
            }
            if (feeAmount > 0) {
