    uint256 public maxSupply = 8888;
    uint256 public mintPrice = 0.005 ether;
    uint256 public maxPerTx = 10;
    bool public mintEnabled;
    address public owner;
    mapping(address => uint256) public balanceOf;
    mapping(uint256 => address) public ownerOf;
    mapping(uint256 => address) public getApproved;
    mapping(address => mapping(address => bool)) public isApprovedForAll;
    event Transfer(address indexed from, address indexed to, uint256 indexed tokenId);
    event Approval(address indexed owner, address indexed approved, uint256 indexed tokenId);
    event ApprovalForAll(address indexed owner, address indexed operator, bool approved);
    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }
    modifier mintActive() {
        require(mintEnabled, "Mint disabled");
        _;
    }
    constructor() {
        owner = msg.sender;
    }
    function mint(uint256 amount) external payable mintActive {
        require(amount > 0 && amount <= maxPerTx, "Invalid amount");
        require(totalSupply + amount <= maxSupply, "Exceeds max supply");
        require(msg.value >= mintPrice * amount, "Insufficient payment");
        _mintBatch(msg.sender, amount);
    }
    function freeMint() external mintActive {
        require(totalSupply < 1000, "Free mint ended");
        require(balanceOf[msg.sender] == 0, "Already free minted");
        _mintBatch(msg.sender, 1);
    }
    function _mintBatch(address to, uint256 amount) internal {
        uint256 startTokenId = totalSupply;
        for (uint256 i = 0; i < amount; i++) {
            uint256 tokenId = startTokenId + i;
            ownerOf[tokenId] = to;
            emit Transfer(address(0), to, tokenId);
        }
        balanceOf[to] += amount;
        totalSupply += amount;
    }
    function transferFrom(address from, address to, uint256 tokenId) public {
        require(ownerOf[tokenId] == from, "Not owner");
        require(msg.sender == from || msg.sender == getApproved[tokenId] || isApprovedForAll[from][msg.sender], "Not approved");
        ownerOf[tokenId] = to;
        delete getApproved[tokenId];
        balanceOf[from]--;
        balanceOf[to]++;
        emit Transfer(from, to, tokenId);
    }
    function safeTransferFrom(address from, address to, uint256 tokenId) external {
        transferFrom(from, to, tokenId);
    }
    function approve(address approved, uint256 tokenId) external {
        require(ownerOf[tokenId] == msg.sender, "Not owner");
        getApproved[tokenId] = approved;
        emit Approval(msg.sender, approved, tokenId);
    }
    function setApprovalForAll(address operator, bool approved) external {
        isApprovedForAll[msg.sender][operator] = approved;
        emit ApprovalForAll(msg.sender, operator, approved);
    }
    function setMintEnabled(bool enabled) external onlyOwner {
        mintEnabled = enabled;
    }
    function setMintPrice(uint256 price) external onlyOwner {
        mintPrice = price;
    }
    function setMaxPerTx(uint256 max) external onlyOwner {
        maxPerTx = max;
    }
    function withdraw() external onlyOwner {
        payable(owner).transfer(address(this).balance);
    }
}

pragma solidity ^0.8.21;
import {SturdyLeverage, IBaseLeverage, IERC20, SafeERC20} from "./SturdyLeverage.sol";
import { IERC4626 } from "../interfaces/IERC4626.sol";
contract ERC4626VaultLeverage is SturdyLeverage {
  using SafeERC20 for IERC20;
  error LV_REQUIRE_MIN_AMOUNT();
  function _processSwap(
    uint256 _amount,
    IBaseLeverage.MultipSwapPath memory _path,
    bool _checkOutAmount
  ) internal override returns (uint256) {
    if (_path.swapType > IBaseLeverage.SwapType.WITHDRAW) {
      return _swapByPath(_amount, _path, _checkOutAmount);
    }
    if (_path.swapType == IBaseLeverage.SwapType.WITHDRAW) {
      if (!_checkOutAmount) revert LV_INVALID_CONFIGURATION();
      uint256 outAmount = IERC4626(_path.swapFrom).redeem(_amount, address(this), address(this));
      if (outAmount < _path.outAmount) revert LV_REQUIRE_MIN_AMOUNT();
      return outAmount;
    }
    address asset = _path.swapFrom;
    address vault = _path.swapTo;
    IERC20(asset).safeApprove(vault, 0);
    IERC20(asset).safeApprove(vault, _amount);
    uint256 outAmount = IERC4626(vault).deposit(_amount, address(this));
    if (_checkOutAmount && outAmount < _path.outAmount) {
      revert LV_REQUIRE_MIN_AMOUNT();
    }
    return outAmount;
  }
}

