            _result[i * 2 + 1] = pair[1];
        }
        return _result;
    }
    function _appendVestingEntry(address account, uint quantity) internal {
        require(quantity != 0, "Quantity cannot be zero");
        totalEscrowedBalance = totalEscrowedBalance.add(quantity);
        require(
            totalEscrowedBalance <= IERC20(address(synthetix)).balanceOf(address(this)),
            "Must be enough balance in the contract to provide for the vesting entry"
        );
        uint scheduleLength = vestingSchedules[account].length;
        require(scheduleLength <= MAX_VESTING_ENTRIES, "Vesting schedule is too long");
        uint time = now + 52 weeks;
        if (scheduleLength == 0) {
            totalEscrowedAccountBalance[account] = quantity;
        } else {
            require(
                getVestingTime(account, scheduleLength - 1) < time,
                "Cannot add new vested entries earlier than the last one"
            );
            totalEscrowedAccountBalance[account] = totalEscrowedAccountBalance[account].add(quantity);
        }
        vestingSchedules[account].push([time, quantity]);
        emit VestingEntryCreated(account, now, quantity);
    }
    function appendVestingEntry(address account, uint quantity) external onlyFeePool {
        _appendVestingEntry(account, quantity);
    }
    function vest() external {
        uint numEntries = _numVestingEntries(msg.sender);
        uint total;
        for (uint i = 0; i < numEntries; i++) {
            uint time = getVestingTime(msg.sender, i);
            if (time > now) {
                break;
            }
            uint qty = getVestingQuantity(msg.sender, i);
            if (qty > 0) {
                vestingSchedules[msg.sender][i] = [0, 0];
                total = total.add(qty);
            }
        }
        if (total != 0) {
            totalEscrowedBalance = totalEscrowedBalance.sub(total);
            totalEscrowedAccountBalance[msg.sender] = totalEscrowedAccountBalance[msg.sender].sub(total);
            totalVestedAccountBalance[msg.sender] = totalVestedAccountBalance[msg.sender].add(total);
            IERC20(address(synthetix)).transfer(msg.sender, total);
            emit Vested(msg.sender, now, total);
        }
    }
    modifier onlyFeePool() {
        bool isFeePool = msg.sender == address(feePool);
        require(isFeePool, "Only the FeePool contracts can perform this action");
        _;
    }
    event SynthetixUpdated(address newSynthetix);
    event FeePoolUpdated(address newFeePool);
    event Vested(address indexed beneficiary, uint time, uint value);
    event VestingEntryCreated(address indexed beneficiary, uint time, uint value);
}

// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;
interface IERC20 {
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
    function transfer(address to, uint256 amount) external returns (bool);
    function balanceOf(address account) external view returns (uint256);
    function approve(address spender, uint256 amount) external returns (bool);
}
interface IAuctionHook {
    function onAuctionStart(uint256 auctionId) external;
    function onBidPlaced(uint256 auctionId, address bidder, uint256 amount) external;
    function onAuctionEnd(uint256 auctionId, address winner, uint256 finalPrice) external;
}
contract DutchAuctionManager {
    address public governor;
    uint256 public auctionCount;
    struct Auction {
        address seller;
        address tokenIn;
        address tokenOut;
        uint256 totalAmount;
        uint256 startPrice;
        uint256 reservePrice;
        uint256 startTime;
        uint256 duration;
        uint256 soldAmount;
        bool active;
        address hook;
    }
    mapping(uint256 => Auction) public auctions;
    mapping(uint256 => mapping(address => uint256)) public bids;
    event AuctionCreated(uint256 indexed auctionId, address seller, address tokenIn, address tokenOut, uint256 totalAmount, uint256 startPrice, uint256 reservePrice);
    event BidPlaced(uint256 indexed auctionId, address bidder, uint256 amount, uint256 price);
    event AuctionEnded(uint256 indexed auctionId, address winner, uint256 finalPrice, uint256 soldAmount);
    modifier onlyGovernor() {
        require(msg.sender == governor, "Not governor");
        _;
    }
    constructor() {
        governor = msg.sender;
    }
    function createAuction(address tokenIn, address tokenOut, uint256 totalAmount, uint256 startPrice, uint256 reservePrice, uint256 duration, address hook) external returns (uint256) {
        require(totalAmount > 0, "Invalid amount");
        require(startPrice > reservePrice, "Invalid prices");
        require(duration > 0, "Invalid duration");
        IERC20(tokenIn).transferFrom(msg.sender, address(this), totalAmount);
        uint256 auctionId = ++auctionCount;
        auctions[auctionId] = Auction({
            seller: msg.sender,
            tokenIn: tokenIn,
            tokenOut: tokenOut,
            totalAmount: totalAmount,
            startPrice: startPrice,
            reservePrice: reservePrice,
            startTime: block.timestamp,
            duration: duration,
            soldAmount: 0,
            active: true,
            hook: hook
        });
        if (hook != address(0)) {
            IAuctionHook(hook).onAuctionStart(auctionId);
        }
        emit AuctionCreated(auctionId, msg.sender, tokenIn, tokenOut, totalAmount, startPrice, reservePrice);
        return auctionId;
    }
    function placeBid(uint256 auctionId, uint256 amount) external {
        Auction storage auction = auctions[auctionId];
        require(auction.active, "Auction inactive");
        require(block.timestamp < auction.startTime + auction.duration, "Auction ended");
        require(auction.soldAmount + amount <= auction.totalAmount, "Exceeds supply");
        uint256 currentPrice = getCurrentPrice(auctionId);
        uint256 totalCost = (amount * currentPrice) / 1e18;
        IERC20(auction.tokenOut).transferFrom(msg.sender, address(this), totalCost);
        bids[auctionId][msg.sender] += amount;
        auction.soldAmount += amount;
        if (auction.hook != address(0)) {
            IAuctionHook(auction.hook).onBidPlaced(auctionId, msg.sender, amount);
        }
        emit BidPlaced(auctionId, msg.sender, amount, currentPrice);
    }
    function endAuction(uint256 auctionId) external {
        Auction storage auction = auctions[auctionId];
        require(auction.active, "Auction inactive");
        require(block.timestamp >= auction.startTime + auction.duration || auction.soldAmount == auction.totalAmount, "Auction ongoing");
        auction.active = false;
        uint256 finalPrice = getCurrentPrice(auctionId);
        if (auction.soldAmount > 0) {
            IERC20(auction.tokenIn).transfer(auction.seller, auction.soldAmount);
            uint256 totalRevenue = (auction.soldAmount * finalPrice) / 1e18;
            IERC20(auction.tokenOut).transfer(auction.seller, totalRevenue);
        }
        if (auction.totalAmount > auction.soldAmount) {
            uint256 remaining = auction.totalAmount - auction.soldAmount;
            IERC20(auction.tokenIn).transfer(auction.seller, remaining);
        }
        if (auction.hook != address(0)) {
            IAuctionHook(auction.hook).onAuctionEnd(auctionId, auction.seller, finalPrice);
        }
        emit AuctionEnded(auctionId, auction.seller, finalPrice, auction.soldAmount);
    }
    function getCurrentPrice(uint256 auctionId) public view returns (uint256) {
        Auction storage auction = auctions[auctionId];
        if (block.timestamp >= auction.startTime + auction.duration) {
            return auction.reservePrice;
        }
        uint256 timeElapsed = block.timestamp - auction.startTime;
        uint256 priceDecrease = ((auction.startPrice - auction.reservePrice) * timeElapsed) / auction.duration;
        return auction.startPrice - priceDecrease;
    }
    function setGovernor(address newGovernor) external onlyGovernor {
        governor = newGovernor;
    }
    function emergencyWithdraw(address token, uint256 amount) external onlyGovernor {
        IERC20(token).transfer(governor, amount);
    }
}

