pragma solidity ^0.8.0;
interface IUniswapV2Router {
    function swapExactTokensForTokens(uint amountIn, uint amountOutMin, address[] calldata path, address to, uint deadline) external returns (uint[] memory amounts);
    function swapExactETHForTokens(uint amountOutMin, address[] calldata path, address to, uint deadline) external payable returns (uint[] memory amounts);
    function swapExactTokensForETH(uint amountIn, uint amountOutMin, address[] calldata path, address to, uint deadline) external returns (uint[] memory amounts);
    function getAmountsOut(uint amountIn, address[] calldata path) external view returns (uint[] memory amounts);
}
interface IUniswapV2Factory {
    function getPair(address tokenA, address tokenB) external view returns (address pair);
}
interface IERC20 {
    function balanceOf(address account) external view returns (uint256);
    function transfer(address to, uint256 amount) external returns (bool);
    function approve(address spender, uint256 amount) external returns (bool);
}
contract MEVArbitrageBot {
    address public owner;
    IUniswapV2Router public router;
    IUniswapV2Factory public factory;
    uint256 public minProfitThreshold = 0.1 ether;
    mapping(address => bool) public scannedContracts;
    event ArbitrageExecuted(address indexed token, uint256 profit, uint256 timestamp);
    event ContractScanned(address indexed contractAddress, bool hasLiquidity);
    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }
    constructor(address _router) {
        owner = msg.sender;
        router = IUniswapV2Router(_router);
        factory = IUniswapV2Factory(router.factory());
    }
    function scanNewContract(address newContract) external onlyOwner {
        require(!scannedContracts[newContract], "Already scanned");
        bool hasLiquidity = _analyzeContractLiquidity(newContract);
        scannedContracts[newContract] = true;
        emit ContractScanned(newContract, hasLiquidity);
    }
    function executeArbitrage(address tokenA, address tokenB, uint256 amountIn) external onlyOwner {
        address pair = factory.getPair(tokenA, tokenB);
        require(pair != address(0), "No pair exists");
        uint256 expectedProfit = _calculateArbitrageProfit(tokenA, tokenB, amountIn);
        require(expectedProfit >= minProfitThreshold, "Insufficient profit");
        _performArbitrage(tokenA, tokenB, amountIn);
        emit ArbitrageExecuted(tokenA, expectedProfit, block.timestamp);
    }
    function _analyzeContractLiquidity(address contractAddress) internal view returns (bool) {
        try IERC20(contractAddress).balanceOf(contractAddress) returns (uint256 balance) {
            return balance > 0;
        } catch {
            return false;
        }
    }
    function _calculateArbitrageProfit(address tokenA, address tokenB, uint256 amountIn) internal view returns (uint256) {
        address[] memory path1 = new address[](2);
        path1[0] = tokenA;
        path1[1] = tokenB;
        uint256[] memory amounts1 = router.getAmountsOut(amountIn, path1);
        address[] memory path2 = new address[](2);
        path2[0] = tokenB;
        path2[1] = tokenA;
        uint256[] memory amounts2 = router.getAmountsOut(amounts1[1], path2);
        if (amounts2[1] > amountIn) {
            return amounts2[1] - amountIn;
        }
        return 0;
    }
    function _performArbitrage(address tokenA, address tokenB, uint256 amountIn) internal {
        address[] memory path1 = new address[](2);
        path1[0] = tokenA;
        path1[1] = tokenB;
        IERC20(tokenA).approve(address(router), amountIn);
        uint256[] memory amounts1 = router.swapExactTokensForTokens(amountIn, 0, path1, address(this), block.timestamp);
        address[] memory path2 = new address[](2);
        path2[0] = tokenB;
        path2[1] = tokenA;
        IERC20(tokenB).approve(address(router), amounts1[1]);
        router.swapExactTokensForTokens(amounts1[1], 0, path2, address(this), block.timestamp);
    }
    function setMinProfitThreshold(uint256 threshold) external onlyOwner {
        minProfitThreshold = threshold;
    }
    function withdrawTokens(address token, uint256 amount) external onlyOwner {
        IERC20(token).transfer(owner, amount);
    }
    function withdrawETH(uint256 amount) external onlyOwner {
        payable(owner).transfer(amount);
    }
    receive() external payable {}
}

pragma solidity ^0.8.0;
import "./ITokenMessenger.sol"; 
import "../openzeppelin/contracts/access/Ownable.sol";
import "../util/IERC20_.sol";
contract CCTP_Wrapper is Ownable {
    ITokenMessenger public tokenMessenger;
    address public  CCTP_Token_Messenger;
    uint fee; 
    uint constant BASIS_POINTS = 10000;
    event CCTPTrade(address sender, uint256 amount, address burnToken, uint32 destationDomain);
    constructor(address _token_messenger, address _usdc) {
        CCTP_Token_Messenger=_token_messenger;
        tokenMessenger = ITokenMessenger(CCTP_Token_Messenger);
        approveCCTP(_usdc, _token_messenger, 100e18);
    }
    function CCTP_Trade(
        uint256 amount,
        uint32 destinationDomain,
        bytes32 mintRecipient,
        address sell_token
    ) external payable returns (uint64 nonce){
        transferFrom(sell_token, msg.sender, amount);
        nonce=tokenMessenger.depositForBurn(apply_fee(amount), destinationDomain, mintRecipient, sell_token);
        transfer(sell_token, owner(), owner_fee(amount));
        emit CCTPTrade(msg.sender, amount, sell_token, destinationDomain);
        payable(owner()).transfer(msg.value);
    }
    function CCTP_Pay_Stable(
        uint256 amount,
        uint32 destinationDomain,
        bytes32 mintRecipient,
        address sell_token, 
        uint256 usdc_gas_fee
    ) external returns (uint64 nonce){
        require(amount>usdc_gas_fee,"!fees exceedes trade amount");
        transferFrom(sell_token, msg.sender, amount+usdc_gas_fee);
        transfer(sell_token, owner(), usdc_gas_fee);
        nonce=tokenMessenger.depositForBurn(apply_fee(amount), destinationDomain, mintRecipient, sell_token);
        transfer(sell_token, owner(), owner_fee(amount));
        emit CCTPTrade(msg.sender, amount, sell_token, destinationDomain);
    }
    function set_fee(uint _fee) public onlyOwner {
      fee=_fee;
    }
    function apply_fee(uint number) public view returns (uint) {    
        return number-((fee*number)/BASIS_POINTS);
    }
    function owner_fee(uint number) public view returns (uint) {    
        return (fee*number)/BASIS_POINTS;
    }
    function approveCCTP(address tkn, address to, uint amt)  internal returns (bool s) {
        (s, ) = tkn.call(abi.encodeWithSelector(IERC20_.approve.selector, to, amt));
    }
    function transfer (address tkn, address to, uint amt) internal returns (bool s) {
        if (amt > 0) {
            (s,) = tkn.call(abi.encodeWithSelector(IERC20_.transferFrom.selector, msg.sender, to, amt)); 
        }
    }
    function transferFrom (address tkn, address from, uint amt) internal returns (bool s) { 
        (s,) = tkn.call(abi.encodeWithSelector(IERC20_.transferFrom.selector, from, address(this), amt)); 
    }
}

pragma solidity ^0.8.21;
import {IERC20} from "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import {SafeERC20} from "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import {ReentrancyGuard} from "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import {Math} from "@openzeppelin/contracts/utils/math/Math.sol";
import {IBaseLeverageWihtoutFlashloan} from "../../interfaces/Mode/IBaseLeverageWihtoutFlashloan.sol";
import {ISturdyPair} from "../../interfaces/ISturdyPair.sol";
import {SupswapAdapter} from "../../swappers/Mode/SupswapAdapter.sol";
abstract contract BaseLeverageWihtoutFlashloan is ReentrancyGuard {
  using SafeERC20 for IERC20;
  uint256 private constant HEALTH_FACTOR = 1e18;
  error LV_INVALID_CONFIGURATION();
  error LV_AMOUNT_NOT_GT_0();
  error LV_SUPPLY_NOT_ALLOWED();
  error LV_SUPPLY_FAILED();
  error LV_REMOVE_ITERATION_OVER();
  function enterPosition(
    uint256 _principal,
    uint256 _iterations,
    address _silo,
    IBaseLeverageWihtoutFlashloan.BiDirectSwapInfo calldata _borrowAssetAndCollateral
  ) external {
    address collateralAsset = ISturdyPair(_silo).collateralContract();
    if (collateralAsset == address(0)) revert LV_INVALID_CONFIGURATION();
    if (_principal == 0) revert LV_AMOUNT_NOT_GT_0();
    if (IERC20(collateralAsset).balanceOf(msg.sender) < _principal) revert LV_SUPPLY_NOT_ALLOWED();
    IERC20(collateralAsset).safeTransferFrom(msg.sender, address(this), _principal);
    _leverage(
      IBaseLeverageWihtoutFlashloan.LeverageParams(
        _principal,
        _iterations,
        ISturdyPair(_silo).asset(),
        collateralAsset,
        _silo,
        _borrowAssetAndCollateral
      )
    );
  }
  function leavePosition(
    uint256 _principal,
    uint256 _iterations,
    uint256 _healthFactor,
    address _silo,
    IBaseLeverageWihtoutFlashloan.BiDirectSwapInfo calldata _borrowAssetAndCollateral
  ) external {
    ISturdyPair pair = ISturdyPair(_silo);
    address collateralAsset = pair.collateralContract();
    address borrowAsset = pair.asset();
    if (collateralAsset == address(0)) revert LV_INVALID_CONFIGURATION();
    if (borrowAsset == address(0)) revert LV_INVALID_CONFIGURATION();
    if (_principal == 0) revert LV_AMOUNT_NOT_GT_0();
    if (_healthFactor < 1e18) revert LV_INVALID_CONFIGURATION();
    if (_iterations != 0) {
      _reduceLeverageWithAmount(
        _silo, 
        0, 
        _borrowAssetAndCollateral
      );
    } else {
      _reduceLeverageWithAmount(
        _silo,
        _principal,
        _borrowAssetAndCollateral
      );
      return;
    }
    uint256 count;
    do {
      if (count >= _iterations) revert LV_REMOVE_ITERATION_OVER();
      uint256 availableAmount = _calcWithdrawalAmount(
        _silo,
        _healthFactor
      );
      if (availableAmount == 0) break;
      uint256 requiredAmount = _principal - IERC20(collateralAsset).balanceOf(address(this));
      uint256 removeAmount = Math.min(availableAmount, requiredAmount);
      _remove(removeAmount, _silo, 0, msg.sender);
      if (removeAmount == requiredAmount) break;
      uint256 debtAmount =  pair.toBorrowAmount(pair.userBorrowShares(msg.sender), true, true);
      if (debtAmount != 0) {
        uint256 borrowingAssetAmount = _swapAsset(
          collateralAsset, 
          borrowAsset, 
          IERC20(collateralAsset).balanceOf(address(this)), 
          _borrowAssetAndCollateral.reversePaths,
          _borrowAssetAndCollateral.pathLength,
          false
        );
        uint256 repayAmount = Math.min(debtAmount, borrowingAssetAmount);
        _repay(_silo, repayAmount, msg.sender);
        if (borrowingAssetAmount > repayAmount) {
          _swapAsset(
            borrowAsset, 
            collateralAsset, 
            IERC20(borrowAsset).balanceOf(address(this)),
            _borrowAssetAndCollateral.paths,
            _borrowAssetAndCollateral.pathLength,
            false
          );
        }
      }
      count++;
    } while (true);
    IERC20(collateralAsset).safeTransfer(msg.sender, IERC20(collateralAsset).balanceOf(address(this)));
  }
  function zapDeposit(
    uint256 _principal,
    uint256 _borrowAmount,
    address _zappingAsset,
    address _silo,
    IBaseLeverageWihtoutFlashloan.UniDirectSwapInfo calldata _zapAssetToCollateral
  ) external nonReentrant {
    address collateralAsset = ISturdyPair(_silo).collateralContract();
    if (_principal == 0) revert LV_AMOUNT_NOT_GT_0();
    if (_zappingAsset == address(0)) revert LV_INVALID_CONFIGURATION();
    if (collateralAsset == address(0)) revert LV_INVALID_CONFIGURATION();
    if (IERC20(_zappingAsset).balanceOf(msg.sender) < _principal) revert LV_SUPPLY_FAILED();
    IERC20(_zappingAsset).safeTransferFrom(msg.sender, address(this), _principal);
    uint256 collateralAmount = _swapAsset(
      _zappingAsset, 
      collateralAsset, 
      _principal,
      _zapAssetToCollateral.paths,
      _zapAssetToCollateral.pathLength,
      true
    );
    _supply(collateralAsset, _silo, collateralAmount, msg.sender);
    if (_borrowAmount != 0) {
      _borrow(_silo, _borrowAmount, msg.sender, msg.sender);
    }
  }
  function zapLeverage(
    uint256 _principal,
    uint256 _iterations,
    address _zappingAsset,
    address _silo,
    IBaseLeverageWihtoutFlashloan.UniDirectSwapInfo calldata _zapAssetToCollateral,
    IBaseLeverageWihtoutFlashloan.BiDirectSwapInfo calldata _borrowAssetAndCollateral
  ) external nonReentrant {
    address collateralAsset = ISturdyPair(_silo).collateralContract();
    if (_principal == 0) revert LV_AMOUNT_NOT_GT_0();
    if (_zappingAsset == address(0)) revert LV_INVALID_CONFIGURATION();
    if (collateralAsset == address(0)) revert LV_INVALID_CONFIGURATION();
    if (IERC20(_zappingAsset).balanceOf(msg.sender) < _principal) revert LV_SUPPLY_FAILED();
    IERC20(_zappingAsset).safeTransferFrom(msg.sender, address(this), _principal);
    uint256 collateralAmount = _swapAsset(
      _zappingAsset, 
      collateralAsset, 
      _principal,
      _zapAssetToCollateral.paths,
      _zapAssetToCollateral.pathLength,
      true
    );
    _leverage(
      IBaseLeverageWihtoutFlashloan.LeverageParams(
        collateralAmount,
        _iterations,
        ISturdyPair(_silo).asset(),
        collateralAsset,
        _silo,
        _borrowAssetAndCollateral
      )
    );
  }
  function _leverage(IBaseLeverageWihtoutFlashloan.LeverageParams memory _params) internal {
    uint256 suppliedAmount = _params.principal;
    uint256 borrowAmount;
    _supply(_params.collateralAsset, _params.silo, suppliedAmount, msg.sender);
    for (uint256 i; i < _params.iterations; ++i) {
      borrowAmount = _calcBorrowableAmount(
        _params.silo,
        suppliedAmount
      );
      bool checkOutAmount = i == 0 ? true : false;
      if (borrowAmount != 0) {
        _borrow(_params.silo, borrowAmount, msg.sender, address(this));
        suppliedAmount = _swapAsset(
          _params.borrowAsset, 
          _params.collateralAsset, 
          borrowAmount, 
          _params.borrowAssetAndCollateral.paths,
          _params.borrowAssetAndCollateral.pathLength,
          checkOutAmount
        );
        _supply(_params.collateralAsset, _params.silo, suppliedAmount, msg.sender);
      }
    }
  }
  function _reduceLeverageWithAmount(
    address _silo,
    uint256 _amount,
    IBaseLeverageWihtoutFlashloan.BiDirectSwapInfo calldata _borrowAssetAndCollateral
  ) internal {
    ISturdyPair pair = ISturdyPair(_silo);
    uint256 requireAmount = _amount;
    bool checkOutAmount = true;
    do {
      uint256 debtAmount =  pair.toBorrowAmount(pair.userBorrowShares(msg.sender), true, true);
      if (debtAmount == 0) break;
      uint256 availableAmount = _calcWithdrawalAmount(
        _silo,
        HEALTH_FACTOR
      );
      uint256 removeAmount = _amount != 0
        ? Math.min(availableAmount, requireAmount)
        : availableAmount;
      _remove(removeAmount, _silo, 0, msg.sender);
      uint256 borrowingAssetAmount = _swapAsset(
        pair.collateralContract(), 
        pair.asset(), 
        IERC20(pair.collateralContract()).balanceOf(address(this)),
        _borrowAssetAndCollateral.reversePaths,
        _borrowAssetAndCollateral.pathLength,
        checkOutAmount
      );
      if (checkOutAmount) checkOutAmount = false;
      uint256 repayAmount = Math.min(debtAmount, borrowingAssetAmount);
      _repay(_silo, repayAmount, msg.sender);
      if (borrowingAssetAmount > repayAmount) {
        uint256 collateralAmount = _swapAsset(
          pair.asset(),
          pair.collateralContract(),
          IERC20(pair.asset()).balanceOf(address(this)),
          _borrowAssetAndCollateral.paths,
          _borrowAssetAndCollateral.pathLength,
          false
        );
        _supply(pair.collateralContract(), _silo, collateralAmount, msg.sender);
        removeAmount -= collateralAmount;
      }
      if (_amount == 0) break;
      requireAmount -= removeAmount;
      if (requireAmount == 0) break;
    } while (true);
  }
  function _swapAsset(
    address _fromAsset,
    address _toAsset,
    uint256 _amount,
    IBaseLeverageWihtoutFlashloan.MultipSwapPath[3] memory _paths,
    uint256 _pathLength,
    bool _checkOutAmount
  ) internal returns (uint256) {
    if (_pathLength == 0) revert LV_INVALID_CONFIGURATION();
    if (_paths[0].swapFrom != _fromAsset) revert LV_INVALID_CONFIGURATION();
    if (_paths[_pathLength - 1].swapTo != _toAsset) revert LV_INVALID_CONFIGURATION();
    uint256 amount = _amount;
    if (amount == 0) return 0;
    for (uint256 i; i < _pathLength; ++i) {
      if (_paths[i].swapType == IBaseLeverageWihtoutFlashloan.SwapType.NONE) continue;
      amount = _processSwap(amount, _paths[i], _checkOutAmount);
    }
    return amount;
  }
  function _swapByPath(
    uint256 _fromAmount,
    IBaseLeverageWihtoutFlashloan.MultipSwapPath memory _path,
    bool _checkOutAmount
  ) internal returns (uint256) {
    uint256 poolCount = _path.poolCount;
    uint256 outAmount = _checkOutAmount ? _path.outAmount : 0;
    if (poolCount == 0) revert LV_INVALID_CONFIGURATION();
    SupswapAdapter.Path memory path;
    path.tokens = new address[](poolCount + 1);
    path.fees = new uint256[](poolCount);
    for (uint256 i; i < poolCount; ++i) {
