pragma solidity ^0.8.0;
interface IERC20 {
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
    function transfer(address to, uint256 amount) external returns (bool);
    function balanceOf(address account) external view returns (uint256);
}
contract StakingContract {
    IERC20 public stakingToken;
    IERC20 public rewardToken;
    address public owner;
    uint256 public totalStaked;
    uint256 public rewardRate;
    uint256 public lockPeriod;
    uint256 public earlyUnstakePenalty;
    bool public paused;
    struct Stake {
        uint256 amount;
        uint256 stakedAt;
        uint256 lastRewardCalculation;
        uint256 pendingRewards;
    }
    mapping(address => Stake) public stakes;
    mapping(address => bool) public isBlacklisted;
    event Staked(address indexed user, uint256 amount);
    event Unstaked(address indexed user, uint256 amount, uint256 penalty);
    event RewardsClaimed(address indexed user, uint256 amount);
    event EmergencyWithdrawn(address indexed user, uint256 amount);
    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }
    modifier whenNotPaused() {
        require(!paused, "Contract paused");
        _;
    }
    modifier notContract() {
        require(msg.sender == tx.origin, "Contracts not allowed");
        _;
    }
    modifier notBlacklisted() {
        require(!isBlacklisted[msg.sender], "Address blacklisted");
        _;
    }
    constructor(address _stakingToken, address _rewardToken, uint256 _rewardRate, uint256 _lockPeriod, uint256 _earlyUnstakePenalty) {
        owner = msg.sender;
        stakingToken = IERC20(_stakingToken);
        rewardToken = IERC20(_rewardToken);
        rewardRate = _rewardRate;
        lockPeriod = _lockPeriod;
        earlyUnstakePenalty = _earlyUnstakePenalty;
    }
    function stake(uint256 amount) external whenNotPaused notContract notBlacklisted {
        require(amount > 0, "Invalid amount");
        require(stakingToken.transferFrom(msg.sender, address(this), amount), "Transfer failed");
        Stake storage userStake = stakes[msg.sender];
        if (userStake.amount > 0) {
            _calculateRewards(msg.sender);
        }
        userStake.amount += amount;
        userStake.stakedAt = block.timestamp;
        userStake.lastRewardCalculation = block.timestamp;
        totalStaked += amount;
        emit Staked(msg.sender, amount);
    }
    function unstake(uint256 amount) external whenNotPaused notContract notBlacklisted {
        Stake storage userStake = stakes[msg.sender];
        require(userStake.amount >= amount, "Insufficient stake");
        _calculateRewards(msg.sender);
        uint256 penalty = 0;
        if (block.timestamp < userStake.stakedAt + lockPeriod) {
            penalty = (amount * earlyUnstakePenalty) / 100;
        }
        uint256 transferAmount = amount - penalty;
        userStake.amount -= amount;
        totalStaked -= amount;
        require(stakingToken.transfer(msg.sender, transferAmount), "Transfer failed");
        if (penalty > 0) {
            require(stakingToken.transfer(owner, penalty), "Penalty transfer failed");
        }
        emit Unstaked(msg.sender, amount, penalty);
    }
    function claimRewards() external whenNotPaused notContract notBlacklisted {
        _calculateRewards(msg.sender);
        Stake storage userStake = stakes[msg.sender];
        uint256 rewardAmount = userStake.pendingRewards;
        require(rewardAmount > 0, "No rewards");
        userStake.pendingRewards = 0;
        require(rewardToken.transfer(msg.sender, rewardAmount), "Reward transfer failed");
        emit RewardsClaimed(msg.sender, rewardAmount);
    }
    function emergencyUnstake() external notContract {
        Stake storage userStake = stakes[msg.sender];
        require(userStake.amount > 0, "No stake");
        uint256 penalty = (userStake.amount * 50) / 100;
        uint256 transferAmount = userStake.amount - penalty;
        totalStaked -= userStake.amount;
        userStake.amount = 0;
        userStake.pendingRewards = 0;
        require(stakingToken.transfer(msg.sender, transferAmount), "Transfer failed");
        require(stakingToken.transfer(owner, penalty), "Penalty transfer failed");
        emit EmergencyWithdrawn(msg.sender, transferAmount);
    }
    function _calculateRewards(address user) internal {
        Stake storage userStake = stakes[user];
        if (userStake.amount == 0) return;
        uint256 timeElapsed = block.timestamp - userStake.lastRewardCalculation;
        uint256 rewards = (userStake.amount * rewardRate * timeElapsed) / (365 days * 100);
        userStake.pendingRewards += rewards;
        userStake.lastRewardCalculation = block.timestamp;
    }
    function setRewardRate(uint256 newRate) external onlyOwner {
        rewardRate = newRate;
    }
    function setLockPeriod(uint256 newPeriod) external onlyOwner {
        lockPeriod = newPeriod;
    }
    function setEarlyUnstakePenalty(uint256 newPenalty) external onlyOwner {
        require(newPenalty <= 50, "Penalty too high");
        earlyUnstakePenalty = newPenalty;
    }
    function setPaused(bool _paused) external onlyOwner {
        paused = _paused;
    }
    function blacklistAddress(address account, bool blacklisted) external onlyOwner {
        isBlacklisted[account] = blacklisted;
    }
    function withdrawRewardTokens(uint256 amount) external onlyOwner {
        require(rewardToken.transfer(owner, amount), "Transfer failed");
    }
    function getPendingRewards(address user) external view returns (uint256) {
        Stake storage userStake = stakes[user];
        if (userStake.amount == 0) return userStake.pendingRewards;
        uint256 timeElapsed = block.timestamp - userStake.lastRewardCalculation;
        uint256 rewards = (userStake.amount * rewardRate * timeElapsed) / (365 days * 100);
        return userStake.pendingRewards + rewards;
    }
}

