            let endAmt := calldataload(add(cdOffset, 0x80))
            let recipient := calldataload(add(cdOffset, 0xA0))

            mstore(item, and(item, 0xFF))
            mstore(add(item, 0x20), token)
            mstore(add(item, 0x40), idOrCrit)
            mstore(add(item, 0x60), startAmt)
            mstore(add(item, 0x80), endAmt)
