            let totalSize := mul(length, 160) // 5 fields * 32 bytes
            if lt(sub(calldatasize(), dataOffset), totalSize) {
                mstore(0x00, 0x08c379a0)
                mstore(0x04, 0x20)
                mstore(0x24, 0x16)
                mstore(0x44, "BufferTooShort")
                revert(0x00, 0x64)
            }

            // Allocate memory for array
            items := mload(0x40)
            mstore(0x40, add(items, add(0x20, mul(length, 0xA0)))) // 0xA0 = 5*32
            mstore(items, length) // Store length

            let dst := add(items, 0x20) // First element
            let src := dataOffset

            for { let i := 0 } lt(i, length) { i := add(i, 1) } {
                // Copy 5 uint256s (160 bytes)
                mstore(dst, calldataload(src))
                mstore(add(dst, 0x20), calldataload(add(src, 0x20)))
                mstore(add(dst, 0x40), calldataload(add(src, 0x40)))
                mstore(add(dst, 0x60), calldataload(add(src, 0x60)))
