            mstore(0x40, add(items, add(0x20, mul(length, 0xC0)))) // 0xC0 = 6*32
            mstore(items, length)

            let dst := add(items, 0x20)
            let src := dataOffset

            for { let i := 0 } lt(i, length) { i := add(i, 1) } {
                // Copy 6 uint256s (192 bytes)
                mstore(dst, calldataload(src))
                mstore(add(dst, 0x20), calldataload(add(src, 0x20)))
                mstore(add(dst, 0x40), calldataload(add(src, 0x40)))
                mstore(add(dst, 0x60), calldataload(add(src, 0x60)))
                mstore(add(dst, 0x80), calldataload(add(src, 0x80)))
                mstore(add(dst, 0xA0), calldataload(add(src, 0xA0)))

