    function parseOfferItemFromBytes(bytes memory data) external pure returns (OfferItem memory item) {
        if (data.length < 160) revert BufferTooShort();

        assembly {
            let ptr := add(data, 0x20) // Skip length

            item := mload(0x40)
            mstore(0x40, add(item, 0xA0)) // Allocate 160 bytes

            // Copy 5 uint256s
            mstore(item, mload(ptr))
            mstore(add(item, 0x20), mload(add(ptr, 0x20)))
            mstore(add(item, 0x40), mload(add(ptr, 0x40)))
            mstore(add(item, 0x60), mload(add(ptr, 0x60)))
            mstore(add(item, 0x80), mload(add(ptr, 0x80)))
        }

        emit OfferItemDecoded(
            item.itemType,
            item.token,
            item.identifierOrCriteria,
            item.startAmount,
            item.endAmount
        );
