    /**
     * @dev Parses a raw bytes array as a ConsiderationItem
     * @param data The raw bytes representing a ConsiderationItem
     * @return item The decoded ConsiderationItem
     */
    function parseConsiderationItemFromBytes(bytes memory data) external pure returns (ConsiderationItem memory item) {
        if (data.length < 192) revert BufferTooShort();

        assembly {
            let ptr := add(data, 0x20)

            item := mload(0x40)
            mstore(0x40, add(item, 0xC0)) // Allocate 192 bytes

            mstore(item, mload(ptr))
            mstore(add(item, 0x20), mload(add(ptr, 0x20)))
            mstore(add(item, 0x40), mload(add(ptr, 0x40)))
            mstore(add(item, 0x60), mload(add(ptr, 0x60)))
            mstore(add(item, 0x80), mload(add(ptr, 0x80)))
            mstore(add(item, 0xA0), mload(add(ptr, 0xA0)))
        }

        emit ConsiderationItemDecoded(
            item.itemType,
            item.token,
            item.identifierOrCriteria,
            item.startAmount,
            item.endAmount,
            item.recipient
        );
    }

