    /**
     * @dev Calculates the calldata offset for a dynamic array based on its index in a function call
     * @param argIndex The index of the dynamic array argument (0-based)
     * @return offset The calldata offset where the array data begins
     */
    function getDynamicArrayOffset(uint256 argIndex) external pure returns (uint256 offset) {
        // Function selector (4) + fixed params (32 * argIndex)
        return 4 + mul(argIndex, 0x20);
    }
}

