/**
 * @title RevenueDistributionContract
 * @dev Manages distribution of ETH revenue to token holders with advanced features
 *      including cooldowns, penalties, and eligibility checks.
 */
contract RevenueDistributionContract is Ownable, Pausable, ReentrancyGuard {
    using SafeMath for uint256;

    // --- Events ---
    event RewardAdded(uint256 reward);
    event RewardClaimed(address indexed user, uint256 amount);
    event CooldownStarted(address indexed user, uint256 timestamp);
    event CooldownReset(address indexed user);
    event PenaltyApplied(address indexed user, uint256 penaltyAmount);
    event ThresholdUpdated(uint256 minTokens, uint256 maxClaim);
    event CooldownPeriodUpdated(uint256 period);
    event RewardExcluded(address indexed account);
    event RewardIncluded(address indexed account);
    event Paused(address account);
    event Unpaused(address account);

    // --- Errors ---
    error InsufficientBalance();
    error NotEligible();
    error CooldownActive();
    error TransferFailed();

    // --- State Variables ---
    IERC20 public immutable rewardToken; // The token users must hold
    uint256 public totalRewardsDistributed;
    uint256 public totalRewardsAvailable;

    // Reward claim threshold
    uint256 public minTokensRequired; // Minimum token balance to claim
    uint256 public maxRewardPerClaim; // Max ETH that can be claimed per transaction

    // Cooldown mechanism
    uint256 public cooldownPeriod; // Seconds
    mapping(address => uint256) public lastClaimTime;

    // Penalty system
    uint256 public penaltyRate; // e.g., 500 = 5%, 10000 = 100%
    address public penaltyWallet;

    // Exclusions
    mapping(address => bool) public isRewardExcluded;
    address[] public excludedAccounts;

    // --- Constructor ---
    constructor(
        address _rewardToken,
        uint256 _minTokensRequired,
        uint256 _maxRewardPerClaim,
        uint256 _cooldownPeriod,
        uint256 _penaltyRate,
        address _penaltyWallet
    ) {
        if (_rewardToken == address(0)) revert();
        if (_penaltyWallet == address(0)) revert();

        rewardToken = IERC20(_rewardToken);
        minTokensRequired = _minTokensRequired;
        maxRewardPerClaim = _maxRewardPerClaim;
        cooldownPeriod = _cooldownPeriod;
        penaltyRate = _penaltyRate;
        penaltyWallet = _penaltyWallet;
    }

    // --- Modifiers ---
    modifier whenNotExcluded(address account) {
        require(!isRewardExcluded[account], "Account excluded");
        _;
    }

    modifier whenEligible(address account) {
        if (isRewardExcluded[account]) revert NotEligible();
        if (rewardToken.balanceOf(account) < minTokensRequired) revert NotEligible();
        _;
    }

    // --- Owner Functions ---
    function setThresholds(uint256 minTokens, uint256 maxClaim) external onlyOwner {
        minTokensRequired = minTokens;
        maxRewardPerClaim = maxClaim;
        emit ThresholdUpdated(minTokens, maxClaim);
    }

    function setCooldownPeriod(uint256 period) external onlyOwner {
        cooldownPeriod = period;
        emit CooldownPeriodUpdated(period);
    }

    function setPenaltyRate(uint256 rate) external onlyOwner {
        require(rate <= 10000, "Penalty too high"); // Max 100%
        penaltyRate = rate;
    }

    function setPenaltyWallet(address wallet) external onlyOwner {
        require(wallet != address(0), "Invalid wallet");
        penaltyWallet = wallet;
    }

    function excludeFromRewards(address account) external onlyOwner {
        require(!isRewardExcluded[account], "Already excluded");
        if (!isRewardExcluded[account]) {
            isRewardExcluded[account] = true;
            excludedAccounts.push(account);
        }
        emit RewardExcluded(account);
    }

    function includeInRewards(address account) external onlyOwner {
        require(isRewardExcluded[account], "Not excluded");
        isRewardExcluded[account] = false;
        emit RewardIncluded(account);
    }

    function pause() external onlyOwner {
        _pause();
        emit Paused(msg.sender);
    }

    function unpause() external onlyOwner {
        _unpause();
        emit Unpaused(msg.sender);
    }

    // --- External Functions ---
    /**
     * @notice Deposit ETH to be distributed as rewards
     */
    function depositRewards() external payable whenNotPaused nonReentrant {
        require(msg.value > 0, "No ETH sent");
        totalRewardsAvailable = totalRewardsAvailable.add(msg.value);
        emit RewardAdded(msg.value);
    }

    /**
     * @notice Claim rewards based on token holdings
     */
    function claimRewards() external whenNotPaused whenEligible(msg.sender) nonReentrant {
        uint256 reward = _calculateReward(msg.sender);
        require(reward > 0, "No rewards");

        // Check cooldown
        uint256 timeSinceLastClaim = block.timestamp.sub(lastClaimTime[msg.sender]);
        if (timeSinceLastClaim < cooldownPeriod) {
            revert CooldownActive();
        }

        // Apply max claim limit
        if (reward > maxRewardPerClaim) {
            reward = maxRewardPerClaim;
        }

        // Apply penalty if applicable (e.g., for frequent claims, though logic can be extended)
        uint256 penalty = reward.mul(penaltyRate).div(10000);
        uint256 netReward = reward.sub(penalty);

        // Update state
        totalRewardsDistributed = totalRewardsDistributed.add(reward);
        totalRewardsAvailable = totalRewardsAvailable.sub(reward);
        lastClaimTime[msg.sender] = block.timestamp;

        // Transfer rewards and penalty
        (bool success1, ) = payable(msg.sender).call{value: netReward}("");
        if (!success1) revert TransferFailed();

        if (penalty > 0) {
            (bool success2, ) = payable(penaltyWallet).call{value: penalty}("");
            if (!success2) revert TransferFailed();
            emit PenaltyApplied(msg.sender, penalty);
        }

        emit RewardClaimed(msg.sender, netReward);
        emit CooldownStarted(msg.sender, block.timestamp);
    }

    /**
     * @notice Reset cooldown for a user (owner emergency function)
     * @param user The address to reset
     */
    function resetCooldown(address user) external onlyOwner {
        lastClaimTime[user] = 0;
        emit CooldownReset(user);
    }

    // --- Internal Functions ---
    function _calculateReward(address account) internal view returns (uint256) {
        if (totalRewardsAvailable == 0) return 0;

        uint256 totalSupply = rewardToken.totalSupply();
        uint256 userBalance = rewardToken.balanceOf(account);

        if (userBalance == 0 || totalSupply == 0) return 0;

        // Pro-rata distribution
        return totalRewardsAvailable.mul(userBalance).div(totalSupply);
    }

    // --- View Functions ---
    function getClaimableReward(address account) external view returns (uint256) {
        if (isRewardExcluded[account]) return 0;
        if (rewardToken.balanceOf(account) < minTokensRequired) return 0;

        uint256 fullReward = _calculateReward(account);
        if (fullReward == 0) return 0;

        uint256 timeSinceLastClaim = block.timestamp.sub(lastClaimTime[account]);
        if (timeSinceLastClaim < cooldownPeriod) return 0;

        return fullReward > maxRewardPerClaim ? maxRewardPerClaim : fullReward;
    }

    function isClaimReady(address account) external view returns (bool) {
        if (isRewardExcluded[account]) return false;
        if (rewardToken.balanceOf(account) < minTokensRequired) return false;
        if (_calculateReward(account) == 0) return false;

        uint256 timeSinceLastClaim = block.timestamp.sub(lastClaimTime[account]);
        return timeSinceLastClaim >= cooldownPeriod;
    }

    function getExcludedAccounts() external view returns (address[] memory) {
        return excludedAccounts;
    }

    // --- Fallback ---
    receive() external payable {
        depositRewards();
    }

    // --- Withdraw Stuck Funds (Owner Safety) ---
    function withdrawStuckETH() external onlyOwner {
        (bool success, ) = payable(owner()).call{value: address(this).balance}("");
        require(success, "Withdraw failed");
    }

    function withdrawStuckTokens(address token) external onlyOwner {
        require(token != address(rewardToken), "Cannot withdraw reward token");
        IERC20(token).transfer(owner(), IERC20(token).balanceOf(address(this)));
    }
}

pragma solidity ^0.8.20;
import "IERC20.sol";
import "SafeERC20.sol";
import "ERC721Enumerable.sol";
import "Ownable2Step.sol";
import "ReentrancyGuard.sol";
import "Strings.sol";
import "ECDSA.sol";
contract CyberV is ERC721Enumerable, Ownable2Step, ReentrancyGuard {
    using SafeERC20 for IERC20;
    string private _baseTokenURI;
    address public signer;
    uint256 public totalCount = 2077;
    uint256 public price = 127*10**15;
    uint256 public whitelistStartTime;
    uint256 public whitelistEndTime;
    uint256 public publicStartTime;
    uint256 public publicEndTime;
    uint8 public countPerAddress = 2;
    mapping(address => uint256) public mintStats;
    constructor(string memory baseTokenURI, address _owner, address _signer) ERC721("CyberV", "CyberV") {
        _baseTokenURI = baseTokenURI;
        _transferOwnership(_owner);
        signer = _signer;
    }
    function getMintPeriod() public view returns(uint256) {
        if (block.timestamp >= whitelistStartTime && block.timestamp <= whitelistEndTime) {
            return 1;
        }
        else if (block.timestamp >= publicStartTime && block.timestamp <= publicEndTime) {
            return 2;
        }
        return 0;
    }
    function mint(uint256 _count, bytes calldata _signature) external payable nonReentrant {
        uint256 mintPeriod = getMintPeriod();
        require(
            mintPeriod > 0,
            "CyberV: mint not started or already closed"
        );
        require(
            _count > 0 && _count <= countPerAddress - mintStats[msg.sender],
            "CyberV: invalid count"
        );
        require(
            totalSupply() < totalCount,
            "CyberV: exceed total available supply"
        );
        require(msg.value == price * _count, "CyberV: invalid eth value");
        if (mintPeriod == 1) {
            bytes32 message = ECDSA.toEthSignedMessageHash(
              keccak256(
                abi.encodePacked(_getChainID(), address(this), msg.sender)
              )
            );
            require(
              ECDSA.recover(message, _signature) == signer,
              "CyberV: invalid signature"
            );
        }
        for(uint i=0; i<_count; i++) {
            mintStats[msg.sender] = mintStats[msg.sender] + 1;
            _safeMint(msg.sender, totalSupply() + 1);
        }
    }
    function tokenURI(uint256 _tokenId)
        public
        view
        virtual
        override
        returns (string memory)
    {
        require(_exists(_tokenId), "CyberV: nonexistent token id");
        return
            string(
                abi.encodePacked(
                    _baseTokenURI,
                    "/",
                    Strings.toString(_tokenId)
                )
            );
    }
    function setSigner(address _signer) external onlyOwner {
        signer = _signer;
    }
    function setBaseURI(string memory baseTokenURI) external onlyOwner {
        _baseTokenURI = baseTokenURI;
    }
    function setWhiteListMintTimeFrame(uint256 _whitelistStartTime, uint256 _whitelistEndTime) external onlyOwner {
        whitelistStartTime = _whitelistStartTime;
        whitelistEndTime = _whitelistEndTime;
    }
    function setPublicMintTimeFrame(uint256 _publicStartTime, uint256 _publicEndTime) external onlyOwner {
        publicStartTime = _publicStartTime;
        publicEndTime = _publicEndTime;
    }
    function withdraw(address _erc20) external onlyOwner {
        if (_erc20 == address(0)) {
            (bool sent, bytes memory data) = payable(owner()).call{value: address(this).balance}("");
            require(sent, "Failed to withdraw Ether");
        } else {
            IERC20 token = IERC20(_erc20);
            token.safeTransfer(owner(), token.balanceOf(address(this)));
        }
    }
    function _getChainID() internal view returns (uint256) {
        uint256 id;
        assembly {
            id := chainid()
        }
        return id;
    }
    receive() external payable {}
}

pragma solidity ^0.5.16;
import "./Owned.sol";
import "./interfaces/ISynthetixDebtShare.sol";
import "./MixinResolver.sol";
import "./SafeDecimalMath.sol";
contract SynthetixDebtShare is Owned, MixinResolver, ISynthetixDebtShare {
    using SafeMath for uint;
    using SafeDecimalMath for uint;
    struct PeriodBalance {
        uint128 amount;
        uint128 periodId;
    }
    bytes32 public constant CONTRACT_NAME = "SynthetixDebtShare";
    bytes32 private constant CONTRACT_ISSUER = "Issuer";
    uint internal constant MAX_PERIOD_ITERATE = 30;
    mapping(address => bool) public authorizedBrokers;
    mapping(address => bool) public authorizedToSnapshot;
    mapping(address => PeriodBalance[]) public balances;
    mapping(uint => uint) public totalSupplyOnPeriod;
    string public name;
    string public symbol;
    uint8 public decimals;
    uint128 public currentPeriodId;
    bool public isInitialized = false;
    constructor(address _owner, address _resolver) public Owned(_owner) MixinResolver(_resolver) {
        name = "Synthetix Debt Shares";
        symbol = "SDS";
        decimals = 18;
        currentPeriodId = 1;
    }
    function resolverAddressesRequired() public view returns (bytes32[] memory addresses) {
        addresses = new bytes32[](1);
        addresses[0] = CONTRACT_ISSUER;
    }
    function balanceOf(address account) public view returns (uint) {
        uint accountPeriodHistoryCount = balances[account].length;
        if (accountPeriodHistoryCount == 0) {
            return 0;
        }
        return uint(balances[account][accountPeriodHistoryCount - 1].amount);
    }
    function balanceOfOnPeriod(address account, uint periodId) public view returns (uint) {
        uint accountPeriodHistoryCount = balances[account].length;
        int oldestHistoryIterate =
            int(MAX_PERIOD_ITERATE < accountPeriodHistoryCount ? accountPeriodHistoryCount - MAX_PERIOD_ITERATE : 0);
        int i;
        for (i = int(accountPeriodHistoryCount) - 1; i >= oldestHistoryIterate; i--) {
            if (balances[account][uint(i)].periodId <= periodId) {
                return uint(balances[account][uint(i)].amount);
            }
        }
        require(i < 0, "SynthetixDebtShare: not found in recent history");
        return 0;
    }
    function totalSupply() public view returns (uint) {
        return totalSupplyOnPeriod[currentPeriodId];
    }
    function sharePercent(address account) external view returns (uint) {
        return sharePercentOnPeriod(account, currentPeriodId);
    }
    function sharePercentOnPeriod(address account, uint periodId) public view returns (uint) {
        uint balance = balanceOfOnPeriod(account, periodId);
        if (balance == 0) {
            return 0;
        }
        return balance.divideDecimal(totalSupplyOnPeriod[periodId]);
    }
    function allowance(address, address spender) public view returns (uint) {
        if (authorizedBrokers[spender]) {
            return uint(-1);
        } else {
            return 0;
        }
    }
    function addAuthorizedBroker(address target) external onlyOwner {
        authorizedBrokers[target] = true;
        emit ChangeAuthorizedBroker(target, true);
    }
    function removeAuthorizedBroker(address target) external onlyOwner {
        authorizedBrokers[target] = false;
        emit ChangeAuthorizedBroker(target, false);
    }
    function addAuthorizedToSnapshot(address target) external onlyOwner {
        authorizedToSnapshot[target] = true;
        emit ChangeAuthorizedToSnapshot(target, true);
    }
    function removeAuthorizedToSnapshot(address target) external onlyOwner {
        authorizedToSnapshot[target] = false;
        emit ChangeAuthorizedToSnapshot(target, false);
    }
    function takeSnapshot(uint128 id) external onlyAuthorizedToSnapshot {
        require(id > currentPeriodId, "period id must always increase");
        totalSupplyOnPeriod[id] = totalSupplyOnPeriod[currentPeriodId];
        currentPeriodId = id;
    }
    function mintShare(address account, uint256 amount) external onlyIssuer {
        require(account != address(0), "ERC20: mint to the zero address");
        _increaseBalance(account, amount);
        totalSupplyOnPeriod[currentPeriodId] = totalSupplyOnPeriod[currentPeriodId].add(amount);
        emit Transfer(address(0), account, amount);
        emit Mint(account, amount);
    }
    function burnShare(address account, uint256 amount) external onlyIssuer {
        require(account != address(0), "ERC20: burn from zero address");
        _deductBalance(account, amount);
        totalSupplyOnPeriod[currentPeriodId] = totalSupplyOnPeriod[currentPeriodId].sub(amount);
        emit Transfer(account, address(0), amount);
        emit Burn(account, amount);
    }
    function approve(address, uint256) external pure returns (bool) {
        revert("debt shares are not transferrable");
    }
    function transfer(address, uint256) external pure returns (bool) {
        revert("debt shares are not transferrable");
    }
    function transferFrom(
        address from,
        address to,
        uint256 amount
    ) external onlyAuthorizedBrokers returns (bool) {
        require(to != address(0), "ERC20: send to the zero address");
        _deductBalance(from, amount);
        _increaseBalance(to, amount);
        emit Transfer(address(from), address(to), amount);
        return true;
    }
    function importAddresses(address[] calldata accounts, uint256[] calldata amounts) external onlyOwner onlySetup {
        uint supply = totalSupplyOnPeriod[currentPeriodId];
        for (uint i = 0; i < accounts.length; i++) {
            uint curBalance = balanceOf(accounts[i]);
            if (curBalance < amounts[i]) {
                uint amount = amounts[i] - curBalance;
                _increaseBalance(accounts[i], amount);
                supply = supply.add(amount);
                emit Mint(accounts[i], amount);
                emit Transfer(address(0), accounts[i], amount);
            } else if (curBalance > amounts[i]) {
                uint amount = curBalance - amounts[i];
                _deductBalance(accounts[i], amount);
                supply = supply.sub(amount);
                emit Burn(accounts[i], amount);
                emit Transfer(accounts[i], address(0), amount);
            }
        }
        totalSupplyOnPeriod[currentPeriodId] = supply;
    }
    function finishSetup() external onlyOwner {
        isInitialized = true;
    }
    function _increaseBalance(address account, uint amount) internal {
        uint accountBalanceCount = balances[account].length;
        if (accountBalanceCount == 0) {
            balances[account].push(PeriodBalance(uint128(amount), uint128(currentPeriodId)));
        } else {
            uint128 newAmount = uint128(uint(balances[account][accountBalanceCount - 1].amount).add(amount));
            if (balances[account][accountBalanceCount - 1].periodId != currentPeriodId) {
                balances[account].push(PeriodBalance(newAmount, currentPeriodId));
            } else {
                balances[account][accountBalanceCount - 1].amount = newAmount;
            }
        }
    }
    function _deductBalance(address account, uint amount) internal {
        uint accountBalanceCount = balances[account].length;
        require(accountBalanceCount != 0, "SynthetixDebtShare: account has no share to deduct");
        uint128 newAmount = uint128(uint(balances[account][accountBalanceCount - 1].amount).sub(amount));
        if (balances[account][accountBalanceCount - 1].periodId != currentPeriodId) {
            balances[account].push(PeriodBalance(newAmount, currentPeriodId));
        } else {
            balances[account][accountBalanceCount - 1].amount = newAmount;
        }
    }
    modifier onlyIssuer() {
        require(msg.sender == requireAndGetAddress(CONTRACT_ISSUER), "SynthetixDebtShare: only issuer can mint/burn");
        _;
    }
    modifier onlyAuthorizedToSnapshot() {
        require(
            authorizedToSnapshot[msg.sender] || msg.sender == requireAndGetAddress(CONTRACT_ISSUER),
            "SynthetixDebtShare: not authorized to snapshot"
        );
        _;
    }
    modifier onlyAuthorizedBrokers() {
        require(authorizedBrokers[msg.sender], "SynthetixDebtShare: only brokers can transferFrom");
        _;
    }
    modifier onlySetup() {
        require(!isInitialized, "SynthetixDebt: only callable while still initializing");
        _;
    }
    event Mint(address indexed account, uint amount);
    event Burn(address indexed account, uint amount);
    event Transfer(address indexed from, address indexed to, uint value);
    event ChangeAuthorizedBroker(address indexed authorizedBroker, bool authorized);
    event ChangeAuthorizedToSnapshot(address indexed authorizedToSnapshot, bool authorized);
}

