/**
 * @title EtherX314
 * @dev ERC20 token with integrated IDO, auto-LP, and reward distribution
 */
contract EtherX314 is ERC20, Ownable, ReentrancyGuard {
    using SafeMath for uint256;

    // --- Token & IDO Parameters ---
    uint256 private constant _totalSupply = 1_000_000_000 * 10**18; // 1B tokens
    uint256 public idoStartTime;
    uint256 public idoEndTime;
    uint256 public idoHardCap = 50 * 10**18; // 50 ETH
    uint256 public idoRaised; // Tracks ETH raised
    bool public idoFinalized = false;

    // --- Addresses ---
    address public marketingWallet;
    address public devWallet;
    address public liquidityWallet;

    // --- Fees ---
    uint256 public marketingFee = 3; // 3%
    uint256 public devFee = 2; // 2%
    uint256 public liquidityFee = 5; // 5%
    uint256 public rewardFee = 5; // 5%
    uint256 private constant _feeDenominator = 100;

    // --- DEX Integration ---
    IUniswapV2Router02 public immutable uniswapV2Router;
    address public uniswapV2Pair;
    bool private _liquidityAdded = false;

    // --- IDO & Rewards ---
    mapping(address => uint256) public idoContributions;
    address[] public idoParticipants;
    mapping(address => bool) public hasClaimedReward;
    uint256 public rewardPool; // ETH for rewards

    // --- Events ---
    event IDOStarted(uint256 startTime, uint256 endTime);
    event IDOContribution(address indexed investor, uint256 amount);
    event RewardsClaimed(address indexed investor, uint256 tokenAmount);
    event LiquidityAdded(uint256 tokenAmount, uint256 ethAmount);
    event Finalized(uint256 tokenForLP, uint256 ethForLP);
    event WalletsUpdated(address marketing, address dev, address liquidity);
    event FeesUpdated(uint256 marketing, uint256 dev, uint256 liquidity, uint256 reward);

    // --- Errors ---
    error IDONotActive();
    error IDOEnded();
    error AmountTooLow();
    error HardCapReached();
    error IDONotFinalized();
    error AlreadyClaimed();
    error NoContribution();
    error InvalidAddress();

    constructor() ERC20("EtherX314", "X314") {
        // Set wallets (placeholders)
        marketingWallet = 0xMarketingAddrHere;
        devWallet = 0xDevAddrHere;
        liquidityWallet = 0xLiquidityAddrHere;

        // Set up Uniswap V2 router (Mainnet)
        uniswapV2Router = IUniswapV2Router02(0x7a250d5630B4cF539739dF2C5dAcb4c659F2488D);

        // Exclude owner and contract from fees
        _excludeFromFees(owner());
        _excludeFromFees(address(this));

        _mint(owner(), _totalSupply);
    }

    // --- Owner Functions ---
    function startIDO(uint256 durationMinutes) external onlyOwner {
        require(idoStartTime == 0, "IDO already started");
        require(durationMinutes > 0, "Invalid duration");

        idoStartTime = block.timestamp;
        idoEndTime = block.timestamp + (durationMinutes * 1 minutes);

        emit IDOStarted(idoStartTime, idoEndTime);
    }

    function updateWallets(address newMarketing, address newDev, address newLiquidity) external onlyOwner {
        if (newMarketing == address(0) || newDev == address(0) || newLiquidity == address(0)) revert InvalidAddress();
        marketingWallet = newMarketing;
        devWallet = newDev;
        liquidityWallet = newLiquidity;
        _excludeFromFees(newMarketing);
        _excludeFromFees(newDev);
        _excludeFromFees(newLiquidity);
        emit WalletsUpdated(newMarketing, newDev, newLiquidity);
    }

    function updateFees(
        uint256 newMarketing,
        uint256 newDev,
        uint256 newLiquidity,
        uint256 newReward
    ) external onlyOwner {
        require(newMarketing <= 10 && newDev <= 10 && newLiquidity <= 10 && newReward <= 10, "Fee too high");
        marketingFee = newMarketing;
        devFee = newDev;
        liquidityFee = newLiquidity;
        rewardFee = newReward;
        emit FeesUpdated(newMarketing, newDev, newLiquidity, newReward);
    }

    function finalizeIDO() external nonReentrant {
        require(!idoFinalized, "IDO already finalized");
        require(block.timestamp > idoEndTime || idoRaised >= idoHardCap, "IDO not ended or hardcap not reached");

        idoFinalized = true;

        // Calculate ETH for LP (50% of raised ETH)
        uint256 ethForLP = idoRaised.mul(50).div(100);

        // Add liquidity
        _addLiquidity(ethForLP);

        // Distribute remaining ETH to wallets
        uint256 remainingEth = address(this).balance;
        uint256 marketingShare = remainingEth.mul(marketingFee).div(_feeDenominator);
        uint256 devShare = remainingEth.mul(devFee).div(_feeDenominator);

        payable(marketingWallet).transfer(marketingShare);
        payable(devWallet).transfer(devShare);

        // Reward pool is funded from token reward fee, not ETH

        emit Finalized(_totalSupply.mul(liquidityFee).div(_feeDenominator.add(rewardFee)), ethForLP);
    }

    // --- IDO Function ---
    function participateInIDO() external payable nonReentrant {
        if (idoStartTime == 0 || block.timestamp < idoStartTime) revert IDONotActive();
        if (block.timestamp > idoEndTime) revert IDOEnded();
        if (msg.value < 0.05 ether) revert AmountTooLow(); // Minimum 0.05 ETH
        if (idoRaised + msg.value > idoHardCap) revert HardCapReached();

        idoContributions[msg.sender] += msg.value;
        idoRaised += msg.value;

        // Add to participants list if first contribution
        if (idoContributions[msg.sender] == msg.value) {
            idoParticipants.push(msg.sender);
        }

        emit IDOContribution(msg.sender, msg.value);
    }

    // --- Reward Distribution ---
    function claimReward() external nonReentrant {
        if (!idoFinalized) revert IDONOTFinalized();
        if (hasClaimedReward[msg.sender]) revert AlreadyClaimed();
        if (idoContributions[msg.sender] == 0) revert NoContribution();

        // Calculate reward: (userContribution / totalRaised) * rewardPoolTokens
        uint256 totalRewardTokens = _totalSupply.mul(rewardFee).div(_feeDenominator.add(liquidityFee));
        uint256 rewardAmount = totalRewardTokens.mul(idoContributions[msg.sender]).div(idoRaised);

        hasClaimedReward[msg.sender] = true;
        _transfer(address(this), msg.sender, rewardAmount);

        emit RewardsClaimed(msg.sender, rewardAmount);
    }

    // --- Internal Functions ---
    function _addLiquidity(uint256 ethAmount) private {
        require(!_liquidityAdded, "Liquidity already added");

        // Approve token for router
        uint256 tokenAmount = _totalSupply.mul(liquidityFee).div(_feeDenominator.add(rewardFee));

        // Create pair if not exists
        if (uniswapV2Pair == address(0)) {
            uniswapV2Pair = IUniswapV2Factory(uniswapV2Router.factory())
                .createPair(address(this), uniswapV2Router.WETH());
        }

        // Add liquidity
        uniswapV2Router.addLiquidity{
            value: ethAmount
        }(
            address(this),
            uniswapV2Router.WETH(),
            tokenAmount,
            ethAmount,
            0, // slippage handled off-chain
            0,
            liquidityWallet, // LP tokens sent to liquidity wallet
            block.timestamp + 3600
        );

        _liquidityAdded = true;
        emit LiquidityAdded(tokenAmount, ethAmount);
    }

    function _excludeFromFees(address account) private {
        // In a real scenario, you'd have a mapping like `isExcludedFromFees[account] = true;`
        // This is a placeholder as ERC20 doesn't natively support fee exclusion
        // Fee logic would be implemented in a custom `_transfer` override
    }

    // --- Custom Transfer with Fees (Placeholder) ---
    // In a full implementation, you'd override `_transfer` to take fees
    // This is omitted for brevity but would route fees to respective pools

    // --- Withdraw Stuck ETH ---
    function rescueETH() external onlyOwner {
        payable(owner()).transfer(address(this).balance);
    }

    // --- Getters ---
    function getParticipantCount() external view returns (uint256) {
        return idoParticipants.length;
    }

    function getContribution(address investor) external view returns (uint256) {
        return idoContributions[investor];
    }

    function isParticipating(address investor) external view returns (bool) {
        return idoContributions[investor] > 0;
    }

    // Receive ETH from IDO
    receive() external payable {}
}

