/**
 * @title CustomERC20Generator
 * @dev A factory-like contract to deploy and manage customizable ERC20 tokens
 *      with automated liquidity, taxes, and Uniswap V3 integration.
 */
contract CustomERC20Generator is Ownable, ReentrancyGuard {
    using SafeMath for uint256;
    using SafeERC20 for IERC20;

    // --- Service Fee ---
    uint256 public serviceFee = 0.5 ether; // Fee to create a token
    address public feeCollector;

    // --- Token Parameters Template ---
    struct TokenConfig {
        string name;
        string symbol;
        uint256 totalSupply;
        uint256 buyTax;
        uint256 sellTax;
        uint256 liquidityTax;
        address marketingWallet;
        uint256 swapThreshold;
        bool shouldAddLiquidity;
        uint256 liquidityAmount;
        address uniswapV3Router;
        uint24 uniswapPoolFee;
    }

    // --- Deployed Token Info ---
    struct TokenInfo {
        address token;
        address creator;
        uint256 creationTime;
    }

    TokenInfo[] public deployedTokens;
    mapping(address => bool) public isTokenActive;
    mapping(address => mapping(address => bool)) public isExcludedFromFees;

    // --- Events ---
    event TokenCreated(
        address indexed token,
        string name,
        string symbol,
        address indexed creator,
        uint256 totalSupply
    );
    event FeesCollected(address indexed token, uint256 marketingAmount, uint256 liquidityAmount);
    event LiquidityAdded(address indexed token, uint256 tokenAmount, uint256 ethAmount);
    event FeeExclusionSet(address indexed token, address indexed account, bool excluded);
    event ParametersUpdated(
        uint256 serviceFee,
        address feeCollector,
        address indexed router
    );
    event TokenBurned(address indexed token, address indexed from, uint256 amount);
    event TokensMinted(address indexed token, address indexed to, uint256 amount);

    // --- Errors ---
    error InsufficientFee();
    error InvalidAddress();
    error TokenCreationFailed();
    error TransferFailed();

    constructor() {
        feeCollector = owner();
    }

    // --- Owner Functions ---
    function updateServiceParams(uint256 newFee, address newCollector) external onlyOwner {
        if (newCollector == address(0)) revert InvalidAddress();
        serviceFee = newFee;
        feeCollector = newCollector;
        emit ParametersUpdated(newFee, newCollector, address(0));
    }

    // --- Token Creation ---
    function createToken(TokenConfig calldata config) external payable nonReentrant returns (address) {
        // Validate input
        if (msg.value < serviceFee) revert InsufficientFee();
        if (config.marketingWallet == address(0) || config.uniswapV3Router == address(0)) revert InvalidAddress();

        // Collect service fee
        (bool sent, ) = feeCollector.call{value: serviceFee}(");
        require(sent, "Fee transfer failed");

        // Deploy new token
        CustomERC20Token newToken = new CustomERC20Token(
            config.name,
            config.symbol,
            config.totalSupply,
            msg.sender, // owner is creator initially
            config.buyTax,
            config.sellTax,
            config.liquidityTax,
            config.marketingWallet,
            config.swapThreshold,
            config.uniswapV3Router,
            config.uniswapPoolFee
        );

        address tokenAddress = address(newToken);
        if (tokenAddress == address(0)) revert TokenCreationFailed();

        // Exclude creator and marketing wallet from fees
        newToken.excludeFromFees(msg.sender);
        newToken.excludeFromFees(config.marketingWallet);
        newToken.excludeFromFees(address(this));
        newToken.excludeFromFees(tokenAddress);

        // Record deployment
        deployedTokens.push(TokenInfo({
            token: tokenAddress,
            creator: msg.sender,
            creationTime: block.timestamp
        }));
        isTokenActive[tokenAddress] = true;

        // Add initial liquidity if requested
        if (config.shouldAddLiquidity && config.liquidityAmount > 0) {
            newToken.transfer(address(newToken), config.liquidityAmount);
            newToken.enableTrading(); // Assume trading starts after LP
            // Liquidity will be added when threshold is met via swaps
        }

        emit TokenCreated(tokenAddress, config.name, config.symbol, msg.sender, config.totalSupply);
        return tokenAddress;
    }

    // --- View Functions ---
    function getTokenCount() external view returns (uint256) {
        return deployedTokens.length;
    }

    function getTokenInfo(uint256 index) external view returns (TokenInfo memory) {
        return deployedTokens[index];
    }

    // --- Internal Logic ---
    function _swapTokensForETH(address token, uint256 tokenAmount, address router, address recipient) internal {
        IERC20(token).safeApprove(router, tokenAmount);

        // For demo, assume WETH and 0.3% fee pool
        address weth = _getWETH(router);

        IUniswapV3Router(router).exactInputSingle{
            value: 0
        }(
            IUniswapV3Router.ExactInputSingleParams({
                tokenIn: token,
                tokenOut: weth,
                fee: 3000, // 0.3%
                recipient: recipient,
                deadline: block.timestamp + 15,
                amountIn: tokenAmount,
                amountOutMinimum: 0,
                sqrtPriceLimitX96: 0
            })
        );
    }

    function _getWETH(address router) internal view returns (address) {
