    contract CustomERC20Token is ERC20, Ownable {
        using SafeMath for uint256;

        uint256 public buyTax;
        uint256 public sellTax;
        uint256 public liquidityTax;
        address public marketingWallet;
        uint256 public swapThreshold;
        address public uniswapV3Router;
        uint24 public uniswapPoolFee;
        bool public tradingEnabled = false;

        mapping(address => bool) public isExcludedFromFees;

        constructor(
            string memory name_,
            string memory symbol_,
            uint256 totalSupply_,
            address owner_,
            uint256 buyTax_,
            uint256 sellTax_,
            uint256 liquidityTax_,
            address marketingWallet_,
            uint256 swapThreshold_,
            address router_,
            uint24 poolFee_
        ) ERC20(name_, symbol_) {
            buyTax = buyTax_;
            sellTax = sellTax_;
            liquidityTax = liquidityTax_;
            marketingWallet = marketingWallet_;
            swapThreshold = swapThreshold_;
            uniswapV3Router = router_;
            uniswapPoolFee = poolFee_;

            _mint(owner_, totalSupply_);
            transferOwnership(owner_);
        }

        function excludeFromFees(address account, bool excluded) external onlyOwner {
            isExcludedFromFees[account] = excluded;
            emit FeeExclusionSet(address(this), account, excluded);
        }

        function enableTrading() external onlyOwner {
            tradingEnabled = true;
        }

        function updateTaxes(
            uint256 newBuy,
            uint256 newSell,
            uint256 newLiquidity
        ) external onlyOwner {
            require(newBuy <= 20 && newSell <= 20 && newLiquidity <= 20, "Tax too high");
            buyTax = newBuy;
            sellTax = newSell;
            liquidityTax = newLiquidity;
        }

        function updateMarketingWallet(address newWallet) external onlyOwner {
            require(newWallet != address(0), "Invalid wallet");
            marketingWallet = newWallet;
        }

        function updateSwapThreshold(uint256 newThreshold) external onlyOwner {
            swapThreshold = newThreshold;
        }

        function _transfer(
            address from,
            address to,
            uint256 amount
        ) internal override {
            require(from != address(0), "ERC20: transfer from zero address");
            require(to != address(0), "ERC20: transfer to zero address");
            require(amount > 0, "Transfer amount zero");
            require(tradingEnabled || isExcludedFromFees[from] || isExcludedFromFees[to], "Trading not enabled");

            uint256 fee = 0;
            bool takeFee = !isExcludedFromFees[from] && !isExcludedFromFees[to];

            if (takeFee) {
                if (to == uniswapV3Router || to == IUniswapV3Factory(uniswapV3Router).getPool(address(this), _getWETH(uniswapV3Router), uniswapPoolFee)) {
                    // Selling
                    fee = amount.mul(sellTax).div(100);
                } else if (from == uniswapV3Router || from == IUniswapV3Factory(uniswapV3Router).getPool(address(this), _getWETH(uniswapV3Router), uniswapPoolFee)) {
                    // Buying
                    fee = amount.mul(buyTax).div(100);
                }

                if (fee > 0) {
                    super._transfer(from, address(this), fee);
                    _handleFees();
                }
            }

            super._transfer(from, to, amount.sub(fee));
        }

        function _handleFees() private {
            uint256 contractTokenBalance = balanceOf(address(this));
            if (contractTokenBalance >= swapThreshold) {
                uint256 totalTax = buyTax.add(sellTax).add(liquidityTax);
                if (totalTax == 0) return;

                uint256 marketingShare = contractTokenBalance.mul(marketingWallet != address(0) ? (buyTax.add(sellTax)) : 0).div(totalTax);
                uint256 liquidityShare = contractTokenBalance.mul(liquidityTax).div(totalTax);

                if (marketingShare > 0) {
                    _swapTokensForETH(address(this), marketingShare, uniswapV3Router, marketingWallet);
                }
                if (liquidityShare > 0) {
                    // Swap half to ETH
                    uint256 half = liquidityShare.div(2);
                    uint256 otherHalf = liquidityShare.sub(half);
                    _swapTokensForETH(address(this), half, uniswapV3Router, address(this));
                    uint256 ethReceived = address(this).balance;
                    _addLiquidity(address(this), otherHalf, ethReceived, uniswapV3Router, uniswapPoolFee);
                }

                emit FeesCollected(address(this), marketingShare, liquidityShare);
            }
        }

        function burn(uint256 amount) external {
            _burn(msg.sender, amount);
            emit TokenBurned(address(this), msg.sender, amount);
        }

        function mint(address to, uint256 amount) external onlyOwner {
            _mint(to, amount);
            emit TokensMinted(address(this), to, amount);
        }
    }
}

