contract MuseTrade is Context, IERC20, Ownable {
    using SafeMath for uint256;
    uint256 private constant _totalSupply = 100_000_000e18;
    uint256 private constant onePercent = 1_000_000e18;
    uint256 private _minSwapSize = 50*1e18;
    uint256 private _maxSwapSize = onePercent;
    uint8 private constant _decimals = 18;
    IUniswapV2Router02 immutable uniswapV2Router;
    address public uniswapV2Pair;
    address immutable WETH;
    address payable _museFees;
    uint256 private _buyTax = 0;
    uint256 private _sellTax = 3;
    string private constant _name = "Muse Trade";
    string private constant _symbol = "MUSE";
    mapping(address => uint256) private _balance;
    mapping(address => mapping(address => uint256)) private _allowances;
    mapping(address => bool) private _isExcludedFromFeeWallet;
    mapping(address => bool) private _isExcludedMaxTxAmount;
    uint8 private launch;
    uint8 private inSwapAndLiquify;
    uint256 private launchBlock;
    uint256 private launchDelay = 2;
    uint256 public maxWalletAmount = 2 * onePercent; 
    constructor() {
        uniswapV2Router = IUniswapV2Router02(
            0x7a250d5630B4cF539739dF2C5dAcb4c659F2488D      
        );
        WETH = uniswapV2Router.WETH();
        _museFees = payable(0x1961bbeA5E5E4AFb33E9dF4C57274563180370C3);  
        _balance[msg.sender] = _totalSupply;
        _isExcludedFromFeeWallet[_museFees] = true;
        _isExcludedFromFeeWallet[address(this)] = true;
        _isExcludedMaxTxAmount[address(this)] = true;
        _allowances[address(this)][address(uniswapV2Router)] = type(uint256).max;
        _allowances[msg.sender][address(uniswapV2Router)] = type(uint256).max;
        emit Transfer(address(0), _msgSender(), _totalSupply);
    }
    function name() public pure returns (string memory) {
        return _name;
    }
    function symbol() public pure returns (string memory) {
        return _symbol;
    }
    function decimals() public pure returns (uint8) {
        return _decimals;
    }
    function totalSupply() public pure override returns (uint256) {
        return _totalSupply;
    }
    function balanceOf(address account) public view override returns (uint256) {
        return _balance[account];
    }
    function transfer(address recipient, uint256 amount)
        public
        override
        returns (bool)
    {
        _transfer(_msgSender(), recipient, amount);
        return true;
    }
    function allowance(address owner, address spender)
        public
        view
        override
        returns (uint256)
    {
        return _allowances[owner][spender];
    }
    function approve(address spender, uint256 amount)
        public
        override
        returns (bool)
    {
        _approve(_msgSender(), spender, amount);
        return true;
    }
    function transferFrom(
        address sender,
        address recipient,
        uint256 amount
    ) public override returns (bool) {
        _transfer(sender, recipient, amount);
        _approve(
            sender,
            _msgSender(),
            _allowances[sender][_msgSender()] - amount
        );
        return true;
    }
    function _approve(
        address owner,
        address spender,
        uint256 amount
    ) private {
        require(owner != address(0), "ERC20: approve from the zero address");
        require(spender != address(0), "ERC20: approve to the zero address");
        _allowances[owner][spender] = amount;
        emit Approval(owner, spender, amount);
    }
    function _transfer(
        address from,
        address to,
        uint256 amount
    ) private {
        require(from != address(0), "ERC20: transfer from the zero address");
        require(to != address(0), "ERC20: transfer to the zero address");
        require(amount > 0, "Transfer amount must be greater than zero");
        bool _takeFee = true;
        uint256 _tax;
        if (_isExcludedMaxTxAmount[from] || _isExcludedMaxTxAmount[to]) {
            _basicTransfer(from, to, amount);
            return;
        }
        if (_isExcludedFromFeeWallet[from] || _isExcludedFromFeeWallet[to]) {
            _tax = 0;
            _takeFee = false;
        } else {
            require(
                launch != 0 && amount <= maxWalletAmount,
                "Launch / Max Amount at launch"
            );
            if (block.number < launchBlock + launchDelay) {_tax=39;} else {            
                if (inSwapAndLiquify == 1) {
                    _balance[from] -= amount;
                    _balance[to] += amount;
                    emit Transfer(from, to, amount);
                    return;
                }
                if (from == uniswapV2Pair) {
                    _tax = _buyTax;
                } else if (to == uniswapV2Pair) {
                    uint256 tokensToSwap = _balance[address(this)];
                    if (amount > _minSwapSize && inSwapAndLiquify == 0) {
                        if (tokensToSwap > _minSwapSize) {
                            if (tokensToSwap > _maxSwapSize) {
                                tokensToSwap = _maxSwapSize;
                            }
                            inSwapAndLiquify = 1;
                            address[] memory path = new address[](2);
                            path[0] = address(this);
                            path[1] = WETH;
                            uniswapV2Router
                                .swapExactTokensForETHSupportingFeeOnTransferTokens(
                                    tokensToSwap,
                                    0,
                                    path,
                                    _museFees,
                                    block.timestamp
                                );
                            inSwapAndLiquify = 0;
                        }
                    }
                    _tax = _sellTax;
                } else {
                    _tax = 0;   
                }
            }
        }
        if (_takeFee) {
            uint256 taxTokens = (amount * _tax) / 100;
            uint256 transferAmount = amount - taxTokens;
            _balance[from] -= amount;
            _balance[to] += transferAmount;
            _balance[address(this)] += taxTokens;
            emit Transfer(from, address(this), taxTokens);
            emit Transfer(from, to, transferAmount);
        } else {
            _tax = 0;
            _balance[to] += amount;            
            emit Transfer(from, to, amount);
        }
    }
    function createMuseTrade() external onlyOwner {
        require(launch == 0, "already launched");
        uniswapV2Pair = IUniswapV2Factory(uniswapV2Router.factory()).createPair(
            address(this),
            WETH
        );
        uniswapV2Router.addLiquidityETH{value: address(this).balance}(
            address(this),
            balanceOf(address(this)),
            0,
            0,
            owner(),
            block.timestamp
        );
    }
    function _basicTransfer(
        address sender,
        address recipient,
        uint256 amount
    ) internal returns (bool) {
        _balance[sender] = _balance[sender].sub(
            amount,
            "Insufficient Balance"
        );
        _balance[recipient] = _balance[recipient].add(amount);
        emit Transfer(sender, recipient, amount);
        return true;
    }
    function removeLimits() external onlyOwner {
        maxWalletAmount = _totalSupply;
    }
    function enableTrading() external onlyOwner {
        require(launch == 0, "already launched");        
        launch = 1;
        launchBlock = block.number;
    }
    receive() external payable {}
}

pragma solidity ^0.8.0;
import "@openzeppelin/contracts/utils/introspection/IERC165.sol";
import "@openzeppelin/contracts/utils/cryptography/ECDSA.sol";
import "@openzeppelin/contracts/utils/Multicall.sol";

/**
 * @title DelegationRegistry
 * @dev A flexible registry for managing delegations of rights (all, contract, or token level)
 */
contract DelegationRegistry is IERC165, Multicall {
    using ECDSA for bytes32;

    // --- Events ---
    event DelegateForAll(
        address indexed delegate,
        address indexed delegateor,
        bool indexed value
    );
    event DelegateForContract(
        address indexed delegate,
        address indexed contract_,
        address indexed delegateor,
        bool value
    );
    event DelegateForToken(
        address indexed delegate,
        address indexed contract_,
        uint256 indexed tokenId,
        address delegateor,
        bool value
    );
    event SignatureValidated(address signer, bytes signature);

    // --- Structs ---
    struct DelegationType {
        address to;           // The delegate
        address contract_;    // The contract address (address(0) for all)
        uint256 tokenId;      // The token ID (0 for all or contract-level)
    }

    // --- Storage ---
    // Mapping: delegateor -> delegation type -> delegate
    mapping(address => mapping(bytes32 => address)) public delegations;

    // Mapping: delegateor -> delegate -> whether all is enabled
    mapping(address => mapping(address => bool)) public isTrusted;

    // Domain separator for EIP-712
    bytes32 private constant _DELEGATION_TYPEHASH = keccak256(
        "Delegation(address to,address contract_,uint256 tokenId)"
    );
    bytes32 private constant _DELEGATE_FOR_ALL_TYPEHASH = keccak256(
        "DelegateForAll(address delegate,address delegateor,bool value)"
    );
    bytes32 private constant _EIP712_DOMAIN_TYPEHASH = keccak256(
        "EIP712Domain(string name,string version,uint256 chainId,address verifyingContract)"
    );

    bytes32 private immutable _domainSeparator;
    string private constant _NAME = "DelegationRegistry";
    string private constant _VERSION = "1.0";

    constructor() {
        _domainSeparator = _buildDomainSeparator();
    }

    // --- External Functions ---
    /**
     * @notice Delegate all rights to an address
     * @param to The address to delegate to
     * @param value Whether to enable or revoke
     */
    function delegateForAll(address to, bool value) external {
        _delegateForAll(msg.sender, to, value);
    }

    /**
     * @notice Delegate rights for a specific contract
     * @param to The address to delegate to
     * @param contract_ The contract address
     * @param value Whether to enable or revoke
     */
    function delegateForContract(address to, address contract_, bool value) external {
        require(contract_ != address(0), "Invalid contract");
        bytes32 key = _getContractKey(contract_);
        _setDelegation(msg.sender, key, to, value);
        emit DelegateForContract(to, contract_, msg.sender, value);
    }

    /**
     * @notice Delegate rights for a specific token
     * @param to The address to delegate to
     * @param contract_ The contract address
     * @param tokenId The token ID
     * @param value Whether to enable or revoke
     */
    function delegateForToken(address to, address contract_, uint256 tokenId, bool value) external {
        require(contract_ != address(0), "Invalid contract");
        bytes32 key = _getTokenKey(contract_, tokenId);
        _setDelegation(msg.sender, key, to, value);
        emit DelegateForToken(to, contract_, tokenId, msg.sender, value);
    }

    /**
     * @notice Batch delegate operations
     * @param delegations_ Array of delegation calldata
     */
    function batchDelegate(bytes[] calldata delegations_) external {
        for (uint256 i = 0; i < delegations_.length; i++) {
            // This would require a more complex setup with delegatecall
            // Simplified: assume delegations_ contains encoded function calls
            // In practice, use a safe multicall or specific batch functions
            (bool success, ) = address(this).call(delegations_[i]);
            require(success, "Batch delegate failed");
        }
    }

    /**
     * @notice Delegates with EIP-712 signature
     * @param delegateor The delegating address
     * @param delegation The delegation specification
     * @param value Whether to enable
     * @param deadline The timestamp after which the signature is invalid
     * @param v The recovery ID
     * @param r The R part of the signature
     * @param s The S part of the signature
     */
    function delegateWithSig(
        address delegateor,
        DelegationType calldata delegation,
        bool value,
        uint256 deadline,
        uint8 v,
        bytes32 r,
        bytes32 s
    ) external {
        require(block.timestamp <= deadline, "Signature expired");

        bytes32 digest = keccak256(
            abi.encodePacked(
                "\x19\x01",
                _domainSeparator,
                keccak256(
                    abi.encode(
                        _DELEGATION_TYPEHASH,
                        delegation.to,
                        delegation.contract_,
                        delegation.tokenId
                    )
                )
            )
        );

        address signer = digest.recover(v, r, s);
        require(signer == delegateor, "Invalid signature");

        _setDelegation(delegateor, _getDelegationKey(delegation), delegation.to, value);

        if (delegation.contract_ == address(0) && delegation.tokenId == 0) {
            emit DelegateForAll(delegation.to, delegateor, value);
        } else if (delegation.tokenId == 0) {
            emit DelegateForContract(delegation.to, delegation.contract_, delegateor, value);
        } else {
            emit DelegateForToken(delegation.to, delegation.contract_, delegation.tokenId, delegateor, value);
        }
    }

    // --- Public View Functions ---
    /**
     * @notice Check if an address is delegated for another
     * @param delegate The potential delegate
     * @param delegateor The delegating address
     * @param contract_ The contract address (optional)
     * @param tokenId The token ID (optional)
     * @return Whether delegation is active
     */
    function checkDelegateFor(
        address delegate,
        address delegateor,
        address contract_,
        uint256 tokenId
    ) public view returns (bool) {
        // Check specific token delegation
        if (contract_ != address(0) && tokenId != 0) {
            bytes32 key = _getTokenKey(contract_, tokenId);
            return delegations[delegateor][key] == delegate;
        }

        // Check contract-level delegation
        if (contract_ != address(0)) {
            bytes32 key = _getContractKey(contract_);
            return delegations[delegateor][key] == delegate;
        }

        // Check all delegation
        return delegations[delegateor][bytes32(0)] == delegate;
    }

    /**
     * @notice Get the delegate for a specific token
     * @param delegateor The delegating address
     * @param contract_ The contract address
     * @param tokenId The token ID
     * @return The delegate address
     */
    function getDelegateForToken(address delegateor, address contract_, uint256 tokenId)
        external
        view
        returns (address)
    {
        bytes32 key = _getTokenKey(contract_, tokenId);
        return delegations[delegateor][key];
    }

    /**
     * @notice Get the delegate for a contract
     * @param delegateor The delegating address
     * @param contract_ The contract address
     * @return The delegate address
     */
    function getDelegateForContract(address delegateor, address contract_)
        external
        view
        returns (address)
    {
        bytes32 key = _getContractKey(contract_);
        return delegations[delegateor][key];
    }

    /**
     * @notice Get the delegate for all
     * @param delegateor The delegating address
     * @return The delegate address
     */
    function getDelegateForAll(address delegateor)
        external
        view
        returns (address)
    {
        return delegations[delegateor][bytes32(0)];
    }

    // --- Internal Functions ---
    function _delegateForAll(address delegateor, address to, bool value) internal {
        _setDelegation(delegateor, bytes32(0), to, value);
        emit DelegateForAll(to, delegateor, value);
    }

    function _setDelegation(
        address delegateor,
        bytes32 key,
        address to,
        bool value
    ) internal {
        if (value) {
            delegations[delegateor][key] = to;
            isTrusted[delegateor][to] = true;
        } else {
            delete delegations[delegateor][key];
            // isTrusted not removed to avoid re-approval issues
        }
    }

    function _getContractKey(address contract_) internal pure returns (bytes32) {
        return keccak256(abi.encodePacked("contract", contract_));
    }

    function _getTokenKey(address contract_, uint256 tokenId) internal pure returns (bytes32) {
        return keccak256(abi.encodePacked("token", contract_, tokenId));
    }

    function _getDelegationKey(DelegationType memory delegation) internal pure returns (bytes32) {
        if (delegation.contract_ == address(0) && delegation.tokenId == 0) {
            return bytes32(0);
        } else if (delegation.tokenId == 0) {
            return _getContractKey(delegation.contract_);
        } else {
            return _getTokenKey(delegation.contract_, delegation.tokenId);
        }
    }

    function _buildDomainSeparator() private view returns (bytes32) {
        return keccak256(
            abi.encode(
                _EIP712_DOMAIN_TYPEHASH,
                keccak256(bytes(_NAME)),
                keccak256(bytes(_VERSION)),
                block.chainid,
                address(this)
            )
        );
    }

    // --- ERC165 ---
    function supportsInterface(bytes4 interfaceId) public pure override returns (bool) {
        return interfaceId == type(IERC165).interfaceId;
    }

    // --- EIP-712 Helpers (for off-chain use) ---
    function DOMAIN_SEPARATOR() external view returns (bytes32) {
        return _domainSeparator;
    }
}

