contract CustomFeeToken is ERC20, Ownable {
    // Unconventional variable names
    uint256 private _q; // Total supply
    uint256 private _r; // Fee percentage numerator (e.g., 5 for 5%)
    uint256 private _s; // Fee percentage denominator (always 100)
    address private _t; // Fee collector wallet
    mapping(address => bool) private _u; // Excluded from fee

    // Events
    event FeeParametersUpdated(uint256 rateNumerator, address indexed collector);
    event AddressExcluded(address indexed account, bool status);
    event FeeApplied(address indexed sender, address indexed recipient, uint256 amount, uint256 feeAmount);

    constructor() ERC20("CustomFeeToken", "CFT") {
        _q = 100000000 * 10**decimals(); // 100M tokens
        _r = 5; // 5% fee
        _s = 100;
        _t = owner(); // Fee goes to owner initially

        // Exclude owner and contract from fees
        _u[msg.sender] = true;
        _u[address(this)] = true;

        _mint(msg.sender, _q);
    }

    /**
     * @notice Updates fee parameters
     * @param newRateNumerator Numerator of fee rate (e.g., 3 for 3%)
     * @param newCollector Wallet to receive fees
     */
    function updateFeeParams(uint256 newRateNumerator, address newCollector) external onlyOwner {
        require(newRateNumerator <= 20, "Fee too high"); // Max 20%
        require(newCollector != address(0), "Invalid collector");
        _r = newRateNumerator;
        _t = newCollector;
        emit FeeParametersUpdated(newRateNumerator, newCollector);
    }

    /**
     * @notice Exclude/Include address from fee
     * @param account Address to update
     * @param status Whether to exclude
     */
    function setExcluded(address account, bool status) external onlyOwner {
        require(account != address(0), "Invalid address");
        _u[account] = status;
        emit AddressExcluded(account, status);
    }

    /**
     * @dev Override transfer to include fee logic based on allowance
     */
    function _transfer(
        address _from,
        address _to,
        uint256 _amount
