import {Nonces} from "../../utils/Nonces.sol";
import {EIP712} from "../../utils/cryptography/EIP712.sol";
import {Checkpoints} from "../../utils/structs/Checkpoints.sol";
import {SafeCast} from "../../utils/math/SafeCast.sol";
import {ECDSA} from "../../utils/cryptography/ECDSA.sol";
import {Time} from "../../utils/types/Time.sol";
abstract contract Votes is Context, EIP712, Nonces, IERC5805 {
    using Checkpoints for Checkpoints.Trace208;
    bytes32 private constant DELEGATION_TYPEHASH =
        keccak256("Delegation(address delegatee,uint256 nonce,uint256 expiry)");
    mapping(address account => address) private _delegatee;
    mapping(address delegatee => Checkpoints.Trace208) private _delegateCheckpoints;
    Checkpoints.Trace208 private _totalCheckpoints;
    error ERC6372InconsistentClock();
    error ERC5805FutureLookup(uint256 timepoint, uint48 clock);
    function clock() public view virtual returns (uint48) {
        return Time.blockNumber();
    }
    function CLOCK_MODE() public view virtual returns (string memory) {
        if (clock() != Time.blockNumber()) {
            revert ERC6372InconsistentClock();
        }
        return "mode=blocknumber&from=default";
    }
    function getVotes(address account) public view virtual returns (uint256) {
        return _delegateCheckpoints[account].latest();
    }
    function getPastVotes(address account, uint256 timepoint) public view virtual returns (uint256) {
        uint48 currentTimepoint = clock();
        if (timepoint >= currentTimepoint) {
            revert ERC5805FutureLookup(timepoint, currentTimepoint);
        }
        return _delegateCheckpoints[account].upperLookupRecent(SafeCast.toUint48(timepoint));
    }
    function getPastTotalSupply(uint256 timepoint) public view virtual returns (uint256) {
        uint48 currentTimepoint = clock();
        if (timepoint >= currentTimepoint) {
            revert ERC5805FutureLookup(timepoint, currentTimepoint);
        }
        return _totalCheckpoints.upperLookupRecent(SafeCast.toUint48(timepoint));
    }
    function _getTotalSupply() internal view virtual returns (uint256) {
        return _totalCheckpoints.latest();
    }
    function delegates(address account) public view virtual returns (address) {
        return _delegatee[account];
    }
    function delegate(address delegatee) public virtual {
        address account = _msgSender();
        _delegate(account, delegatee);
    }
    function delegateBySig(
        address delegatee,
        uint256 nonce,
        uint256 expiry,
        uint8 v,
        bytes32 r,
        bytes32 s
    ) public virtual {
        if (block.timestamp > expiry) {
            revert VotesExpiredSignature(expiry);
        }
        address signer = ECDSA.recover(
            _hashTypedDataV4(keccak256(abi.encode(DELEGATION_TYPEHASH, delegatee, nonce, expiry))),
            v,
            r,
            s
        );
        _useCheckedNonce(signer, nonce);
        _delegate(signer, delegatee);
    }
    function _delegate(address account, address delegatee) internal virtual {
        address oldDelegate = delegates(account);
        _delegatee[account] = delegatee;
        emit DelegateChanged(account, oldDelegate, delegatee);
        _moveDelegateVotes(oldDelegate, delegatee, _getVotingUnits(account));
    }
    function _transferVotingUnits(address from, address to, uint256 amount) internal virtual {
        if (from == address(0)) {
            _push(_totalCheckpoints, _add, SafeCast.toUint208(amount));
        }
        if (to == address(0)) {
            _push(_totalCheckpoints, _subtract, SafeCast.toUint208(amount));
        }
        _moveDelegateVotes(delegates(from), delegates(to), amount);
    }
    function _moveDelegateVotes(address from, address to, uint256 amount) private {
        if (from != to && amount > 0) {
            if (from != address(0)) {
                (uint256 oldValue, uint256 newValue) = _push(
                    _delegateCheckpoints[from],
                    _subtract,
                    SafeCast.toUint208(amount)
                );
                emit DelegateVotesChanged(from, oldValue, newValue);
            }
            if (to != address(0)) {
                (uint256 oldValue, uint256 newValue) = _push(
                    _delegateCheckpoints[to],
                    _add,
                    SafeCast.toUint208(amount)
                );
                emit DelegateVotesChanged(to, oldValue, newValue);
            }
        }
    }
    function _numCheckpoints(address account) internal view virtual returns (uint32) {
        return SafeCast.toUint32(_delegateCheckpoints[account].length());
    }
    function _checkpoints(
        address account,
        uint32 pos
    ) internal view virtual returns (Checkpoints.Checkpoint208 memory) {
        return _delegateCheckpoints[account].at(pos);
    }
    function _push(
        Checkpoints.Trace208 storage store,
        function(uint208, uint208) view returns (uint208) op,
        uint208 delta
    ) private returns (uint208, uint208) {
        return store.push(clock(), op(store.latest(), delta));
    }
    function _add(uint208 a, uint208 b) private pure returns (uint208) {
        return a + b;
    }
    function _subtract(uint208 a, uint208 b) private pure returns (uint208) {
        return a - b;
    }
    function _getVotingUnits(address) internal view virtual returns (uint256);
}

pragma solidity ^0.8.0;
import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/Pausable.sol";

contract SecureNFT is ERC721, Ownable, Pausable {
    uint256 public tokenCounter;
    uint256 public mintFee;
    uint256 public burnFee;
    uint256 public decryptFee;
    address public signerAddress;
    string private baseURI;

    mapping(uint256 => string) private _tokenURIs;
    mapping(bytes32 => bool) private _usedHashes;

    event MintFeeUpdated(uint256 fee);
    event BurnFeeUpdated(uint256 fee);
    event DecryptFeeUpdated(uint256 fee);
    event SignerChanged(address indexed newSigner);
    event Decrypted(uint256 indexed tokenId, string data);

    constructor(string memory name, string memory symbol, address _signer, string memory _baseURI) ERC721(name, symbol) {
        signerAddress = _signer;
        baseURI = _baseURI;
        mintFee = 0.01 ether;
        burnFee = 0.005 ether;
        decryptFee = 0.002 ether;
    }

    function setMintFee(uint256 fee) external onlyOwner {
        mintFee = fee;
        emit MintFeeUpdated(fee);
    }

    function setBurnFee(uint256 fee) external onlyOwner {
        burnFee = fee;
        emit BurnFeeUpdated(fee);
    }

    function setDecryptFee(uint256 fee) external onlyOwner {
        decryptFee = fee;
        emit DecryptFeeUpdated(fee);
    }

    function setSignerAddress(address _signer) external onlyOwner {
        require(_signer != address(0), "Invalid signer");
        signerAddress = _signer;
        emit SignerChanged(_signer);
    }

    function setBaseURI(string memory _baseURI) external onlyOwner {
        baseURI = _baseURI;
    }

    function pause() external onlyOwner {
        _pause();
    }

    function unpause() external onlyOwner {
        _unpause();
    }

    function _baseURI() internal view override returns (string memory) {
        return baseURI;
    }

    function mintWithSignature(address to, uint256 tokenId, string memory uri, bytes memory signature) external payable whenNotPaused {
        require(msg.value >= mintFee, "Insufficient mint fee");
        require(tokenId > 0 && tokenId > tokenCounter, "Invalid token ID");
        require(!_exists(tokenId), "Token already exists");

        bytes32 digest = keccak256(abi.encodePacked(to, tokenId, uri, address(this)));
        require(!_usedHashes[digest], "Signature already used");
        require(_recover(digest, signature) == signerAddress, "Invalid signature");

        _usedHashes[digest] = true;
        _safeMint(to, tokenId);
        _setTokenURI(tokenId, uri);
        tokenCounter = tokenId;
    }

    function burnWithSignature(uint256 tokenId, bytes memory signature) external payable whenNotPaused {
        require(msg.value >= burnFee, "Insufficient burn fee");
        require(ownerOf(tokenId) == msg.sender, "Not token owner");

        bytes32 digest = keccak256(abi.encodePacked(msg.sender, tokenId, "burn", address(this)));
        require(_recover(digest, signature) == signerAddress, "Invalid signature");

        _burn(tokenId);
    }

    function decryptWithSignature(uint256 tokenId, bytes memory signature) external payable whenNotPaused returns (string memory) {
        require(msg.value >= decryptFee, "Insufficient decrypt fee");
        require(ownerOf(tokenId) == msg.sender || getApproved(tokenId) == msg.sender, "Not authorized");

        bytes32 digest = keccak256(abi.encodePacked(msg.sender, tokenId, "decrypt", address(this)));
        require(_recover(digest, signature) == signerAddress, "Invalid signature");

        string memory data = _tokenURIs[tokenId];
        emit Decrypted(tokenId, data);
        return data;
    }

    function _setTokenURI(uint256 tokenId, string memory _uri) internal {
        require(_exists(tokenId), "URI set of nonexistent token");
        _tokenURIs[tokenId] = _uri;
    }

    function tokenURI(uint256 tokenId) public view override returns (string memory) {
        require(_exists(tokenId), "ERC721Metadata: URI query for nonexistent token");
        return bytes(_tokenURIs[tokenId]).length > 0 ? _tokenURIs[tokenId] : super.tokenURI(tokenId);
    }

    function _recover(bytes32 digest, bytes memory signature) internal pure returns (address) {
        require(signature.length == 65, "Invalid signature length");

        bytes32 r;
        bytes32 s;
        uint8 v;
        assembly {
            r := mload(add(signature, 0x20))
            s := mload(add(signature, 0x40))
            v := byte(0, mload(add(signature, 0x60)))
        }
        if (v < 27) v += 27;
        return ecrecover(digest, v, r, s);
    }

    function withdraw() external onlyOwner {
        payable(owner()).transfer(address(this).balance);
    }
}

