contract Withdrawal is
    ContextUpgradeable,
    OwnableUpgradeable,
    ReentrancyGuardUpgradeable,
    AccessControlUpgradeable
{
    using SafeERC20Upgradeable for IERC20Upgradeable;
    bytes public constant PREFIX = "\x19Ethereum Signed Message:\n32";
    IERC20Upgradeable public tubesToken;
    uint256 public totalWithdrawal;
    mapping(uint256 => bool) public withdrawalIdExists;
    mapping(address => bool) private _mapSigners;
    address[] private _signers;
    event Claim(address owner, uint256 withdrawalId, uint256 amount);
    function initialize(IERC20Upgradeable _tubesToken) public initializer {
        __Ownable_init();
        __ReentrancyGuard_init();
        __AccessControl_init();
        tubesToken = _tubesToken;
    }
    function claimWithdrawal(
        uint256 amount,
        uint256 withdrawalId,
        uint8[] memory v,
        bytes32[] memory r,
        bytes32[] memory s
    ) public {
        require(amount > 0, "Amount cannot be 0");
        require(!withdrawalIdExists[withdrawalId], "Not unique");
        bytes32 permitTxHash = keccak256(
            abi.encodePacked(
                bytes1(0x19),
                bytes1(0),
                msg.sender,
                address(this),
                amount,
                withdrawalId
            )
        );
        address lastAddr = address(0);
        uint8 verifiedSigners = 0;
        for (uint64 i = 0; i < v.length; i++) {
            address recovered = ecrecover(permitTxHash, v[i], r[i], s[i]);
            if (recovered > lastAddr && _mapSigners[recovered])
                verifiedSigners++;
            lastAddr = recovered;
        }
        require(verifiedSigners == _signers.length, "Invalid signers");
        withdrawalIdExists[withdrawalId] = true;
        totalWithdrawal += amount;
        tubesToken.safeTransfer(msg.sender, amount);
        emit Claim(msg.sender, withdrawalId, amount);
    }
    function setSigners(address[] memory signers_) external virtual onlyOwner {
        _updateMap(_signers, false, _mapSigners);
        delete _signers;
        _signers = signers_;
        _updateMap(signers_, true, _mapSigners);
    }
    function _updateMap(
        address[] memory arr,
        bool status,
        mapping(address => bool) storage map
    ) internal {
        for (uint64 i = 0; i < arr.length; i++) {
            map[arr[i]] = status;
        }
    }
}

