    {
        bytes32[] memory taskIds = _createdTasks[_taskCreator].values();
        return taskIds;
    }
    function getTaskId(
        address taskCreator,
        address execAddress,
        bytes4 execSelector,
        LibDataTypes.ModuleData memory moduleData,
        address feeToken
    ) external pure returns (bytes32 taskId) {
        taskId = LibTaskId.getTaskId(
            taskCreator,
            execAddress,
            execSelector,
            moduleData,
            feeToken
        );
    }
    function _createTask(
        address _taskCreator,
        address _execAddress,
        bytes memory _execDataOrSelector,
        LibDataTypes.ModuleData memory _moduleData,
        address _feeToken
    ) private returns (bytes32 taskId) {
        taskId = LibTaskId.getTaskId(
            _taskCreator,
            _execAddress,
            _execDataOrSelector.memorySliceSelector(),
            _moduleData,
            _feeToken
        );
        require(
            !_createdTasks[_taskCreator].contains(taskId),
            "Automate.createTask: Duplicate task"
        );
        LibTaskModule.onCreateTask(
            taskId,
            _taskCreator,
            _execAddress,
            _execDataOrSelector,
            _moduleData,
            taskModuleAddresses
        );
        _createdTasks[_taskCreator].add(taskId);
        emit LibEvents.TaskCreated(
            _taskCreator,
            _execAddress,
            _execDataOrSelector,
            _moduleData,
            _feeToken,
            taskId
        );
    }
    function _cancelTask(address _taskCreator, bytes32 _taskId) private {
        require(
            _createdTasks[_taskCreator].contains(_taskId),
            "Automate.cancelTask: Task not found"
        );
        _createdTasks[_taskCreator].remove(_taskId);
        emit LibEvents.TaskCancelled(_taskId, _taskCreator);
    }
}

pragma solidity 0.8.25;
import {WOCTA} from "./WOCTA.sol";
import {ECDSA} from "@openzeppelin/contracts/utils/cryptography/ECDSA.sol";
import {IBridge} from "./interfaces/IBridge.sol";
import {Initializable} from "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import {IERC20, SafeERC20} from "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import {EIP712Upgradeable} from "@openzeppelin/contracts-upgradeable/utils/cryptography/EIP712Upgradeable.sol";
import {PausableUpgradeable} from "@openzeppelin/contracts-upgradeable/utils/PausableUpgradeable.sol";
import {AccessControlUpgradeable} from "@openzeppelin/contracts-upgradeable/access/AccessControlUpgradeable.sol";
abstract contract Bridge is Initializable, EIP712Upgradeable, PausableUpgradeable, AccessControlUpgradeable, IBridge {
    using SafeERC20 for IERC20;
    using ECDSA for bytes32;
    bytes32 public constant OPERATOR_ROLE = keccak256("OPERATOR_ROLE");
    string public constant NAME = "OCTA_BRIDGE";
    string public constant VERSION = "1.0.0";
    uint256 public constant DAY = 86400;
    uint256 private dayLimit;
    address private feeWallet;
    uint256 private minSend;
    uint256 private fee;
    WOCTA private wOCTA;
    mapping(bytes32 => bool) private completedTransactions; 
    mapping(address => Limits) private dayLimits;
    mapping(uint256 => bool) private supportedChains;
    constructor() {
        _disableInitializers();
    }
    receive() external payable {
        revert IncorrectSend();
    }
    function initialize(
        address _defaultAdmin,
        address _operator,
        WOCTA _wOCTA,
        address _feeWallet,
        uint256 _fee,
        uint256 _minSend,
        uint256 _dayLimit
    ) external initializer {
        if (_defaultAdmin == address(0)) revert ZeroAddress();
        __EIP712_init(NAME, VERSION);
        __AccessControl_init();
        __Pausable_init();
        wOCTA = _wOCTA;
        feeWallet = _feeWallet;
        fee = _fee;
        minSend = _minSend;
        dayLimit = _dayLimit;
        _grantRole(DEFAULT_ADMIN_ROLE, _defaultAdmin);
        _grantRole(OPERATOR_ROLE, _operator);
    }
    function getDayLimit() public view returns (uint256) {
        return dayLimit;
    }
    function getFeeWallet() public view returns (address) {
        return feeWallet;
    }
    function getMinSend() public view returns (uint256) {
        return minSend;
    }
    function getFee() public view returns (uint256) {
        return fee;
    }
    function getWOCTA() public view returns (WOCTA) {
        return wOCTA;
    }
    function getCompletedTransaction(bytes32 hash) public view returns (bool) {
        return completedTransactions[hash];
    }
    function getUserDayLimit(address user) public view returns (Limits memory) {
        return dayLimits[user];
    }
    function getSupportedChain(uint256 chainId) public view returns (bool) {
        return supportedChains[chainId];
    }
    function sendTokens(
        uint256 amountWithFee,
        uint256 toChainId
    ) public payable virtual whenNotPaused returns (uint256) {
        if (toChainId == block.chainid || !supportedChains[toChainId]) revert IncorrectToChainId();
        if (minSend > 0 && amountWithFee < minSend) revert NotReachedMinLimit();
        uint256 amount = amountWithFee - fee;
        if (dayLimit > 0) {
            Limits storage _dayLimit = dayLimits[msg.sender];
            uint256 leftAmount = _dayLimit.timestamp + DAY >= block.timestamp ? dayLimit - _dayLimit.amount : dayLimit;
            if (amount > leftAmount) revert ExceededDailyLimit(amount, leftAmount);
            if (_dayLimit.timestamp + DAY >= block.timestamp) {
                dayLimits[msg.sender].amount += amount;
            } else {
                dayLimits[msg.sender].amount = amount;
            }
            _dayLimit.timestamp = block.timestamp;
        }
        emit Sended(msg.sender, amount, toChainId);
        return amount;
    }
    function receiveTokensBatch(Transaction[] calldata transactions, bytes[] memory signatures) external {
        uint256 length = signatures.length;
        for (uint256 i; i < length; ++i) receiveTokens(transactions[i], signatures[i]);
    }
    function receiveTokens(Transaction calldata transaction, bytes memory signature) public virtual whenNotPaused {
        bytes32 hash = keccak256(abi.encode(transaction));
        if (completedTransactions[hash]) revert AlreadyProcessed();
        if (!supportedChains[transaction.chainIdFrom]) revert IncorrectFromChainId();
        bytes32 digest = _hashTypedDataV4(
            keccak256(
                abi.encode(
                    keccak256("Transaction(bytes32 salt,address user,uint256 amount,uint256 chainIdFrom)"),
                    transaction.salt,
                    msg.sender,
                    transaction.amount,
                    transaction.chainIdFrom
                )
            )
        );
        if (!hasRole(OPERATOR_ROLE, ECDSA.recover(digest, signature))) revert IncorrectSignedData();
        completedTransactions[hash] = true;
        emit Received(msg.sender, transaction.amount, transaction.chainIdFrom, transaction.salt);
    }
    function amountAbleToSend() external view returns (uint256 leftAmount) {
        Limits memory _dayLimit = dayLimits[msg.sender];
        leftAmount = dayLimit;
        if (_dayLimit.timestamp + DAY >= block.timestamp) leftAmount -= _dayLimit.amount;
    }
    function setFee(uint256 newFee) external onlyRole(DEFAULT_ADMIN_ROLE) {
        fee = newFee;
        emit FeeChanged(newFee);
    }
    function setFeeWallet(address newFeeWallet) external onlyRole(DEFAULT_ADMIN_ROLE) {
        feeWallet = newFeeWallet;
        emit FeeWalletChanged(newFeeWallet);
    }
    function setMinSend(uint256 newMinMinSend) external onlyRole(DEFAULT_ADMIN_ROLE) {
        minSend = newMinMinSend;
        emit MinSendChanged(newMinMinSend);
    }
    function setDayLimit(uint256 newDayLimit) external onlyRole(DEFAULT_ADMIN_ROLE) {
        dayLimit = newDayLimit;
        emit DayLimitChanged(newDayLimit);
    }
    function setWOCTA(address newWOCTA) external onlyRole(DEFAULT_ADMIN_ROLE) {
        wOCTA = WOCTA(newWOCTA);
        emit wOCTAAddressChanged(newWOCTA);
    }
    function addSupportedChains(uint256[] calldata chainIds) external onlyRole(DEFAULT_ADMIN_ROLE) {
        uint256 length = chainIds.length;
        for (uint256 i; i < length; ++i) {
            supportedChains[chainIds[i]] = true;
        }
        emit SupportedChainsAdded(chainIds);
    }
    function removeSupportedChains(uint256[] calldata chainIds) external whenPaused onlyRole(DEFAULT_ADMIN_ROLE) {
        uint256 length = chainIds.length;
        for (uint256 i; i < length; ++i) {
            supportedChains[chainIds[i]] = false;
        }
        emit SupportedChainsRemoved(chainIds);
    }
    function pause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _pause();
    }
    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _unpause();
    }
    function withdrawEth() external virtual onlyRole(DEFAULT_ADMIN_ROLE) {
        _sendEth(msg.sender, address(this).balance);
    }
    function withdrawERC20(IERC20 _token) external virtual onlyRole(DEFAULT_ADMIN_ROLE) {
        uint256 amount = _token.balanceOf(address(this));
        _token.safeTransfer(msg.sender, amount);
        emit Erc20Withdrawn(address(_token), amount);
    }
    function _sendEth(address to, uint256 amount) internal {
        (bool status, bytes memory reason) = payable(to).call{value: amount}("");
        if (!status) revert EthSendFailed(reason);
        emit EthSended(to, amount);
    }
    uint256[50] private __gap;
}

