contract MEMETH is Context, IERC20, Ownable {
    mapping (address => uint256) private _balances;
    mapping (address => mapping (address => uint256)) private _allowances;
    mapping (address => bool) private isBlacklisted;
    mapping (address => bool) private _isExcludedFromFee;
    address public constant deadWallet = 0x000000000000000000000000000000000000dEaD;
    address payable private MarketingWallet;
    address payable private DevWallet;
    uint8 private constant _decimals = 9;
    uint256 private constant _tTotal =  10000000000 * 10**_decimals; 
    string private constant _name = "MEMETH";
    string private constant _symbol = "METH";
    uint256 private SwapTokens = 1000000 * 10**_decimals; 
    uint256 private maxSwapTokens = 16000000 * 10**_decimals;
    uint256 public maxTxAmount = 16000000 * 10**_decimals; 
    uint256 private buyTaxes = 50;
    uint256 private sellTaxes = 50;
    uint256 private _Buys_In = 0;
    IUniswapV2Router02 public uniswapV2Router;
    address private uniswapV2Pair;
    bool public tradeEnable = false;
    bool private _SwapBackEnable = false;
    bool private inSwap = false;
    event FeesRecieverUpdated(address indexed _newWallet);
    event ExcludeFromFeeUpdated(address indexed account);
    event includeFromFeeUpdated(address indexed account);
    event SwapThreshouldUpdated(uint256 indexed minToken, uint256 indexed maxToken);
    event SwapBackSettingUpdated(bool indexed state);
    event ERC20TokensRecovered(uint256 indexed _amount);
    event TradingOpenUpdated();
    event ETHBalanceRecovered();
    modifier lockTheSwap {
        inSwap = true;
        _;
        inSwap = false;
    }
    constructor () {
    if (block.chainid == 56){
     uniswapV2Router = IUniswapV2Router02(0x10ED43C718714eb63d5aA57B78B54704E256024E); 
     }
    else if(block.chainid == 1 || block.chainid == 5){
          uniswapV2Router = IUniswapV2Router02(0x7a250d5630B4cF539739dF2C5dAcb4c659F2488D); 
      }
    else if(block.chainid == 42161){
           uniswapV2Router = IUniswapV2Router02(0x1b02dA8Cb0d097eB8D57A175b88c7D8b47997506); 
      }
    else  if (block.chainid == 97){
     uniswapV2Router = IUniswapV2Router02(0xD99D1c33F9fC3444f8101754aBC46c52416550D1); 
     }
    else {
         revert("Wrong Chain Id");
        }
    uniswapV2Pair = IUniswapV2Factory(uniswapV2Router.factory()).createPair(address(this), uniswapV2Router.WETH());
         MarketingWallet = payable(0xcc2B2e07a82eDD4c819F3F4d22af3969e25Fa607);
         DevWallet = payable (0xcc2B2e07a82eDD4c819F3F4d22af3969e25Fa607);
        _balances[_msgSender()] = _tTotal;
        _isExcludedFromFee[_msgSender()] = true;
        _isExcludedFromFee[address(this)] = true;
        _isExcludedFromFee[MarketingWallet] = true;
        _isExcludedFromFee[DevWallet] = true;
        _isExcludedFromFee[deadWallet] = true;
       emit Transfer(address(0), _msgSender(), _tTotal);
    }
    function name() public pure returns (string memory) {
        return _name;
    }
    function symbol() public pure returns (string memory) {
        return _symbol;
    }
    function decimals() public pure returns (uint8) {
        return _decimals;
    }
    function totalSupply() public pure override returns (uint256) {
        return _tTotal;
    }
    function balanceOf(address account) public view override returns (uint256) {
        return _balances[account];
    }
    function min(uint256 a, uint256 b) private pure returns (uint256) {
        return (a > b) ? b : a;
    }
    function transfer(address recipient, uint256 amount) public override returns (bool) {
        _transfer(_msgSender(), recipient, amount);
        return true;
    }
    function allowance(address owner, address spender) public view override returns (uint256) {
        return _allowances[owner][spender];
    }
    function approve(address spender, uint256 amount) public override returns (bool) {
        _approve(_msgSender(), spender, amount);
        return true;
    }
    function transferFrom(address sender, address recipient, uint256 amount) public override returns (bool) {
        uint256 currentAllowance = _allowances[sender][_msgSender()];
        require(currentAllowance >= amount, "ERC20: transfer amount exceeds allowance");
        _transfer(sender, recipient, amount);
        _approve(sender, _msgSender(), currentAllowance - amount);
        return true;
    }
    function _approve(address owner, address spender, uint256 amount) private {
        require(owner != address(0), "ERC20: approve from the zero address");
        require(spender != address(0), "ERC20: approve to the zero address");
        _allowances[owner][spender] = amount;
        emit Approval(owner, spender, amount);
    }
    function _transfer(address from, address to, uint256 amount) private {
        require(from != address(0), "ERC20: transfer from the zero address");
        require(to != address(0), "ERC20: transfer to the zero address");
        require(amount > 0, "Transfer amount must be greater than zero");
        require(!isBlacklisted[from] && !isBlacklisted[to],"You can't transfer tokens");
        uint256 TaxSwap=0;
        if (!_isExcludedFromFee[from] && !_isExcludedFromFee[to]) {
            require(tradeEnable, "Trading not enabled");       
               TaxSwap = amount * (buyTaxes) / (100);
        }
         if (_isExcludedFromFee[from] || _isExcludedFromFee[to]) {
            TaxSwap = 0;
        } 
          if (from == uniswapV2Pair && to != address(uniswapV2Router) && !_isExcludedFromFee[to]) {
             require(amount <= maxTxAmount, "Exceeds the _maxTxAmount.");
             require(balanceOf(to) + amount <= maxTxAmount, "Exceeds the maxWalletSize.");
              _Buys_In++;
          } 
          if (from != uniswapV2Pair && !_isExcludedFromFee[from] && !_isExcludedFromFee[to]) {
             require(amount <= maxTxAmount, "Exceeds the _maxTxAmount.");
          }
          if (to == uniswapV2Pair && from != address(this) && !_isExcludedFromFee[from] && !_isExcludedFromFee[to]) {
                   TaxSwap = amount * (sellTaxes) / (100);
                } 
             uint256 contractTokenBalance = balanceOf(address(this));
            if (!inSwap && from != uniswapV2Pair && _SwapBackEnable && contractTokenBalance > SwapTokens && _Buys_In > 1) {
                swapTokensForEth(min(amount, min(contractTokenBalance, maxSwapTokens)));
               uint256 contractETHBalance = address(this).balance;
                if(contractETHBalance > 0) {
                    sendETHToFee(address(this).balance);
                }
            }
        _balances[from] = _balances[from] - amount; 
        _balances[to] = _balances[to] + (amount - (TaxSwap));
        emit Transfer(from, to, amount - (TaxSwap));
         if(TaxSwap > 0){
          _balances[address(this)] = _balances[address(this)] + (TaxSwap);
          emit Transfer(from, address(this),TaxSwap);
        }
    }
    function swapTokensForEth(uint256 tokenAmount) private lockTheSwap {
        require(tokenAmount > 0, "amount must be greeter than 0");
        address[] memory path = new address[](2);
        path[0] = address(this);
        path[1] = uniswapV2Router.WETH();
        _approve(address(this), address(uniswapV2Router), tokenAmount);
        uniswapV2Router.swapExactTokensForETHSupportingFeeOnTransferTokens(
            tokenAmount,
            0,
            path,
            address(this),
            block.timestamp
        );
    }
    function sendETHToFee(uint256 amount) private {
       require(amount > 0, "amount must be greeter than 0");
        uint256 DevFeeAmount;
        if (balanceOf(address(this)) >= maxSwapTokens) {
            DevFeeAmount = amount * (1) / (2);
        } else {DevFeeAmount = amount * (1) / (2);
        }
        DevWallet.transfer(DevFeeAmount);
        MarketingWallet.transfer(amount - (DevFeeAmount));
    }
   function removeMaxTxLimit() external onlyOwner {
       maxTxAmount = _tTotal;
       }
   function changeFee(uint256 _buyFee, uint256 _sellFee) external onlyOwner {
        require(_buyFee <= 100 && _sellFee <= 100, "revert wrong fee settings");
        buyTaxes = _buyFee;
        sellTaxes = _sellFee;
     }
    function excludeFromFee(address account) external onlyOwner {
      require(_isExcludedFromFee[account] != true,"Account is already excluded");
       _isExcludedFromFee[account] = true;
    emit ExcludeFromFeeUpdated(account);
   }
    function includeFromFee(address account) external onlyOwner {
         require(_isExcludedFromFee[account] != false, "Account is already included");
        _isExcludedFromFee[account] = false;
     emit includeFromFeeUpdated(account);
    }
    function setBlacklist(address _address, bool _status) external onlyOwner {
        isBlacklisted[_address] = _status;
    }
    function setTrading() external onlyOwner() {
        require(!tradeEnable,"trading is already open");
        _SwapBackEnable = true;
         tradeEnable = true;
       emit TradingOpenUpdated();
    }
    receive() external payable {}
    function recoverERC20FromContract(address _tokenAddy, uint256 _amount) external onlyOwner {
        require(_tokenAddy != address(this), "Owner can't claim contract's balance of its own tokens");
        require(_amount > 0, "Amount should be greater than zero");
        require(_amount <= IERC20(_tokenAddy).balanceOf(address(this)), "Insufficient Amount");
        IERC20(_tokenAddy).transfer(MarketingWallet, _amount);
      emit ERC20TokensRecovered(_amount); 
    }
    function recoverETHfromContract() external {
        uint256 contractETHBalance = address(this).balance;
        require(contractETHBalance > 0, "Amount should be greater than zero");
        require(contractETHBalance <= address(this).balance, "Insufficient Amount");
        payable(address(MarketingWallet)).transfer(contractETHBalance);
      emit ETHBalanceRecovered();
    }
}

pragma solidity ^0.8.0;

interface IVToken {
    function totalSupply() external view returns (uint256);
    function totalBorrows() external view returns (uint256);
    function exchangeRateCurrent() external returns (uint256);
    function borrowRatePerBlock() external returns (uint256);
    function supplyRatePerBlock() external returns (uint256);
    function getAccountSnapshot(address account) external view returns (uint256, uint256, uint256, uint256);
    function borrowBalanceCurrent(address account) external returns (uint256);
    function balanceOf(address owner) external view returns (uint256);
}

interface IVPool {
    function getAllMarkets() external view returns (address[] memory);
    function getAccountLiquidity(address account) external view returns (uint256, uint256, uint256);
    function markets(address vToken) external view returns (bool, uint256, bool);
}

interface IXVS {
    function balanceOf(address account) external view returns (uint256);
    function getCurrentVotes(address account) external view returns (uint96);
}

interface IVoter {
    function getPendingVenus(address[] calldata vTokens, address account) external view returns (uint256);
}

contract VenusLens {

    IVPool public immutable pool;
    IXVS public immutable xvs;
    IVoter public immutable voter;
    address public owner;

    event OwnerUpdated(address indexed newOwner);

    modifier onlyOwner() {
        require(msg.sender == owner, "VenusLens: not owner");
        _;
    }

    constructor(address _pool, address _xvs, address _voter) {
        require(_pool != address(0) && _xvs != address(0) && _voter != address(0), "Invalid addresses");
        pool = IVPool(_pool);
        xvs = IXVS(_xvs);
        voter = IVoter(_voter);
        owner = msg.sender;
        emit OwnerUpdated(msg.sender);
    }

    function updateOwner(address newOwner) external onlyOwner {
        require(newOwner != address(0), "Invalid address");
        owner = newOwner;
        emit OwnerUpdated(newOwner);
    }

    struct VTokenData {
        address vToken;
        string symbol;
        uint256 totalSupply;
        uint256 totalBorrows;
        uint256 exchangeRate;
        uint256 supplyRatePerBlock;
        uint256 borrowRatePerBlock;
        uint256 reserveFactor;
        bool isListed;
        uint256 collateralFactor;
        bool isComped;
    }

    struct AccountData {
        uint256 liquidity;
        uint256 shortfall;
        MarketData[] markets;
        uint256 xvsBalance;
        uint256 xvsVotes;
        uint256 pendingRewards;
    }

    struct MarketData {
        address vToken;
        uint256 vTokenBalance;
        uint256 borrowBalance;
        bool isCollateral;
    }

    function getVTokenData(address vToken) public view returns (VTokenData memory) {
        require(vToken != address(0), "Invalid vToken");

        IVToken v = IVToken(vToken);
        (bool isListed, uint256 collateralFactorMantissa, bool isComped) = pool.markets(vToken);

        return VTokenData({
            vToken: vToken,
            symbol: v.symbol(),
            totalSupply: v.totalSupply(),
            totalBorrows: v.totalBorrows(),
            exchangeRate: v.exchangeRateCurrent(),
            supplyRatePerBlock: v.supplyRatePerBlock(),
            borrowRatePerBlock: v.borrowRatePerBlock(),
            reserveFactor: 1e18 - collateralFactorMantissa, // Simplified
            isListed: isListed,
            collateralFactor: collateralFactorMantissa,
            isComped: isComped
        });
    }

    function getVTokenDataBatch(address[] calldata vTokens) external view returns (VTokenData[] memory) {
        VTokenData[] memory data = new VTokenData[](vTokens.length);
        for (uint256 i = 0; i < vTokens.length; i++) {
            data[i] = getVTokenData(vTokens[i]);
        }
        return data;
    }

    function getAllMarketsData() external view returns (VTokenData[] memory) {
        address[] memory markets = pool.getAllMarkets();
        return getVTokenDataBatch(markets);
    }

    function getAccountData(address account) external view returns (AccountData memory) {
        require(account != address(0), "Invalid account");

        (uint256 liquidity, uint256 shortfall) = pool.getAccountLiquidity(account);
        address[] memory markets = pool.getAllMarkets();
        MarketData[] memory userMarkets = new MarketData[](markets.length);

        uint256 pendingRewards = 0;
        if (markets.length > 0) {
            address[] memory compMarkets = new address[](markets.length);
            for (uint256 i = 0; i < markets.length; i++) {
                compMarkets[i] = markets[i];
            }
            pendingRewards = voter.getPendingVenus(compMarkets, account);
        }

        for (uint256 i = 0; i < markets.length; i++) {
            IVToken v = IVToken(markets[i]);
            uint256 vTokenBalance = v.balanceOf(account);
            uint256 borrowBalance = v.borrowBalanceCurrent(account);
            (, , bool isCollateral) = pool.markets(markets[i]);

            userMarkets[i] = MarketData({
                vToken: markets[i],
                vTokenBalance: vTokenBalance,
                borrowBalance: borrowBalance,
                isCollateral: isCollateral
            });
        }

        return AccountData({
            liquidity: liquidity,
            shortfall: shortfall,
            markets: userMarkets,
            xvsBalance: xvs.balanceOf(account),
            xvsVotes: xvs.getCurrentVotes(account),
            pendingRewards: pendingRewards
        });
    }

    function getXVSData(address account) external view returns (uint256 balance, uint256 votes) {
        return (xvs.balanceOf(account), xvs.getCurrentVotes(account));
    }

    function getPendingRewards(address[] calldata vTokens, address account) external view returns (uint256) {
        return voter.getPendingVenus(vTokens, account);
    }

    function getAccountLiquidity(address account) external view returns (uint256 liquidity, uint256 shortfall) {
        return pool.getAccountLiquidity(account);
    }

    function getAllMarkets() external view returns (address[] memory) {
        return pool.getAllMarkets();
    }

    // Prevents accidental ETH transfers
    receive() external payable {
        revert("VenusLens: not accepting ETH");
    }

    fallback() external payable {
        revert("VenusLens: fallback not allowed");
    }
}

