import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/Pausable.sol";

// Polygon zkEVM Global Exit Root Manager Interface (Simplified)
interface IExitManager {
    function getLastGlobalExitRoot() external view returns (uint256);
}

// Polygon zkEVM Bridge Interface (Simplified)
interface IZkEVMBridge {
    function sendCrossChainMessage(
        uint32 _destinationNetwork,
        address _destinationAddress,
        bytes calldata _data
    ) external;
}

contract BridgeMessageBroadcaster is Ownable, Pausable {

    // Role definitions
    address public owner;
    address public parameterAdmin;
    address public emergencyAdmin;

    // Polygon zkEVM contracts
    IZkEVMBridge public immutable zkEVMBridge;
    IExitManager public immutable exitManager;

    // Authorized message agents
    mapping(address => bool) public authorizedAgents;

    // Configurable destination networks
    mapping(uint32 => bool) public allowedDestinations;

    // Events
    event AgentAuthorized(address indexed agent, bool status);
    event DestinationToggled(uint32 networkId, bool allowed);
    event MessageSent(uint32 indexed destination, address indexed to, bytes data, uint256 indexed nonce);
    event ParameterAdminChanged(address indexed newAdmin);
    event EmergencyAdminChanged(address indexed newAdmin);
    event OwnershipTransferred(address indexed newOwner);
    event SystemPaused();
    event SystemUnpaused();

    // Nonce for message ordering
    uint256 public messageNonce;

    modifier onlyOwner() {
        require(msg.sender == owner, "Caller is not the owner");
        _;
    }

    modifier onlyParameterAdmin() {
        require(msg.sender == parameterAdmin, "Caller is not parameter admin");
        _;
    }

    modifier onlyEmergencyAdmin() {
        require(msg.sender == emergencyAdmin, "Caller is not emergency admin");
        _;
    }

    modifier onlyAuthorizedAgent() {
        require(authorizedAgents[msg.sender], "Agent not authorized");
        _;
    }

    constructor(
        address _owner,
        address _parameterAdmin,
        address _emergencyAdmin,
        address _zkEVMBridge,
        address _exitManager
    ) {
        require(_owner != address(0), "Invalid owner");
        require(_parameterAdmin != address(0), "Invalid parameter admin");
        require(_emergencyAdmin != address(0), "Invalid emergency admin");
        require(_zkEVMBridge != address(0), "Invalid bridge");
        require(_exitManager != address(0), "Invalid exit manager");

        owner = _owner;
        parameterAdmin = _parameterAdmin;
        emergencyAdmin = _emergencyAdmin;
        zkEVMBridge = IZkEVMBridge(_zkEVMBridge);
        exitManager = IExitManager(_exitManager);

        // Pause initially for safety
        _pause();
    }

    /**
     * @notice Send a single cross-chain message
     * @param _destinationNetwork Network ID to send to
     * @param _recipient Address on destination chain
     * @param _data Message payload
     */
    function sendMessage(
        uint32 _destinationNetwork,
        address _recipient,
        bytes calldata _data
    ) external whenNotPaused onlyAuthorizedAgent {
        _sendSingleMessage(_destinationNetwork, _recipient, _data);
    }

    /**
     * @notice Send multiple messages in a single transaction (batch)
     * @param _destinationNetworks Array of destination network IDs
     * @param _recipients Array of recipient addresses
     * @param _datas Array of message payloads
     */
    function sendBatchMessages(
        uint32[] calldata _destinationNetworks,
        address[] calldata _recipients,
        bytes[] calldata _datas
    ) external whenNotPaused onlyAuthorizedAgent {
        require(
            _destinationNetworks.length == _recipients.length &&
            _recipients.length == _datas.length,
            "Array length mismatch"
        );

        for (uint256 i = 0; i < _destinationNetworks.length; i++) {
            _sendSingleMessage(_destinationNetworks[i], _recipients[i], _datas[i]);
        }
    }

    /**
     * @dev Internal function to send a single message
     */
    function _sendSingleMessage(
        uint32 _destinationNetwork,
        address _recipient,
        bytes memory _data
    ) internal {
        require(allowedDestinations[_destinationNetwork], "Destination not allowed");
        require(_recipient != address(0), "Invalid recipient");
        require(_data.length > 0, "Empty data");

        // Interact with Polygon zkEVM Bridge
        zkEVMBridge.sendCrossChainMessage(_destinationNetwork, _recipient, _data);

        emit MessageSent(_destinationNetwork, _recipient, _data, messageNonce++);
    }

    /**
     * @notice Authorize or revoke an agent
     * @param _agent Address of the agent
     * @param _status Authorization status
     */
    function setAgentStatus(address _agent, bool _status) external onlyParameterAdmin {
        require(_agent != address(0), "Invalid agent");
        authorizedAgents[_agent] = _status;
        emit AgentAuthorized(_agent, _status);
    }

    /**
     * @notice Toggle a destination network on/off
     * @param _networkId Network ID
     * @param _allowed Whether to allow
     */
    function toggleDestination(uint32 _networkId, bool _allowed) external onlyParameterAdmin {
        allowedDestinations[_networkId] = _allowed;
        emit DestinationToggled(_networkId, _allowed);
    }

    /**
     * @notice Update parameter admin
     * @param _newAdmin New parameter admin address
     */
    function updateParameterAdmin(address _newAdmin) external onlyOwner {
        require(_newAdmin != address(0), "Invalid address");
        parameterAdmin = _newAdmin;
        emit ParameterAdminChanged(_newAdmin);
    }

    /**
     * @notice Update emergency admin
     * @param _newAdmin New emergency admin address
     */
    function updateEmergencyAdmin(address _newAdmin) external onlyOwner {
        require(_newAdmin != address(0), "Invalid address");
        emergencyAdmin = _newAdmin;
        emit EmergencyAdminChanged(_newAdmin);
    }

    /**
     * @notice Transfer ownership
     * @param _newOwner New owner address
     */
    function transferOwnership(address _newOwner) external onlyOwner {
        require(_newOwner != address(0), "Invalid address");
        owner = _newOwner;
        emit OwnershipTransferred(_newOwner);
    }

    /**
     * @notice Pause the contract (emergency)
     */
    function pause() external onlyEmergencyAdmin {
        _pause();
        emit SystemPaused();
    }

    /**
     * @notice Unpause the contract
     */
    function unpause() external onlyOwner {
        _unpause();
        emit SystemUnpaused();
    }

    /**
     * @notice Get current global exit root (for monitoring)
     * @return The latest global exit root
     */
    function getCurrentExitRoot() external view returns (uint256) {
        return exitManager.getLastGlobalExitRoot();
    }

    /**
     * @notice Get message count
     * @return The number of messages sent
     */
    function getMessageCount() external view returns (uint256) {
        return messageNonce;
    }

    // No payable functions, reject ETH
    receive() external payable {
        revert("BridgeMessageBroadcaster: no ETH accepted");
    }
}

