pragma solidity ^0.8.0;
contract MultiSigWallet {
    address[] public owners;
    mapping(address => bool) public isOwner;
    uint public required;
    struct Transaction {
        address to;
        uint value;
        bytes data;
        bool executed;
        uint confirmations;
    }
    Transaction[] public transactions;
    mapping(uint => mapping(address => bool)) public confirmations;
    event Deposit(address indexed sender, uint amount);
    event Submit(uint indexed txId);
    event Confirm(address indexed owner, uint indexed txId);
    event Revoke(address indexed owner, uint indexed txId);
    event Execute(uint indexed txId);
    event OwnerAdded(address indexed owner);
    event OwnerRemoved(address indexed owner);
    event RequirementChanged(uint newRequired);
    modifier onlyOwner() {
        require(isOwner[msg.sender], "Not owner");
        _;
    }
    modifier txExists(uint _txId) {
        require(_txId < transactions.length, "Tx not exist");
        _;
    }
    modifier notExecuted(uint _txId) {
        require(!transactions[_txId].executed, "Already executed");
        _;
    }
    modifier notConfirmed(uint _txId) {
        require(!confirmations[_txId][msg.sender], "Already confirmed");
        _;
    }
    constructor(address[] memory _owners, uint _required) {
        require(_owners.length > 0, "No owners");
        require(_required > 0 && _required <= _owners.length, "Invalid required");
        for (uint i = 0; i < _owners.length; i++) {
            address owner = _owners[i];
            require(owner != address(0), "Invalid owner");
            require(!isOwner[owner], "Duplicate owner");
            isOwner[owner] = true;
            owners.push(owner);
        }
        required = _required;
    }
    receive() external payable {
        if (msg.value > 0) emit Deposit(msg.sender, msg.value);
    }
    function submit(address _to, uint _value, bytes calldata _data) external onlyOwner returns (uint) {
        uint txId = transactions.length;
        transactions.push(Transaction(_to, _value, _data, false, 0));
        emit Submit(txId);
        return txId;
    }
    function confirm(uint _txId) external onlyOwner txExists(_txId) notExecuted(_txId) notConfirmed(_txId) {
        confirmations[_txId][msg.sender] = true;
        transactions[_txId].confirmations++;
        emit Confirm(msg.sender, _txId);
    }
    function execute(uint _txId) external txExists(_txId) notExecuted(_txId) {
        Transaction storage txn = transactions[_txId];
        require(txn.confirmations >= required, "Not enough confirmations");
        txn.executed = true;
        (bool success, ) = txn.to.call{value: txn.value}(txn.data);
        require(success, "Execution failed");
        emit Execute(_txId);
    }
    function revoke(uint _txId) external onlyOwner txExists(_txId) notExecuted(_txId) {
        require(confirmations[_txId][msg.sender], "Not confirmed");
        confirmations[_txId][msg.sender] = false;
        transactions[_txId].confirmations--;
        emit Revoke(msg.sender, _txId);
    }
    function addOwner(address _owner) external onlyOwner {
        require(_owner != address(0), "Invalid owner");
        require(!isOwner[_owner], "Already owner");
        isOwner[_owner] = true;
        owners.push(_owner);
        emit OwnerAdded(_owner);
    }
    function removeOwner(address _owner) external onlyOwner {
        require(isOwner[_owner], "Not owner");
        require(owners.length > 1, "Cannot remove last owner");
        isOwner[_owner] = false;
        for (uint i = 0; i < owners.length - 1; i++) {
            if (owners[i] == _owner) {
                owners[i] = owners[owners.length - 1];
                break;
            }
        }
        owners.pop();
        if (required > owners.length) {
            required = owners.length;
            emit RequirementChanged(required);
        }
        emit OwnerRemoved(_owner);
    }
    function changeRequirement(uint _required) external onlyOwner {
        require(_required > 0 && _required <= owners.length, "Invalid requirement");
        required = _required;
        emit RequirementChanged(_required);
    }
    function getOwners() external view returns (address[] memory) {
        return owners;
    }
    function getTransactionCount() external view returns (uint) {
        return transactions.length;
    }
    function isConfirmed(uint _txId) external view returns (bool) {
        return transactions[_txId].confirmations >= required;
    }
    function getConfirmations(uint _txId) external view returns (address[] memory) {
        address[] memory result = new address[](owners.length);
        uint count = 0;
        for (uint i = 0; i < owners.length; i++) {
            if (confirmations[_txId][owners[i]]) {
                result[count] = owners[i];
                count++;
            }
        }
        address[] memory trimmed = new address[](count);
        for (uint i = 0; i < count; i++) {
            trimmed[i] = result[i];
        }
        return trimmed;
    }
}

