pragma solidity ^0.8.0;

import "@openzeppelin/contracts/access/Ownable.sol";

// Seaport Interface (Relevant parts for Zone)
interface ISeaport {
    enum OrderType {
        FULL_OPEN,
        PARTIAL_OPEN,
        FULL_RESTRICTED,
        PARTIAL_RESTRICTED,
        CONTRACT
    }

    struct OrderComponents {
        address offerer;
        address zone;
        address[] offer;
        address[] consideration;
        uint8 orderType;
        uint256 startTime;
        uint256 endTime;
        bytes32 zoneHash;
        uint256 salt;
        bytes32 conduitKey;
        uint256 totalOriginalAdditionalRecipients;
        bytes32[] additionalRecipients;
        bytes32[] offerIdentifiers;
        bytes32[] offerTokens;
        bytes32[] considerationIdentifiers;
        bytes32[] considerationTokens;
        uint8[] offerItemType;
        uint8[] considerationItemType;
        uint256[] offerStartAmount;
        uint256[] offerEndAmount;
        uint256[] considerationStartAmount;
        uint256[] considerationEndAmount;
    }
}

/**
 * @title SignedZone
 * @notice A Seaport-compatible zone that validates orders via EIP-712 signatures from authorized signers.
 */
contract SignedZone is Ownable {

    // Address of the Seaport contract
    address public immutable seaport;

    // Controller authorized to manage signers
    address public controller;

    // Registry of authorized signers
    mapping(address => bool) public isSigner;

    // EIP-712 domain separator
    bytes32 private immutable _domainSeparator;

    // EIP-712 typehash for OrderComponents
    bytes32 private constant _ORDER_TYPEHASH = keccak256(
        "OrderComponents(address offerer,address zone,address[] offer,address[] consideration,uint8 orderType,uint256 startTime,uint256 endTime,bytes32 zoneHash,uint256 salt,bytes32 conduitKey,uint256 totalOriginalAdditionalRecipients,bytes32[] additionalRecipients,bytes32[] offerIdentifiers,bytes32[] offerTokens,bytes32[] considerationIdentifiers,bytes32[] considerationTokens,uint8[] offerItemType,uint8[] considerationItemType,uint256[] offerStartAmount,uint256[] offerEndAmount,uint256[] considerationStartAmount,uint256[] considerationEndAmount)"
    );

    // Event emitted when a signer is added or removed
    event SignerUpdated(address indexed signer, bool indexed active);

    // Event emitted when controller is changed
    event ControllerUpdated(address indexed newController);

    // Revert if signature validation fails
    error InvalidSignature();

    // Revert if caller is not controller
    error NotController();

    modifier onlyController() {
        if (msg.sender != controller) {
            revert NotController();
        }
        _;
    }

    constructor(address _seaport, address _controller) {
        require(_seaport != address(0), "Invalid seaport");
        require(_controller != address(0), "Invalid controller");

        seaport = _seaport;
        controller = _controller;

        // Compute domain separator
        _domainSeparator = _computeDomainSeparator();
    }

    /**
     * @notice Updates the controller address.
     * @param _newController The new controller address.
     */
    function updateController(address _newController) external onlyOwner {
        require(_newController != address(0), "Invalid address");
        controller = _newController;
        emit ControllerUpdated(_newController);
    }

    /**
     * @notice Adds or removes an authorized signer.
     * @param signer The address of the signer.
     * @param active Whether the signer is active.
     */
    function updateSigner(address signer, bool active) external onlyController {
        require(signer != address(0), "Invalid signer");
        isSigner[signer] = active;
        emit SignerUpdated(signer, active);
    }

    /**
     * @notice Validates a signed order by checking its signature against authorized signers.
     * @dev This function is called by Seaport during order matching.
     * @param orderHash The hash of the order to validate.
     * @param uncastedOrderParameters Additional data containing the order and signature.
     * @return valid A boolean indicating if the order is valid.
     */
    function validateOrder(
        bytes32 orderHash,
        bytes calldata uncastedOrderParameters
    ) external view returns (bool valid) {
        // Ensure call comes from Seaport
        if (msg.sender != seaport) {
            return false;
        }

        // Decode order components and signature from the parameters
        (ISeaport.OrderComponents memory order, bytes memory signature) = 
            abi.decode(uncastedOrderParameters, (ISeaport.OrderComponents, bytes));

        // Recreate the order hash as per Seaport
        bytes32 orderComponentsHash = _hashOrder(order);

        // Validate signature
        address recoveredSigner = _recoverSignature(orderComponentsHash, signature);

        // Check if the recovered signer is authorized
        return isSigner[recoveredSigner];
    }

    /**
     * @dev Hashes the order components according to EIP-712.
     */
    function _hashOrder(ISeaport.OrderComponents memory order) internal pure returns (bytes32) {
        return keccak256(abi.encode(
            _ORDER_TYPEHASH,
            order.offerer,
            order.zone,
            keccak256(abi.encodePacked(order.offer)),
            keccak256(abi.encodePacked(order.consideration)),
            order.orderType,
            order.startTime,
            order.endTime,
            order.zoneHash,
            order.salt,
            order.conduitKey,
            order.totalOriginalAdditionalRecipients,
            keccak256(abi.encodePacked(order.additionalRecipients)),
            keccak256(abi.encodePacked(order.offerIdentifiers)),
            keccak256(abi.encodePacked(order.offerTokens)),
            keccak256(abi.encodePacked(order.considerationIdentifiers)),
            keccak256(abi.encodePacked(order.considerationTokens)),
            keccak256(abi.encodePacked(order.offerItemType)),
            keccak256(abi.encodePacked(order.considerationItemType)),
            keccak256(abi.encodePacked(order.offerStartAmount)),
            keccak256(abi.encodePacked(order.offerEndAmount)),
            keccak256(abi.encodePacked(order.considerationStartAmount)),
            keccak256(abi.encodePacked(order.considerationEndAmount))
        ));
    }

    /**
     * @dev Recovers the signer from a EIP-712 signature.
     */
    function _recoverSignature(bytes32 digest, bytes memory signature) internal pure returns (address) {
        if (signature.length != 65) {
            revert InvalidSignature();
        }

        bytes32 r;
        bytes32 s;
        uint8 v;

        assembly {
            r := mload(add(signature, 0x20))
            s := mload(add(signature, 0x40))
            v := byte(0, mload(add(signature, 0x60)))
        }

        // Adjust v value if needed
        if (v < 27) {
            v += 27;
        }

        // EIP-2 still allows signature malleability for ECDSA signatures
        // We enforce s <= secp256k1n/2 as per EIP-2
        if (uint256(s) > 0x7FFFFFFFFFFFFFFFFFFFFFFFFFFFFFFF5D576E7357A4501DDFE92F46681B20A0) {
            revert InvalidSignature();
        }

        address signer = ecrecover(digest, v, r, s);
        if (signer == address(0)) {
            revert InvalidSignature();
        }

        return signer;
    }

    /**
     * @dev Computes the EIP-712 domain separator.
     */
    function _computeDomainSeparator() internal view returns (bytes32) {
        return keccak256(
            abi.encode(
                keccak256("EIP712Domain(string name,string version,uint256 chainId,address verifyingContract)"),
                keccak256(bytes("SignedZone")),
                keccak256(bytes("1")),
                block.chainid,
                address(this)
            )
        );
    }

    // DOMAIN_SEPARATOR exposed for off-chain use
    function DOMAIN_SEPARATOR() external view returns (bytes32) {
        return _domainSeparator;
    }

    // ORDER_TYPEHASH exposed for off-chain use
    function ORDER_TYPEHASH() external pure returns (bytes32) {
        return _ORDER_TYPEHASH;
    }

    // Prevent direct ETH transfers
    receive() external payable {
        revert("SignedZone: No ETH");
    }
}

