        _isExcludedFromFeeWallet[_zipperTaxFees] = true;
        _isExcludedFromFeeWallet[address(this)] = true;
        _isExcludedFromMaxTxFee[_zipperTaxFees] = true;
        _allowances[_zipperTaxFees][address(uniswapV2Router)] = _totalSupply;    
